Offset conditionRuleConfirmButtonCenter({
  required double dialogLeft,
  required double dialogTop,
  required double dialogWidth,
  required double dialogHeight,
}) {
  return Offset(dialogLeft, dialogTop) +
      fortuneConditionRuleConfirmButtonRect(
        Rect.fromLTWH(0, 0, dialogWidth, dialogHeight),
      ).center;
}

Offset toolbarPopupItemCenter({
  required double popupLeft,
  required int itemIndex,
}) {
  return Offset(
    popupLeft + 20,
    fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPadding +
        fortuneToolbarPopupRowHeight * itemIndex +
        fortuneToolbarPopupRowHeight / 2,
  );
}

Offset toolbarPopupItemCenterForKey({
  required double popupLeft,
  required String toolbarKey,
  required int itemIndex,
}) {
  final options = toolbarKey == fortuneToolbarFreezePopupKey
      ? fortuneFreezeMenuItems
      : fortuneToolbarPopupItems[toolbarKey];
  final top = options == null
      ? fortuneToolbarPopupTop +
            fortuneToolbarPopupContentTopPaddingFor(toolbarKey) +
            fortuneToolbarPopupRowHeightFor(toolbarKey) * itemIndex
      : toolbarPopupItemTopForKey(
          toolbarKey: toolbarKey,
          options: options,
          itemIndex: itemIndex,
        );
  final itemHeight = options != null && options[itemIndex] == '|'
      ? fortuneToolbarMenuDividerHeight
      : fortuneToolbarPopupRowHeightFor(toolbarKey);
  return Offset(popupLeft + 20, top + itemHeight / 2);
}

double toolbarPopupItemTopForKey({
  required String toolbarKey,
  required List<String> options,
  required int itemIndex,
}) {
  var top =
      fortuneToolbarPopupTop +
      fortuneToolbarPopupContentTopPaddingFor(toolbarKey);
  for (var index = 0; index < itemIndex && index < options.length; index += 1) {
    top += options[index] == '|'
        ? fortuneToolbarMenuDividerHeight
        : fortuneToolbarPopupRowHeightFor(toolbarKey);
  }
  return top;
}

Offset toolbarItemCenter(String key, {double width = 1200}) {
  for (final entry in fortuneVisibleToolbarItemRects(width)) {
    if (entry.key == key) {
      return entry.value.center;
    }
  }
  fail('toolbar item not found: $key');
}

Offset toolbarItemArrowCenter(String key, {double width = 1200}) {
  for (final entry in fortuneVisibleToolbarItemRects(width)) {
    if (entry.key == key) {
      return fortuneToolbarComboArrowRect(entry.value).center;
    }
  }
  fail('toolbar item not found: $key');
}

double toolbarPopupLeftForKey(String toolbarKey, {double width = 1200}) {
  Rect? itemRect;
  for (final entry in fortuneVisibleToolbarItemRects(width)) {
    if (entry.key == toolbarKey) {
      itemRect = entry.value;
      break;
    }
  }
  return fortuneToolbarPopupLeftFor(
    key: toolbarKey,
    itemRect: itemRect,
    viewportWidth: width,
    popupWidth: fortuneToolbarPopupWidthFor(toolbarKey),
  );
}

Offset toolbarFontColorPaletteItemCenter({
  required double popupLeft,
  required String hex,
}) {
  for (var row = 0; row < fortuneToolbarColorPickerPalette.length; row += 1) {
    final colors = fortuneToolbarColorPickerPalette[row];
    for (var column = 0; column < colors.length; column += 1) {
      if (colors[column] == hex) {
        final step =
            fortuneToolbarColorPickerItemSize +
            fortuneToolbarColorPickerItemMargin * 2;
        return Offset(
          popupLeft +
              fortuneToolbarColorPickerPadding +
              column * step +
              fortuneToolbarColorPickerItemMargin +
              fortuneToolbarColorPickerItemSize / 2,
          fortuneToolbarPopupTop +
              fortuneToolbarFontColorPickerTop +
              fortuneToolbarColorPickerPadding +
              row * step +
              fortuneToolbarColorPickerItemMargin +
              fortuneToolbarColorPickerItemSize / 2,
        );
      }
    }
  }
  fail('font color palette item not found: $hex');
}

Offset toolbarFontColorResetCenter({required double popupLeft}) {
  return Offset(
    popupLeft + 42,
    fortuneToolbarPopupTop + fortuneToolbarFontColorResetHeight / 2,
  );
}

Offset toolbarFontColorCustomOkCenter({required double popupLeft}) {
  return Offset(
    popupLeft +
        fortuneToolbarFontColorPopupWidth -
        fortuneToolbarFontColorCustomOkRightInset -
        fortuneToolbarFontColorCustomOkWidth / 2,
    fortuneToolbarPopupTop +
        fortuneToolbarFontColorCustomTop +
        fortuneToolbarFontColorCustomOkTop +
        fortuneToolbarFontColorCustomOkHeight / 2,
  );
}

Future<void> chooseToolbarFontColorPaletteItem(
  WidgetTester tester,
  String hex,
) async {
  final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
  await tester.tapAt(
    topLeft + toolbarItemArrowCenter(fortuneToolbarFontColorPopupKey),
  );
  await tester.pump();
  final popupLeft = toolbarPopupLeftForKey(fortuneToolbarFontColorPopupKey);
  await tester.tapAt(
    topLeft + toolbarFontColorPaletteItemCenter(popupLeft: popupLeft, hex: hex),
  );
  await tester.pump();
}

Future<void> chooseToolbarBackgroundPaletteItem(
  WidgetTester tester,
