) async {
  final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
  await tester.tapAt(
    topLeft + toolbarItemArrowCenter(fortuneToolbarBackgroundPopupKey),
  );
  await tester.pump();
