Future<void> resetToolbarBackgroundColor(WidgetTester tester) async {
  final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
  await tester.tapAt(
    topLeft + toolbarItemArrowCenter(fortuneToolbarBackgroundPopupKey),
  );
  await tester.pump();
  final popupLeft = toolbarPopupLeftForKey(fortuneToolbarBackgroundPopupKey);
  await tester.tapAt(
    topLeft + toolbarFontColorResetCenter(popupLeft: popupLeft),
  );
  await tester.pump();
}

Future<void> dismissFortuneLocationMessageDialog(
  WidgetTester tester, {
  Size canvasSize = const Size(900, 360),
}) async {
  final painter =
      tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
  final message = painter.locationMessageDialogText;
  expect(message, isNotNull);
  await tester.sendKeyEvent(LogicalKeyboardKey.enter);
  await tester.pump();
  var nextPainter =
      tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
  if (nextPainter.locationMessageDialogText != null) {
    await tester.sendKeyEvent(LogicalKeyboardKey.escape);
    await tester.pump();
    nextPainter =
        tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
  }
  expect(nextPainter.locationMessageDialogText, isNull);
}

Offset conditionFormatTopLevelArrowTarget({
  required double popupLeft,
  required int topLevelIndex,
}) {
  return Offset(
    popupLeft + 136,
    toolbarPopupItemCenterForKey(
      popupLeft: 0,
      toolbarKey: fortuneToolbarConditionFormatPopupKey,
      itemIndex: topLevelIndex,
    ).dy,
  );
}

Offset conditionFormatSubmenuItemCenter({
  required double popupLeft,
  required int topLevelIndex,
  required int itemIndex,
  double viewportWidth = conditionFormatToolbarTestWidth,
}) {
  const topLevelWidth = fortuneConditionFormatTopLevelPopupWidth;
  final submenuWidth =
      topLevelIndex == fortuneConditionFormatSelectionTopLevelIndex
      ? fortuneConditionFormatSelectionSubmenuWidth
      : fortuneConditionFormatSubmenuWidth;
  final desiredLeft = popupLeft + topLevelWidth;
  final left = desiredLeft + submenuWidth > viewportWidth
      ? math.max(
          fortuneToolbarPopupViewportMargin,
          popupLeft +
              fortuneConditionFormatSubmenuOverflowLeftInset -
              submenuWidth,
        )
      : desiredLeft;
  return Offset(
    left + 20,
    toolbarPopupItemTopForKey(
          toolbarKey: fortuneToolbarConditionFormatPopupKey,
          options: fortuneConditionFormatTopLevelItems,
          itemIndex: topLevelIndex,
        ) +
        fortuneConditionFormatSubmenuTopOffset +
        fortuneConditionFormatSubmenuRowHeight * itemIndex +
        fortuneConditionFormatSubmenuRowHeight / 2,
  );
}

Offset borderSubmenuItemCenter({
  required double popupLeft,
  required String submenuKey,
  required int itemIndex,
  double viewportWidth = 1200,
}) {
  final topLevelWidth = fortuneToolbarPopupWidthFor(
    fortuneToolbarBorderPopupKey,
  );
  final submenuWidth = submenuKey == fortuneToolbarBorderColorSubmenuKey
      ? fortuneToolbarFontColorPopupWidth
      : fortuneToolbarBorderStyleSubmenuWidth;
  final desiredLeft = popupLeft + topLevelWidth;
  final left = desiredLeft + submenuWidth > viewportWidth
      ? math.max(fortuneToolbarPopupViewportMargin, popupLeft - submenuWidth)
      : desiredLeft;
  final submenuHeight = submenuKey == fortuneToolbarBorderColorSubmenuKey
      ? fortuneToolbarFontColorPopupHeight
      : fortuneToolbarPopupVerticalPadding +
            fortuneToolbarBorderStyleSubmenuResetHeight +
            fortuneToolbarBorderStyleSubmenuRowHeight *
                fortuneToolbarBorderStyleValues.length;
  final top =
      fortuneToolbarPopupTop +
      fortuneToolbarPopupHeightFor(
        fortuneToolbarBorderPopupKey,
        fortuneToolbarBorderPopupCommands,
      ) -
      submenuHeight;
  if (submenuKey == fortuneToolbarBorderColorSubmenuKey) {
    return Offset(left + 20, top + fortuneToolbarFontColorResetHeight / 2);
  }
  if (itemIndex == 0) {
    return Offset(
      left + 20,
      top +
          fortuneToolbarPopupContentTopPadding +
          fortuneToolbarBorderStyleSubmenuResetHeight / 2,
    );
  }
  return Offset(
    left + 20,
    top +
        fortuneToolbarPopupContentTopPadding +
        fortuneToolbarBorderStyleSubmenuResetHeight +
        fortuneToolbarBorderStyleSubmenuRowHeight * (itemIndex - 1) +
        fortuneToolbarBorderStyleSubmenuRowHeight / 2,
  );
}

Offset borderColorPaletteItemCenter({
  required double popupLeft,
  required String hex,
  double viewportWidth = 1200,
}) {
  final topLevelWidth = fortuneToolbarPopupWidthFor(
    fortuneToolbarBorderPopupKey,
  );
  final desiredLeft = popupLeft + topLevelWidth;
  final left = desiredLeft + fortuneToolbarFontColorPopupWidth > viewportWidth
      ? math.max(
          fortuneToolbarPopupViewportMargin,
          popupLeft - fortuneToolbarFontColorPopupWidth,
        )
      : desiredLeft;
  final submenuTop =
      fortuneToolbarPopupTop +
      fortuneToolbarPopupHeightFor(
        fortuneToolbarBorderPopupKey,
        fortuneToolbarBorderPopupCommands,
      ) -
      fortuneToolbarFontColorPopupHeight;
  for (var row = 0; row < fortuneToolbarColorPickerPalette.length; row += 1) {
    final colors = fortuneToolbarColorPickerPalette[row];
    for (var column = 0; column < colors.length; column += 1) {
      if (colors[column] == hex) {
        final step =
            fortuneToolbarColorPickerItemSize +
            fortuneToolbarColorPickerItemMargin * 2;
        return Offset(
          left +
              fortuneToolbarColorPickerPadding +
              column * step +
              fortuneToolbarColorPickerItemMargin +
              fortuneToolbarColorPickerItemSize / 2,
          submenuTop +
              fortuneToolbarFontColorPickerTop +
              fortuneToolbarColorPickerPadding +
              row * step +
              fortuneToolbarColorPickerItemMargin +
              fortuneToolbarColorPickerItemSize / 2,
        );
      }
    }
  }
  fail('border color palette item not found: $hex');
}

Future<void> tapConditionFormatSubmenuItem(
  WidgetTester tester, {
  required Offset topLeft,
  required double popupLeft,
  required String submenuKey,
  required int itemIndex,
}) async {
  final topLevelIndex = switch (submenuKey) {
    fortuneConditionFormatHighlightSubmenuKey =>
      fortuneConditionFormatHighlightTopLevelIndex,
    fortuneConditionFormatSelectionSubmenuKey =>
      fortuneConditionFormatSelectionTopLevelIndex,
    fortuneConditionFormatDeleteSubmenuKey =>
      fortuneConditionFormatDeleteTopLevelIndex,
    _ => throw ArgumentError.value(submenuKey, 'submenuKey'),
  };
  await tester.tapAt(
    topLeft +
        conditionFormatTopLevelArrowTarget(
          popupLeft: popupLeft,
          topLevelIndex: topLevelIndex,
        ),
  );
  await tester.pump();
  await tester.tapAt(
    topLeft +
        conditionFormatSubmenuItemCenter(
          popupLeft: popupLeft,
          topLevelIndex: topLevelIndex,
          itemIndex: itemIndex,
        ),
  );
  await tester.pump();
}

