    expect(fortuneAxisSizeInputWidth, 112.0);
    expect(fortuneAxisSizeInputHeight, 28.0);
    expect(fortuneAxisSizeConfirmButtonRightInset, 168.0);
    expect(fortuneAxisSizeCancelButtonRightInset, 86.0);
    expect(fortuneAxisSizeDialogButtonBottomInset, 14.0);
    expect(fortuneAxisSizeDialogButtonWidth, 68.0);
    expect(fortuneAxisSizeDialogButtonHeight, 28.0);

    void expectContained(Rect outer, Rect inner) {
      expect(inner.left, greaterThanOrEqualTo(outer.left));
      expect(inner.top, greaterThanOrEqualTo(outer.top));
      expect(inner.right, lessThanOrEqualTo(outer.right));
      expect(inner.bottom, lessThanOrEqualTo(outer.bottom));
    }

    final dialogRect = fortuneAxisSizeDialogRect(const Size(800, 600));
    expect(dialogRect, const Rect.fromLTWH(260, 231, 280, 138));
    expect(
      fortuneAxisSizeInputRect(dialogRect),
      const Rect.fromLTWH(352, 287, 112, 28),
    );
    expect(
      fortuneAxisSizeConfirmButtonRect(dialogRect),
      const Rect.fromLTWH(372, 327, 68, 28),
    );
    expect(
      fortuneAxisSizeCancelButtonRect(dialogRect),
      const Rect.fromLTWH(454, 327, 68, 28),
    );
    expectContained(dialogRect, fortuneAxisSizeConfirmButtonRect(dialogRect));
    expectContained(dialogRect, fortuneAxisSizeCancelButtonRect(dialogRect));
    expect(
      fortuneAxisSizeConfirmButtonRect(dialogRect).top -
          fortuneAxisSizeInputRect(dialogRect).bottom,
      12.0,
    );
    expect(
      dialogRect.bottom - fortuneAxisSizeCancelButtonRect(dialogRect).bottom,
      14.0,
    );
    expect(
      dialogRect.right - fortuneAxisSizeCancelButtonRect(dialogRect).right,
      18.0,
    );
    expect(
      fortuneAxisSizeDialogRect(const Size(240, 100)),
      const Rect.fromLTWH(16, 36, 208, 138),
    );
    final narrowDialogRect = fortuneAxisSizeDialogRect(const Size(240, 100));
    expect(
      fortuneAxisSizeInputRect(narrowDialogRect),
      const Rect.fromLTWH(108, 92, 112, 28),
    );
    expect(
      fortuneAxisSizeConfirmButtonRect(narrowDialogRect),
      const Rect.fromLTWH(56, 132, 68, 28),
    );
    expect(
      fortuneAxisSizeCancelButtonRect(narrowDialogRect),
      const Rect.fromLTWH(138, 132, 68, 28),
    );
    expectContained(
      narrowDialogRect,
      fortuneAxisSizeConfirmButtonRect(narrowDialogRect),
    );
    expectContained(
      narrowDialogRect,
      fortuneAxisSizeCancelButtonRect(narrowDialogRect),
    );
  });

