  testWidgets('toolbar popup closes on outside sheet click like upstream', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    await tester.pumpWidget(
      MaterialApp(
        home: SizedBox(
          width: 1688,
          height: 600,
          child: FortuneSheetCanvas(
            workbook: FortuneWorkbook(
              sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
            ),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemArrowCenter(fortuneToolbarFontPopupKey, width: 1688),
    );
    await tester.pump();

    expect(painter().toolbarPopupKey, fortuneToolbarFontPopupKey);

    await tester.tapAt(topLeft + const Offset(84, 120));
    await tester.pump();

    expect(painter().toolbarPopupKey, isNull);
    expect(painter().selection.row, 1);
    expect(painter().selection.column, 0);
    expect(
      FocusManager.instance.primaryFocus?.debugLabel,
      'FortuneSheetCanvas',
    );
  });

