      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 280,
          child: FortuneSheetCanvas(
            workbook: FortuneWorkbook(
              sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
            ),
            settings: FortuneSettings(
              toolbarItems: const [fortuneToolbarUndoCommand],
              customToolbarItems: [
                FortuneCustomToolbarItem(
                  key: 'custom-refresh',
                  tooltip: 'Refresh',
                  children: 'R',
                  onClick: (item) => calls.add(item.key),
                ),
              ],
            ),
          ),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final customRect = fortuneVisibleToolbarItemRects(
      360,
      items: fortuneToolbarItemsWithCustom(
        const [fortuneToolbarUndoCommand],
        const [FortuneCustomToolbarItem(key: 'custom-refresh')],
