  });

  testWidgets(
    'toolbar auto sum fills row and column totals for grid selection',
    (tester) async {
      tester.view.physicalSize = const Size(1688, 600);
      tester.view.devicePixelRatio = 1.0;
      addTearDown(() {
        tester.view.resetPhysicalSize();
        tester.view.resetDevicePixelRatio();
      });

      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: '30'),
              const FortuneCellCoord(0, 1): const FortuneCell(value: '40'),
              const FortuneCellCoord(1, 0): const FortuneCell(value: '30'),
              const FortuneCellCoord(1, 1): const FortuneCell(value: '50'),
            },
            selectionSave: const [
              {
                'row': [0, 1],
                'column': [0, 1],
                'row_focus': 0,
                'column_focus': 0,
              },
            ],
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarQuickFormulaPopupKey, width: 1688),
      );
      await tester.pump();

      final cells = painter().workbook.activeSheet.cells;
      expect(cells[const FortuneCellCoord(0, 2)]?.formula, '=SUM(A1:B1)');
      expect(cells[const FortuneCellCoord(0, 2)]?.renderedText, '70');
      expect(cells[const FortuneCellCoord(1, 2)]?.formula, '=SUM(A2:B2)');
      expect(cells[const FortuneCellCoord(1, 2)]?.renderedText, '80');
      expect(cells[const FortuneCellCoord(2, 0)]?.formula, '=SUM(A1:A2)');
      expect(cells[const FortuneCellCoord(2, 0)]?.renderedText, '60');
      expect(cells[const FortuneCellCoord(2, 1)]?.formula, '=SUM(B1:B2)');
      expect(cells[const FortuneCellCoord(2, 1)]?.renderedText, '90');
    },
  );

