        child: SizedBox(
          width: 640,
          height: 760,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester
              .widgetList<CustomPaint>(find.byType(CustomPaint))
              .singleWhere((paint) => paint.painter is FortuneSheetPainter)
              .painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final rowHeaderGesture = await tester.startGesture(
      topLeft + const Offset(20, 100),
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await rowHeaderGesture.up();
    await tester.pump();

    expect(
      painter().contextMenuItems,
      contains(fortuneContextSetRowHeightCommand),
    );

    final rowHeightInput = find.byKey(
      const ValueKey('fortune-context-menu-input-set-row-height'),
    );
    await tester.tap(rowHeightInput);
    await tester.enterText(rowHeightInput, '12345');
    await tester.pump();

    final inputRect = tester.getRect(rowHeightInput);
    final dragGesture = await tester.startGesture(
      inputRect.centerLeft + const Offset(2, 0),
      kind: PointerDeviceKind.mouse,
      buttons: kPrimaryMouseButton,
    );
    await dragGesture.moveTo(inputRect.centerRight - const Offset(2, 0));
    await dragGesture.up();
    await tester.pump();

    final rowHeightController = tester
        .widget<EditableText>(rowHeightInput)
        .controller;
    expect(rowHeightController.selection.isValid, isTrue);
    expect(rowHeightController.selection.isCollapsed, isFalse);

    final insertRowInput = find.byKey(
      const ValueKey('fortune-context-menu-input-insert-row'),
    );
    await tester.tap(insertRowInput);
    await tester.pump();

    expect(rowHeightController.selection.isCollapsed, isTrue);
  });

  testWidgets('column header menu button opens upstream header context menu', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1000, 900);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 760,
          child: FortuneSheetCanvas(
            workbook: FortuneWorkbook(
              sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
            ),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final currentPainter = painter();
    final settings = currentPainter.workbook.settings;
    final metrics = currentPainter.workbook.activeSheet.metrics(settings);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final headerRect = Rect.fromLTWH(
      settings.rowHeaderWidth + metrics.columnStart(0),
      sheetTop,
      metrics.columnEnd(0) - metrics.columnStart(0),
      settings.columnHeaderHeight,
    );
    final buttonCenter =
        topLeft + fortuneColumnHeaderMenuButtonRect(headerRect).center;

    await tester.sendEventToBinding(PointerHoverEvent(position: buttonCenter));
    await tester.pump();

    expect(painter().hoveredColumnHeaderIndex, 0);
    expect(painter().hoveredRowHeaderIndex, isNull);

    final semantics = painter().semanticsBuilder(const Size(640, 760));
