  testWidgets('header mouse down mirrors upstream focus selection metadata', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1000, 900);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 760,
          child: FortuneSheetCanvas(
            workbook: FortuneWorkbook(
              sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
            ),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final settings = painter().workbook.settings;
    final metrics = painter().workbook.activeSheet.metrics(settings);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final rowHeaderTarget =
        topLeft +
        Offset(
          settings.rowHeaderWidth / 2,
          sheetTop +
              settings.columnHeaderHeight +
              metrics.rowStart(4) +
              (metrics.rowEnd(4) - metrics.rowStart(4)) / 2,
        );

    await tester.tapAt(rowHeaderTarget);
    await tester.pump();

    var rawSelection =
        (painter().workbook.activeSheet.selectionSave! as List).single as Map;
    expect(painter().selection.row, 4);
    expect(painter().selection.column, 0);
    expect(rawSelection['row'], [4, 4]);
    expect(rawSelection['column'], [
      0,
      painter().selection.normalizedColumnEnd,
    ]);
    expect(rawSelection['row_focus'], 4);
    expect(rawSelection['column_focus'], 0);
    expect(rawSelection['row_select'], isTrue);

    final columnHeaderTarget =
        topLeft +
        Offset(
          settings.rowHeaderWidth +
              metrics.columnStart(4) +
              (metrics.columnEnd(4) - metrics.columnStart(4)) / 2,
          sheetTop + settings.columnHeaderHeight / 2,
        );

    await tester.tapAt(columnHeaderTarget);
    await tester.pump();

    rawSelection =
        (painter().workbook.activeSheet.selectionSave! as List).single as Map;
    expect(painter().selection.row, 0);
    expect(painter().selection.column, 4);
    expect(rawSelection['row'], [0, painter().selection.normalizedRowEnd]);
    expect(rawSelection['column'], [4, 4]);
    expect(rawSelection['row_focus'], 0);
    expect(rawSelection['column_focus'], 4);
    expect(rawSelection['column_select'], isTrue);
  });

