  testWidgets('canvas cell mouse down hooks receive cell and bounds', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1000, 900);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    var allowBeforeMouseDown = false;
    final beforeCalls = <Map<String, Object?>>[];
    final afterCalls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      settings: FortuneSettings(
        beforeCellMouseDown: (cell, info) {
          beforeCalls.add({
            'value': cell?.value,
            'type': cell?.cellType?.type,
            'info': Map<String, int>.from(info),
          });
          return allowBeforeMouseDown;
        },
        afterCellMouseDown: (cell, info) {
          afterCalls.add({
            'value': cell?.value,
            'type': cell?.cellType?.type,
            'info': Map<String, int>.from(info),
          });
        },
      ),
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(1, 1): const FortuneCell(
              value: '50',
              cellType: FortuneCellType(type: 'n'),
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 760,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(130, 120));
    await tester.pump();

    expect(beforeCalls, [
      {
        'value': '50',
        'type': 'n',
        'info': {
          'row': 1,
          'column': 1,
          'startRow': 20,
          'startColumn': 74,
          'endRow': 40,
          'endColumn': 148,
        },
      },
    ]);
    expect(afterCalls, isEmpty);
    expect(painter().selection.row, 0);
    expect(painter().selection.column, 0);

    allowBeforeMouseDown = true;
    await tester.tapAt(topLeft + const Offset(130, 120));
    await tester.pump();

    expect(beforeCalls, hasLength(2));
    expect(afterCalls, [beforeCalls.last]);
    expect(painter().selection.row, 1);
    expect(painter().selection.column, 1);
  });

