  testWidgets('context menu copy and paste use platform clipboard', (
    tester,
  ) async {
    var clipboardText = '';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        switch (call.method) {
          case 'Clipboard.setData':
            clipboardText = (call.arguments as Map)['text'] as String;
            return null;
          case 'Clipboard.getData':
            return <String, Object?>{'text': clipboardText};
        }
        return null;
      },
    );
    addTearDown(() {
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'copy me'),
          },
          nullCells: {
            const FortuneCellCoord(0, 1),
            const FortuneCellCoord(1, 2),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 560,
          child: FortuneSheetCanvas(
            workbook: workbook,
            imagePicker: fortuneTestImagePicker(),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    const a1 = Offset(58, 100);
    final contextGesture = await tester.startGesture(
      topLeft + a1,
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await contextGesture.up();
    await tester.pump();

    expect(painter().contextMenuAt, isNotNull);

    final menuAt = painter().contextMenuAt!;
    await tester.tapAt(topLeft + menuAt + const Offset(40, 20));
    await tester.pump();

    expect(clipboardText, 'copy me');
    expect(painter().contextMenuAt, isNull);

    await tester.tapAt(topLeft + const Offset(130, 100));
    await tester.pump();

    clipboardText = '=A1\tpasted\nnext\trow';
    final pasteContextGesture = await tester.startGesture(
      topLeft + const Offset(130, 100),
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await pasteContextGesture.up();
    await tester.pump();

    final pasteMenuAt = painter().contextMenuAt!;
    await tester.tapAt(topLeft + pasteMenuAt + const Offset(40, 48));
    await tester.pump();

    final cells = painter().workbook.activeSheet.cells;
    expect(cells[const FortuneCellCoord(0, 1)]?.formula, '=A1');
    expect(cells[const FortuneCellCoord(0, 2)]?.renderedText, 'pasted');
    expect(cells[const FortuneCellCoord(1, 1)]?.renderedText, 'next');
    expect(cells[const FortuneCellCoord(1, 2)]?.renderedText, 'row');
    expect(
      painter().workbook.activeSheet.nullCells,
      isNot(contains(const FortuneCellCoord(0, 1))),
    );
    expect(
      painter().workbook.activeSheet.nullCells,
      isNot(contains(const FortuneCellCoord(1, 2))),
    );
    final selectionSave = painter().workbook.activeSheet.selectionSave! as List;
    final pastedRange = selectionSave.single as Map;
    expect(pastedRange['row'], [0, 1]);
    expect(pastedRange['column'], [1, 2]);
    expect(pastedRange['row_focus'], 0);
    expect(pastedRange['column_focus'], 1);
    expect(painter().contextMenuAt, isNull);
  });

