  testWidgets('context menu orderAZ and orderZA sort raw selected range', (
    tester,
  ) async {
    final workbook = FortuneSheetCodec.workbookFromJson({
      'data': [
        {
          'id': 's1',
          'name': 'Sheet1',
          'status': 1,
          'row': 3,
          'column': 10,
          'luckysheet_select_save': [
            {
              'row': [0, 2],
              'column': [0, 1],
            },
          ],
          'celldata': [
            {
              'r': 0,
              'c': 0,
              'v': {'v': 3, 'm': '3'},
            },
            {
              'r': 0,
              'c': 1,
              'v': {'v': 'charlie', 'm': 'charlie'},
            },
            {
              'r': 1,
              'c': 0,
              'v': {'v': 1, 'm': '1'},
            },
            {
              'r': 1,
              'c': 1,
              'v': {'v': 'alpha', 'm': 'alpha'},
            },
            {
              'r': 2,
              'c': 0,
              'v': {'v': 2, 'm': '2'},
            },
            {
              'r': 2,
              'c': 1,
              'v': {'v': 'bravo', 'm': 'bravo'},
            },
          ],
          'dataVerification': {
            '0_1': {'type': 'dropdown', 'value1': 'charlie'},
          },
          'hyperlink': {
            '2_1': {'r': 2, 'linkAddress': 'https://example.test/bravo'},
          },
        },
      ],
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 560,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));

    Future<void> openContextMenuAt(Offset local) async {
      final gesture = await tester.startGesture(
        topLeft + local,
        kind: PointerDeviceKind.mouse,
        buttons: kSecondaryMouseButton,
      );
      await gesture.up();
      await tester.pump();
    }

    Future<void> tapContextCommand(String command) async {
      await tester.tapAt(
        topLeft +
            fortuneContextMenuItemCenter(
              painter().contextMenuAt!,
              command,
              painter().contextMenuItems,
            ),
      );
      await tester.pump();
    }

    await openContextMenuAt(const Offset(58, 100));
    await tapContextCommand('orderAZ');

    var json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    List<Object?> columnValues(int column) {
      final cells = json['celldata'] as List<Object?>;
      return [
        for (final row in [0, 1, 2])
          ((((cells.cast<Map>().singleWhere(
                (cell) => cell['r'] == row && cell['c'] == column,
              ))['v'])
              as Map)['v']),
      ];
    }

    expect(columnValues(0), [1, 2, 3]);
    expect(columnValues(1), ['alpha', 'bravo', 'charlie']);
    expect(json['dataVerification'], {
      '2_1': {'type': 'dropdown', 'value1': 'charlie'},
    });
    expect(json['hyperlink'], {
      '1_1': {'r': 1, 'linkAddress': 'https://example.test/bravo'},
    });
    expect(painter().contextMenuAt, isNull);

    await openContextMenuAt(const Offset(58, 100));
    await tapContextCommand('orderAZ');

    json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    expect(columnValues(0), [1, 2, 3]);
    expect(columnValues(1), ['alpha', 'bravo', 'charlie']);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    expect(columnValues(0), [3, 1, 2]);
    expect(columnValues(1), ['charlie', 'alpha', 'bravo']);
    expect(json['dataVerification'], {
      '0_1': {'type': 'dropdown', 'value1': 'charlie'},
    });
    expect(json['hyperlink'], {
      '2_1': {'r': 2, 'linkAddress': 'https://example.test/bravo'},
    });

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    expect(columnValues(0), [1, 2, 3]);
    expect(columnValues(1), ['alpha', 'bravo', 'charlie']);

    await openContextMenuAt(const Offset(58, 100));
    await tapContextCommand('orderZA');

    json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    expect(columnValues(0), [3, 2, 1]);
    expect(columnValues(1), ['charlie', 'bravo', 'alpha']);
    expect(json['dataVerification'], {
      '0_1': {'type': 'dropdown', 'value1': 'charlie'},
    });
    expect(json['hyperlink'], {
      '1_1': {'r': 1, 'linkAddress': 'https://example.test/bravo'},
    });
    expect(painter().contextMenuAt, isNull);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    expect(columnValues(0), [1, 2, 3]);
    expect(columnValues(1), ['alpha', 'bravo', 'charlie']);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    expect(columnValues(0), [3, 2, 1]);
    expect(columnValues(1), ['charlie', 'bravo', 'alpha']);
  });

