          ],
          'celldata': [
            {
              'r': 0,
              'c': 0,
              'v': {'v': 1, 'm': '1'},
            },
            {
              'r': 0,
              'c': 1,
              'v': {'v': 'bravo', 'm': 'bravo'},
            },
            {
              'r': 1,
              'c': 0,
              'v': {'v': 2, 'm': '2'},
            },
            {
              'r': 1,
              'c': 1,
              'v': {'v': 'alpha', 'm': 'alpha'},
            },
            {
              'r': 2,
              'c': 0,
              'v': {'v': 3, 'm': '3'},
            },
            {
              'r': 2,
              'c': 1,
              'v': {'v': 'charlie', 'm': 'charlie'},
            },
          ],
        },
      ],
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 560,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));

    Future<void> openContextMenuAt(Offset local) async {
      final gesture = await tester.startGesture(
        topLeft + local,
        kind: PointerDeviceKind.mouse,
        buttons: kSecondaryMouseButton,
      );
      await gesture.up();
      await tester.pump();
    }

    Future<void> tapContextCommand(String command) async {
      await tester.tapAt(
        topLeft +
            fortuneContextMenuItemCenter(
              painter().contextMenuAt!,
              command,
              painter().contextMenuItems,
            ),
      );
      await tester.pump();
    }

    await openContextMenuAt(const Offset(58, 100));
    await tapContextCommand('sort');

    expect(painter().contextMenuAt, isNull);
    expect(painter().customSortDialogOpen, isTrue);

    final canvasSize = tester.getSize(find.byType(FortuneSheetCanvas));
    final dialogRect = fortuneCustomSortDialogRect(
      canvasSize,
      2,
    ).shift(topLeft);
    await tester.tapAt(fortuneCustomSortColumnRowRect(dialogRect, 1).center);
    await tester.pump();
    expect(painter().customSortColumnOffset, 1);

    await tester.tapAt(fortuneCustomSortDescendingHitRect(dialogRect).center);
    await tester.pump();
    expect(painter().customSortAscending, isFalse);

    await tester.tapAt(fortuneCustomSortConfirmButtonRect(dialogRect).center);
    await tester.pump();

    final json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
    final cells = (json['celldata'] as List).cast<Map>();
    Object? cellValue(int row, int column) {
      return (cells.singleWhere(
            (cell) => cell['r'] == row && cell['c'] == column,
          )['v']
          as Map)['v'];
    }

    expect(
      [
        for (final row in [0, 1, 2]) cellValue(row, 1),
      ],
      ['charlie', 'bravo', 'alpha'],
    );
    expect(
      [
        for (final row in [0, 1, 2]) cellValue(row, 0),
      ],
      [3, 1, 2],
    );
    expect(painter().customSortDialogOpen, isFalse);
  });

