  testWidgets('keyboard formula entry replay matches upstream core fixture', (
    tester,
  ) async {
    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> enterCellText(Offset cellCenter, String text) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + cellCenter);
      await tester.pump();
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();
      await tester.enterText(find.byType(EditableText), text);
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();
    }

    for (final fixture in const [
      (
        firstFormula: 'SUM',
        secondFormula: 'SUM',
        replacement: '120',
        storedReplacement: '120',
        firstValue: '330',
        secondValue: '660',
        refreshedFirstValue: '240',
        refreshedSecondValue: '480',
      ),
      (
        firstFormula: 'AVERAGE',
        secondFormula: 'AVERAGE',
        replacement: '120',
        storedReplacement: '120',
        firstValue: '165',
        secondValue: '165',
        refreshedFirstValue: '120',
        refreshedSecondValue: '120',
      ),
      (
        firstFormula: 'MAX',
        secondFormula: 'MAX',
        replacement: '120',
        storedReplacement: '120',
        firstValue: '210',
        secondValue: '210',
        refreshedFirstValue: '120',
        refreshedSecondValue: '120',
      ),
      (
        firstFormula: 'MIN',
        secondFormula: 'MIN',
        replacement: '120',
        storedReplacement: '120',
        firstValue: '120',
        secondValue: '120',
        refreshedFirstValue: '120',
        refreshedSecondValue: '120',
      ),
      (
        firstFormula: 'COUNT',
        secondFormula: 'COUNT',
        replacement: '',
        storedReplacement: null,
        firstValue: '2',
        secondValue: '3',
        refreshedFirstValue: '1',
        refreshedSecondValue: '2',
      ),
      (
        firstFormula: 'SUM',
        secondFormula: 'MAX',
        replacement: '120',
        storedReplacement: '120',
        firstValue: '330',
        secondValue: '330',
        refreshedFirstValue: '240',
        refreshedSecondValue: '240',
      ),
    ]) {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            rowCount: 1,
            columnCount: 4,
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: '120'),
              const FortuneCellCoord(0, 1): const FortuneCell(value: '210'),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 640,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      await enterCellText(
        const Offset(203, 100),
        '=${fixture.firstFormula}(A1:B1)',
      );
      await enterCellText(
        const Offset(276, 100),
        '=${fixture.secondFormula}(A1:C1)',
      );

      var cells = painter().workbook.activeSheet.cells;
      expect(
        cells[const FortuneCellCoord(0, 2)]?.renderedText,
        fixture.firstValue,
      );
      expect(
        cells[const FortuneCellCoord(0, 3)]?.renderedText,
        fixture.secondValue,
      );

      await enterCellText(const Offset(130, 100), fixture.replacement);

      cells = painter().workbook.activeSheet.cells;
      expect(
        cells[const FortuneCellCoord(0, 1)]?.value,
        fixture.storedReplacement,
      );
      expect(
        cells[const FortuneCellCoord(0, 2)]?.renderedText,
        fixture.refreshedFirstValue,
      );
      expect(
        cells[const FortuneCellCoord(0, 3)]?.renderedText,
        fixture.refreshedSecondValue,
      );
    }
  });

