    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
      settings: FortuneSettings(
        beforePaste: (selection, content) {
          calls.add({
            'row': selection?.single.rowStart,
            'column': selection?.single.columnStart,
            'content': content,
          });
          return false;
        },
      ),
