  testWidgets('canvas sheet lifecycle hooks wrap tab actions', (tester) async {
    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1'),
        FortuneSheet(id: 's2', name: 'Sheet2'),
      ],
      settings: FortuneSettings(
        beforeAddSheet: (sheet) {
          calls.add({'hook': 'beforeAdd', 'id': sheet.id, 'name': sheet.name});
          return true;
        },
        afterAddSheet: (sheet) {
          calls.add({'hook': 'afterAdd', 'id': sheet.id, 'name': sheet.name});
        },
        beforeActivateSheet: (id) {
          calls.add({'hook': 'beforeActivate', 'id': id});
          return true;
        },
        afterActivateSheet: (id) {
          calls.add({'hook': 'afterActivate', 'id': id});
        },
        beforeDeleteSheet: (id) {
          calls.add({'hook': 'beforeDelete', 'id': id});
          return true;
        },
        afterDeleteSheet: (id) {
          calls.add({'hook': 'afterDelete', 'id': id});
        },
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 520,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    await tester.tapAt(Offset(topLeft.dx + 15, tabY));
    await tester.pump();

    final addedSheetId = painter().workbook.activeSheet.id;
    expect(addedSheetId, matches(fortuneUuidV4Pattern));
    expect(addedSheetId, isNot('sheet_03'));

    expect(calls, [
      {'hook': 'beforeAdd', 'id': addedSheetId, 'name': 'Sheet3'},
      {'hook': 'afterAdd', 'id': addedSheetId, 'name': 'Sheet3'},
    ]);
    expect(painter().workbook.activeSheet.id, addedSheetId);

    await tester.tapAt(Offset(topLeft.dx + 58, tabY));
    await tester.pump();

    expect(calls.sublist(2), [
      {'hook': 'beforeActivate', 'id': 's1'},
      {'hook': 'afterActivate', 'id': 's1'},
    ]);
    expect(painter().workbook.activeSheet.id, 's1');

    final firstTabWidth = math.max(72.0, 'Sheet1'.length * 8 + 32.0);
    await tester.tapAt(Offset(topLeft.dx + 58 + firstTabWidth - 11, tabY));
    await tester.pump();
    final menuAt = painter().sheetTabMenuAt!;
    await tester.tapAt(
      Offset(
        topLeft.dx + menuAt.dx + 18,
        topLeft.dy + menuAt.dy + fortuneSheetTabMenuContentTopPadding + 14,
      ),
    );
    await tester.pump();

    expect(calls.sublist(4), [
      {'hook': 'beforeDelete', 'id': 's1'},
      {'hook': 'afterDelete', 'id': 's1'},
    ]);
    expect(painter().workbook.sheets.map((sheet) => sheet.id), [
      's2',
      addedSheetId,
    ]);
  });

  testWidgets('sheet tabs restore saved selection and scroll offsets', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 80,
          columnCount: 20,
          selectionSave: [
            {
              'row': [1, 1],
              'column': [2, 2],
              'row_focus': 1,
              'column_focus': 2,
            },
          ],
          hasRawSelectionSave: true,
          selectionRange: [
            {
              'row': [0, 2],
              'column': [0, 2],
              'rangeExtra': 'stale-s1',
            },
          ],
          hasRawSelectionRange: true,
        ),
        FortuneSheet(
          id: 's2',
          name: 'Sheet2',
          rowCount: 80,
          columnCount: 20,
          selectionSave: [
            {
              'row': [3, 4],
              'column': [1, 2],
              'row_focus': 3,
              'column_focus': 1,
            },
          ],
          hasRawSelectionSave: true,
          selectionRange: [
            {
              'row': [5, 6],
              'column': [3, 4],
              'rangeExtra': 'stale-s2',
            },
          ],
          hasRawSelectionRange: true,
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    expect(painter().selection.row, 1);
    expect(painter().selection.column, 2);

    Future<void> scrollDownTicks(int ticks) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      for (var tick = 0; tick < ticks; tick += 1) {
        await tester.sendEventToBinding(
          PointerScrollEvent(
            position: topLeft + const Offset(240, 180),
            scrollDelta: const Offset(0, 120),
          ),
        );
        await tester.pump();
      }
    }

    await scrollDownTicks(5);
    expect(painter().scrollOffset.dy, 120);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    final firstTabWidth = math.max(72.0, 'Sheet1'.length * 8 + 32.0);
    await tester.tapAt(Offset(topLeft.dx + 58 + firstTabWidth + 20, tabY));
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 's2');
    expect(painter().selection.row, 3);
    expect(painter().selection.column, 1);
    expect(painter().selection.rowEnd, 4);
    expect(painter().selection.columnEnd, 2);
    expect(painter().workbook.activeSheet.selectionRange, isEmpty);
    expect(painter().workbook.activeSheet.selectionSave, isNotEmpty);
    expect(painter().scrollOffset, Offset.zero);

    await scrollDownTicks(3);
    expect(painter().scrollOffset.dy, 80);

    await tester.tapAt(Offset(topLeft.dx + 58, tabY));
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 's1');
    expect(painter().selection.row, 1);
    expect(painter().selection.column, 2);
    expect(painter().selection.rowEnd, 1);
    expect(painter().selection.columnEnd, 2);
    expect(painter().workbook.activeSheet.selectionRange, isEmpty);
    expect(painter().workbook.activeSheet.selectionSave, isNotEmpty);
    expect(painter().scrollOffset.dy, 120);

    await tester.tapAt(Offset(topLeft.dx + 58 + firstTabWidth + 20, tabY));
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 's2');
    expect(painter().scrollOffset.dy, 80);

    await tester.tapAt(Offset(topLeft.dx + 58, tabY));
    await tester.pump();
    expect(painter().workbook.activeSheet.id, 's1');
    expect(painter().scrollOffset.dy, 120);

    final contextGesture = await tester.startGesture(
      Offset(topLeft.dx + 58 + firstTabWidth + 20, tabY),
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await contextGesture.up();
    await tester.pump();

    expect(painter().sheetTabMenuAt, isNotNull);
    expect(painter().workbook.activeSheet.id, 's2');
    expect(painter().selection.row, 3);
    expect(painter().selection.column, 1);
    expect(painter().selection.rowEnd, 4);
    expect(painter().selection.columnEnd, 2);
    expect(painter().workbook.activeSheet.selectionRange, isEmpty);
    expect(painter().scrollOffset.dy, 80);
  });

