  testWidgets('canvas sheet rename hooks wrap tab rename', (tester) async {
    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
      settings: FortuneSettings(
        beforeUpdateSheetName: (id, oldName, newName) {
          calls.add({
            'hook': 'before',
            'id': id,
            'old': oldName,
            'new': newName,
          });
          return true;
        },
        afterUpdateSheetName: (id, oldName, newName) {
          calls.add({
            'hook': 'after',
            'id': id,
            'old': oldName,
            'new': newName,
          });
        },
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    final firstTabWidth = math.max(72.0, 'Sheet1'.length * 8 + 32.0);
    await tester.tapAt(Offset(topLeft.dx + 58 + firstTabWidth - 11, tabY));
    await tester.pump();
    final menuAt = painter().sheetTabMenuAt!;
    await tester.tapAt(
      Offset(topLeft.dx + menuAt.dx + 18, topLeft.dy + menuAt.dy + 76),
    );
    await tester.pump();

    await tester.enterText(find.byType(EditableText), 'Renamed');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    expect(calls, [
      {'hook': 'before', 'id': 's1', 'old': 'Sheet1', 'new': 'Renamed'},
      {'hook': 'after', 'id': 's1', 'old': 'Sheet1', 'new': 'Renamed'},
    ]);
    expect(painter().workbook.activeSheet.name, 'Renamed');
  });

  testWidgets('keyboard shortcuts adjust active sheet zoom ratio', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(58, 100));
    await tester.pump();

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.equal);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 1.1);

    await tester.sendKeyEvent(LogicalKeyboardKey.minus);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 1.0);

    await tester.sendKeyEvent(LogicalKeyboardKey.equal);
    await tester.sendKeyEvent(LogicalKeyboardKey.equal);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 1.2);

    await tester.sendKeyEvent(LogicalKeyboardKey.digit0);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 1.0);
  });

  testWidgets('keyboard zoom shortcuts clamp to upstream bounds', (
    tester,
  ) async {
    Future<FortuneSheetPainter> pumpWithZoom(double zoomRatio) async {
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 640,
            height: 360,
            child: FortuneSheetCanvas(
              workbook: FortuneWorkbook(
                sheets: [
                  FortuneSheet(id: 's1', name: 'Sheet1', zoomRatio: zoomRatio),
                ],
              ),
            ),
          ),
        ),
      );
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + const Offset(58, 100));
      await tester.pump();
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    await pumpWithZoom(3.95);
    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.numpadAdd);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 4.0);

    await tester.sendKeyEvent(LogicalKeyboardKey.numpadAdd);
    await tester.pump();
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);

    expect(painter().workbook.activeSheet.zoomRatio, 4.0);

    await pumpWithZoom(0.15);
    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.numpadSubtract);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 0.1);

    await tester.sendKeyEvent(LogicalKeyboardKey.numpadSubtract);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 0.1);

    await tester.sendKeyEvent(LogicalKeyboardKey.numpad0);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.activeSheet.zoomRatio, 1.0);
  });

