  testWidgets('editor dialogs expose upstream action button semantics', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    FortuneSheetPainter painterWith({
      bool formatSearchDialogOpen = false,
      bool formulaSearchDialogOpen = false,
      bool splitTextDialogOpen = false,
      bool locationDialogOpen = false,
      bool hyperlinkDialogOpen = false,
      bool dataVerificationDialogOpen = false,
      bool conditionRuleDialogOpen = false,
      bool axisSizeDialogOpen = false,
    }) {
      return FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        formatSearchDialogOpen: formatSearchDialogOpen,
        formulaSearchDialogOpen: formulaSearchDialogOpen,
        splitTextDialogOpen: splitTextDialogOpen,
        locationDialogOpen: locationDialogOpen,
        hyperlinkDialogOpen: hyperlinkDialogOpen,
        dataVerificationDialogOpen: dataVerificationDialogOpen,
        conditionRuleDialogOpen: conditionRuleDialogOpen,
        axisSizeDialogOpen: axisSizeDialogOpen,
        axisSizeDialogAxis: axisSizeDialogOpen ? 'row' : null,
        axisSizeDialogIndex: axisSizeDialogOpen ? 0 : null,
      );
    }

    void expectButtonLabels(FortuneSheetPainter painter, List<String> labels) {
      final semantics = painter.semanticsBuilder(const Size(640, 360));
      for (final label in labels) {
        final matches = semantics.where(
          (node) =>
              node.properties.label == label && node.properties.button == true,
        );
        expect(matches, isNotEmpty, reason: label);
      }
    }

    expectButtonLabels(painterWith(formatSearchDialogOpen: true), const [
      'Close',
      'OK',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(formulaSearchDialogOpen: true), const [
      'Close',
      'OK',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(splitTextDialogOpen: true), const [
      'Close',
      'OK',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(locationDialogOpen: true), const [
      'Close',
      'OK',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(hyperlinkDialogOpen: true), const [
      'OK',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(dataVerificationDialogOpen: true), const [
      'Close',
      'OK',
      'Delete verification',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(conditionRuleDialogOpen: true), const [
      'Close',
      'OK',
      'Cancel',
    ]);
    expectButtonLabels(painterWith(axisSizeDialogOpen: true), const [
      'OK',
      'Cancel',
    ]);
  });

