  testWidgets('location dialog exposes upstream choice semantics', (
    tester,
  ) async {
    final painter = FortuneSheetPainter(
      workbook: FortuneWorkbook(
        sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
      ),
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
      locationDialogOpen: true,
      locationDialogType: fortuneToolbarLocationFormulaCommand,
      locationConstantDate: true,
      locationConstantNumber: false,
      locationConstantString: true,
      locationConstantLogical: false,
      locationConstantError: true,
      locationFormulaDate: false,
      locationFormulaNumber: true,
      locationFormulaString: false,
      locationFormulaLogical: true,
      locationFormulaError: false,
    );
    final semantics = painter.semanticsBuilder(const Size(640, 480));

    bool checked(String label) {
      return semantics
          .singleWhere(
            (node) =>
                node.properties.label == label &&
                node.properties.checked != null,
          )
          .properties
          .checked!;
    }

    List<bool?> valueStates(String label) {
      return semantics
          .where(
            (node) =>
                node.properties.label == label &&
                node.properties.checked != null,
          )
          .map((node) => node.properties.checked)
          .toList();
    }

    expect(checked('Constant'), isFalse);
    expect(checked('Formula'), isTrue);
    expect(checked('Null'), isFalse);
    expect(checked('Row span'), isFalse);
    expect(checked('Column span'), isFalse);
    expect(valueStates('Date'), [true, false]);
    expect(valueStates('Number'), [false, true]);
    expect(valueStates('String'), [true, false]);
    expect(valueStates('Logical'), [false, true]);
    expect(valueStates('Error'), [true, false]);
  });

