  testWidgets('hyperlink dialog exposes upstream input semantics', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1'),
        FortuneSheet(id: 's2', name: 'Sheet2'),
      ],
    );

    FortuneSheetPainter painterWith({
      required String linkType,
      required String address,
      bool selectingCellRange = false,
    }) {
      return FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        hyperlinkDialogOpen: true,
        hyperlinkDialogDisplayText: 'Docs',
        hyperlinkDialogLinkType: linkType,
        hyperlinkDialogAddressText: address,
        hyperlinkDialogSelectingCellRange: selectingCellRange,
      );
    }

    CustomPainterSemantics textField(
      List<CustomPainterSemantics> semantics,
      String label,
    ) {
      return semantics.singleWhere(
        (entry) =>
            entry.properties.label == label &&
            entry.properties.textField == true,
      );
    }

    CustomPainterSemantics button(
      List<CustomPainterSemantics> semantics,
      String label,
    ) {
      return semantics.singleWhere(
        (entry) =>
            entry.properties.label == label && entry.properties.button == true,
      );
    }

    final cellRangeSemantics = painterWith(
      linkType: 'cellrange',
      address: 'A1:B2',
    ).semanticsBuilder(const Size(640, 360));
    expect(
      textField(cellRangeSemantics, 'Display text').properties.value,
      'Docs',
    );
    expect(
      button(cellRangeSemantics, 'Link type').properties.value,
      'Cell range',
    );
    expect(
      textField(cellRangeSemantics, 'Cell range').properties.value,
      'A1:B2',
    );
    expect(button(cellRangeSemantics, 'Select cell range'), isNotNull);

    final sheetSemantics = painterWith(
      linkType: 'sheet',
      address: 'Sheet2',
    ).semanticsBuilder(const Size(640, 360));
    expect(button(sheetSemantics, 'Link type').properties.value, 'Sheet');
    expect(button(sheetSemantics, 'Worksheet').properties.value, 'Sheet2');
    expect(
      sheetSemantics.where(
        (entry) =>
            entry.properties.label == 'Worksheet' &&
            entry.properties.textField == true,
      ),
      isEmpty,
    );

    final rangeSelectionSemantics = painterWith(
      linkType: 'cellrange',
      address: 'A1:B2',
      selectingCellRange: true,
    ).semanticsBuilder(const Size(640, 360));
    expect(button(rangeSelectionSemantics, 'Close'), isNotNull);
    expect(button(rangeSelectionSemantics, 'Cancel'), isNotNull);
    expect(button(rangeSelectionSemantics, 'OK'), isNotNull);
    expect(
      textField(rangeSelectionSemantics, 'Select cell range').properties.value,
      'A1:B2',
    );
    expect(
      rangeSelectionSemantics.where(
        (entry) =>
            entry.properties.label == 'Display text' &&
            entry.properties.textField == true,
      ),
      isEmpty,
    );
  });

