  testWidgets('hyperlink mini card edit and unlink commands update cell', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(900, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'Docs',
              hyperlink: FortuneHyperlink(
                row: 0,
                column: 0,
                linkType: 'webpage',
                linkAddress: 'https://example.test',
              ),
            ),
          },
          hyperlinks: const {
            '0_0': {
              'linkType': 'webpage',
              'linkAddress': 'https://example.test',
            },
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 900,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );
    await tester.pump();

    final metrics = workbook.activeSheet.metrics(workbook.settings);
    final cellRect = Rect.fromLTWH(
      workbook.settings.rowHeaderWidth,
      workbook.settings.toolbarHeight +
          workbook.settings.formulaBarHeight +
          workbook.settings.columnHeaderHeight,
      metrics.visibleDataColumns.first.toDouble(),
      metrics.visibleDataRows.first.toDouble(),
    );
    final cardRect = fortuneHyperlinkCardRect(const Size(900, 360), cellRect);

    await tester.tapAt(fortuneHyperlinkCardEditButtonRect(cardRect).center);
    await tester.pump();
