      customSortHasHeader: false,
      customSortAscending: false,
      customSortColumnOffset: 1,
    );
    final semantics = painter.semanticsBuilder(const Size(640, 420));

    CustomPainterSemantics node(String label) {
      return semantics.singleWhere(
        (entry) => entry.properties.label == label,
        orElse: () => throw StateError(
          'Missing $label in ${semantics.map((entry) => entry.properties.label).toList()}',
        ),
      );
    }

    expect(node('Data has a header row').properties.checked, isFalse);
    expect(node('A').properties.selected, isFalse);
    expect(node('B').properties.selected, isTrue);
    expect(node('C').properties.selected, isFalse);
    expect(node('Ascending').properties.checked, isFalse);
    expect(node('Descending').properties.checked, isTrue);
