      semantics.where(
        (entry) =>
            entry.properties.label == 'sort' && entry.properties.button == true,
      ),
      isNotEmpty,
    );
    expect(
      semantics.where(
        (entry) =>
            entry.properties.label == 'Close' &&
            entry.properties.button == true,
      ),
      isNotEmpty,
    );
    expect(
      semantics.where(
        (entry) =>
            entry.properties.label == 'Cancel' &&
            entry.properties.button == true,
      ),
      isEmpty,
    );

    final localizedPainter = FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(
        row: 0,
        column: 0,
        rowEnd: 3,
        columnEnd: 2,
