      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
      customSortDialogOpen: true,
      customSortHasHeader: true,
      customSortColumnOffset: 0,
      locale: const FortuneSheetLocale(sortColumnOperation: 'Column custom'),
    );
    final localizedSemantics = localizedPainter.semanticsBuilder(
      const Size(640, 420),
    );
    expect(
      localizedSemantics.any(
        (entry) =>
            entry.properties.label == 'Column custom A' &&
            entry.properties.selected == true,
      ),
      isTrue,
    );
  });

  testWidgets('search dialog exposes upstream action button semantics', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    FortuneSheetPainter painterWith({required bool replaceMode}) {
      return FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        searchDialogOpen: true,
        searchReplaceMode: replaceMode,
      );
    }

    void expectButtonLabels(FortuneSheetPainter painter, List<String> labels) {
      final semantics = painter.semanticsBuilder(const Size(640, 360));
      for (final label in labels) {
        final matches = semantics.where(
          (node) =>
              node.properties.label == label && node.properties.button == true,
        );
        expect(matches, isNotEmpty, reason: label);
      }
    }

    expectButtonLabels(painterWith(replaceMode: false), const [
      'Find All',
      'Find next',
      'Close',
    ]);
    expectButtonLabels(painterWith(replaceMode: true), const [
      'Replace All',
      'Replace',
      'Find All',
      'Find next',
      'Close',
    ]);
  });

  testWidgets('search dialog exposes upstream tab button semantics', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    FortuneSheetPainter painterWith({required bool replaceMode}) {
      return FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        searchDialogOpen: true,
        searchReplaceMode: replaceMode,
      );
    }

    CustomPainterSemantics button(
      List<CustomPainterSemantics> semantics,
      String label,
      bool? selected,
    ) {
      return semantics.singleWhere(
        (node) =>
            node.properties.label == label &&
            node.properties.button == true &&
            node.properties.selected == selected,
      );
    }

    final findMode = painterWith(
      replaceMode: false,
    ).semanticsBuilder(const Size(640, 360));
    expect(button(findMode, 'Find', true).properties.selected, isTrue);
    expect(button(findMode, 'Replace', false).properties.selected, isFalse);
    expect(
      findMode
          .where(
            (node) =>
                node.properties.label == 'Close' &&
                node.properties.button == true,
          )
          .length,
      greaterThanOrEqualTo(2),
    );

    final replaceMode = painterWith(
      replaceMode: true,
    ).semanticsBuilder(const Size(640, 360));
    expect(button(replaceMode, 'Find', false).properties.selected, isFalse);
    expect(button(replaceMode, 'Replace', true).properties.selected, isTrue);
  });

