  testWidgets(
    'zoom control buttons and presets adjust active sheet zoom ratio',
    (tester) async {
      final workbook = FortuneWorkbook(
        sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 640,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      const settings = FortuneSettings();
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final canvasSize = tester.getSize(find.byType(FortuneSheetCanvas));

      await tester.tapAt(
        topLeft + fortuneZoomInButtonRect(canvasSize, settings).center,
      );
      await tester.pump();

      expect(painter().workbook.activeSheet.zoomRatio, 1.1);

      await tester.tapAt(
        topLeft + fortuneZoomOutButtonRect(canvasSize, settings).center,
      );
      await tester.pump();

      expect(painter().workbook.activeSheet.zoomRatio, 1.0);

      await tester.tapAt(
        topLeft + fortuneZoomRatioButtonRect(canvasSize, settings).center,
      );
      await tester.pump();

      expect(painter().zoomMenuOpen, isTrue);

      await tester.tapAt(
        topLeft +
            Offset(20, canvasSize.height - settings.statisticBarHeight / 2),
      );
      await tester.pump();

      expect(painter().zoomMenuOpen, isFalse);

      await tester.tapAt(
        topLeft + fortuneZoomRatioButtonRect(canvasSize, settings).center,
      );
      await tester.pump();

      expect(painter().zoomMenuOpen, isTrue);

      await tester.tapAt(
        topLeft + fortuneZoomPresetItemRect(canvasSize, settings, 5).center,
      );
      await tester.pump();

      expect(painter().workbook.activeSheet.zoomRatio, 1.5);
      expect(painter().zoomMenuOpen, isFalse);
    },
  );

  testWidgets('workbook prop change clears transient zoom and hover state', (
    tester,
  ) async {
    final firstWorkbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );
    final secondWorkbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's2', name: 'Sheet2')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: firstWorkbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final canvasSize = tester.getSize(find.byType(FortuneSheetCanvas));
    const settings = FortuneSettings();
    await tester.tapAt(
      topLeft + fortuneZoomRatioButtonRect(canvasSize, settings).center,
    );
    await tester.pump();

    await tester.sendEventToBinding(
      PointerHoverEvent(
        position:
            topLeft +
            Offset(
              settings.rowHeaderWidth + settings.defaultColWidth - 8,
              settings.effectiveToolbarHeight +
                  settings.effectiveFormulaBarHeight +
                  settings.columnHeaderHeight / 2,
            ),
      ),
    );
    await tester.pump();

    expect(painter().zoomMenuOpen, isTrue);
    expect(painter().hoveredColumnHeaderIndex, 0);

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: secondWorkbook),
        ),
      ),
    );
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 's2');
    expect(painter().zoomMenuOpen, isFalse);
    expect(painter().hoveredColumnHeaderIndex, isNull);
    expect(painter().hoveredRowHeaderIndex, isNull);
  });

