  testWidgets('keyboard shortcut copy writes dragged range as TSV', (
    tester,
  ) async {
    var clipboardText = '';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        if (call.method == 'Clipboard.setData') {
          clipboardText = (call.arguments as Map)['text'] as String;
        }
        return null;
      },
    );
    addTearDown(() {
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            const FortuneCellCoord(0, 1): const FortuneCell(
              value: '=A1+1',
              formula: '=A1+1',
            ),
            const FortuneCellCoord(2, 0): const FortuneCell(value: 'A3'),
            const FortuneCellCoord(2, 1): const FortuneCell(value: 'B3'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.dragFrom(
      topLeft + const Offset(83, 100),
      const Offset(73, 38),
    );
    await tester.pump();

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyC);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(clipboardText, 'A1\t=A1+1\n\t\nA3\tB3');
    final painter =
        tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
    expect(painter.workbook.activeSheet.selectionRange, [
      {
        'row': [0, 2],
        'column': [0, 1],
      },
    ]);
  });

  testWidgets('keyboard copy and cut skip partial merged range', (
    tester,
  ) async {
    var clipboardText = 'unchanged';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        if (call.method == 'Clipboard.setData') {
          clipboardText = (call.arguments as Map)['text'] as String;
        }
        return null;
      },
    );
    addTearDown(() {
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });

    const merge = FortuneCellMerge(row: 0, column: 0, columnSpan: 2);
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'Merged',
              merge: merge,
            ),
            const FortuneCellCoord(0, 1): const FortuneCell(merge: merge),
          },
          selectionSave: [
            {
              'row': [0, 0],
              'column': [0, 0],
              'row_focus': 0,
              'column_focus': 0,
            },
          ],
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

