    Future<void> verifyBlockedCut(FortuneSheet sourceSheet) async {
      clipboardText = 'unchanged';
      final workbook = FortuneWorkbook(sheets: [sourceSheet]);
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
