      sheet = painter().workbook.activeSheet;
      expect(sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText, 'Read');
      expect(sheet.cells[const FortuneCellCoord(1, 2)]?.bold, isTrue);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      expect(sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText, 'Read');
      expect(sheet.cells[const FortuneCellCoord(1, 2)]?.bold, isNot(isTrue));
    }

    await verifyBlockedCut(
      FortuneSheet(
        id: 'row-read-only',
        name: 'RowReadOnly',
        rowReadOnly: const {'0': 'readonly'},
        cells: {
          const FortuneCellCoord(0, 0): const FortuneCell(value: 'Read'),
          const FortuneCellCoord(1, 2): const FortuneCell(value: 'Undo'),
        },
      ),
    );

    await verifyBlockedCut(
      FortuneSheet(
        id: 'column-read-only',
        name: 'ColumnReadOnly',
        colReadOnly: const {'0': 'readonly'},
        cells: {
          const FortuneCellCoord(0, 0): const FortuneCell(value: 'Read'),
          const FortuneCellCoord(1, 2): const FortuneCell(value: 'Undo'),
        },
      ),
    );
  });

