  testWidgets('typing after multiline editor newline stays on new line', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: Overlay(
          initialEntries: [
            OverlayEntry(
              builder: (context) => SizedBox(
                width: 640,
                height: 360,
                child: FortuneSheetCanvas(workbook: workbook),
              ),
            ),
          ],
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    var editable = tester.widget<EditableText>(find.byType(EditableText));
    editable.controller.value = const TextEditingValue(
      text: 'line1',
      selection: TextSelection.collapsed(offset: 5),
    );
    await tester.pump();

    Future<void> expectTextStaysOnNewLineAfter(
      LogicalKeyboardKey modifier,
    ) async {
      tester.testTextInput.enterText('line1');
      await tester.pump();

      await tester.sendKeyDownEvent(modifier);
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.sendKeyUpEvent(modifier);
      await tester.pump();

      editable = tester.widget<EditableText>(find.byType(EditableText));
      expect(
        editable.controller.value,
        const TextEditingValue(
          text: 'line1\n',
          selection: TextSelection.collapsed(offset: 6),
        ),
      );
      expect(tester.testTextInput.editingState?['text'], 'line1\n');
      expect(tester.testTextInput.editingState?['selectionBase'], 6);
      expect(tester.testTextInput.editingState?['selectionExtent'], 6);

      tester.testTextInput.enterText('line1\nx');
      await tester.pump();

      editable = tester.widget<EditableText>(find.byType(EditableText));
      expect(editable.controller.text, 'line1\nx');
      expect(editable.controller.selection.baseOffset, 7);

      tester.testTextInput.enterText('line1');
      await tester.pump();

      await tester.sendKeyDownEvent(modifier);
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.sendKeyUpEvent(modifier);
      expect(tester.testTextInput.editingState?['text'], 'line1\n');
      expect(tester.testTextInput.editingState?['selectionBase'], 6);
      expect(tester.testTextInput.editingState?['selectionExtent'], 6);

      tester.testTextInput.enterText(
        '${tester.testTextInput.editingState?['text']}x',
      );
      await tester.pump();
      await tester.pump();

      editable = tester.widget<EditableText>(find.byType(EditableText));
      expect(editable.controller.text, 'line1\nx');
      expect(editable.controller.selection.baseOffset, 7);
    }

    await expectTextStaysOnNewLineAfter(LogicalKeyboardKey.altLeft);
    await expectTextStaysOnNewLineAfter(LogicalKeyboardKey.shiftLeft);
  });

