    );
    await gesture.moveTo(Offset(editableRect.left + 92, dragY));
    await gesture.up();
    await tester.pump();

    var editable = tester.widget<EditableText>(find.byType(EditableText));
    editable.controller.selection = const TextSelection(
      baseOffset: 8,
      extentOffset: 2,
    );
    await tester.pump();

    editable = tester.widget<EditableText>(find.byType(EditableText));
    final selectedRange = TextRange(
      start: math.min(
        editable.controller.selection.start,
        editable.controller.selection.end,
      ),
      end: math.max(
        editable.controller.selection.start,
        editable.controller.selection.end,
