    expect(editable.controller.selection.start, 2);
    expect(editable.controller.selection.end, 7);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    editable = tester.widget<EditableText>(find.byType(EditableText));
    final redoneSpan = editable.controller.buildTextSpan(
      context: tester.element(find.byType(EditableText)),
      style: editable.style,
      withComposing: false,
    );
    expect(redoneSpan.children!.whereType<WidgetSpan>(), hasLength(5));
    expect(editable.controller.selection.start, 2);
    expect(editable.controller.selection.end, 7);

    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    final saved =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)];
    expect(saved?.inlineRuns, isNotNull);
    expect(
      saved?.inlineRuns
          ?.singleWhere((run) => run.text == 'cdefg')
          .extraFields['script'],
      'superscript',
    );
    expect(
      saved?.inlineRuns?.singleWhere((run) => run.text == 'cdefg').fontSize,
      12,
    );
  });

  testWidgets('editor renders RTF inline metadata extras', (tester) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'hideabcdeshup',
              fontSize: 20,
              inlineRuns: [
                FortuneInlineTextRun(
                  text: 'hide',
                  extraFields: {'rtfHidden': true},
                ),
                FortuneInlineTextRun(
                  text: 'abc',
                  extraFields: {'rtfAllCaps': true},
                ),
                FortuneInlineTextRun(
                  text: 'de',
                  fontSize: 20,
                  extraFields: {'rtfSmallCaps': true},
                ),
                FortuneInlineTextRun(
                  text: 'sh',
                  extraFields: {'rtfShadow': true},
                ),
                FortuneInlineTextRun(
                  text: 'up',
                  underline: true,
                  extraFields: {
                    'rtfBaselineShiftPt': 4.0,
                    'rtfUnderlineStyle': 'ulwave',
                  },
                ),
              ],
            ),
          },
          columnWidths: const {0: 220},
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    final editable = tester.widget<EditableText>(find.byType(EditableText));
    final span = editable.controller.buildTextSpan(
      context: tester.element(find.byType(EditableText)),
      style: editable.style,
      withComposing: false,
    );
    final children = span.children!;

    expect(
      children.whereType<TextSpan>().map((child) => child.text).join(),
      'ABCDEsh',
    );
    final smallCapsSpan = children.whereType<TextSpan>().singleWhere(
      (child) => child.text == 'DE',
    );
    expect(smallCapsSpan.style!.fontSize, closeTo(16.4, 0.01));
    final shadowSpan = children.whereType<TextSpan>().singleWhere(
      (child) => child.text == 'sh',
    );
    expect(shadowSpan.style!.shadows, isNotEmpty);

    final shifted = children.whereType<WidgetSpan>().toList();
    expect(shifted, hasLength(2));
    for (final widgetSpan in shifted) {
      final box = widgetSpan.child as SizedBox;
      final translate = box.child as Transform;
      expect(translate.transform.storage[13], closeTo(-4.0, 0.01));
      final scale = translate.child as Transform;
      final text = scale.child as Text;
      expect(text.style!.decorationStyle, TextDecorationStyle.wavy);
    }
  });

