      var clearSpan = editable.controller.buildTextSpan(
        context: tester.element(find.byType(EditableText)),
        style: editable.style,
        withComposing: false,
      );
      expect((clearSpan.children ?? const []).whereType<WidgetSpan>(), isEmpty);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      editable = tester.widget<EditableText>(find.byType(EditableText));
      final undoClearSpan = editable.controller.buildTextSpan(
        context: tester.element(find.byType(EditableText)),
        style: editable.style,
        withComposing: false,
      );
      expect(undoClearSpan.children!.whereType<WidgetSpan>(), hasLength(2));
      expect(editable.controller.selection.baseOffset, 4);
      expect(editable.controller.selection.extentOffset, 1);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      editable = tester.widget<EditableText>(find.byType(EditableText));
      clearSpan = editable.controller.buildTextSpan(
        context: tester.element(find.byType(EditableText)),
