      expect(editable.controller.selection.baseOffset, 4);
      expect(editable.controller.selection.extentOffset, 1);

      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();

      final saved =
          painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
      expect(saved.inlineRuns, hasLength(2));
      expect(saved.inlineRuns![0].text, 'abcd');
      expect(saved.inlineRuns![0].fontSize, 18);
      expect(saved.inlineRuns![0].extraFields['script'], isNull);
      expect(saved.inlineRuns![1].text, 'ef');
      expect(saved.inlineRuns![1].fontSize, 14);
    },
  );

