  testWidgets('editor keyboard selection copies through shortcut and popup', (
    tester,
  ) async {
    var clipboardText = '';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        switch (call.method) {
          case 'Clipboard.setData':
            clipboardText = (call.arguments as Map)['text'] as String;
            return null;
          case 'Clipboard.getData':
            return <String, Object?>{'text': clipboardText};
        }
        return null;
      },
    );
    addTearDown(() {
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'abcdefghij',
            ),
          },
          columnWidths: const {0: 180},
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester
          .widgetList<CustomPaint>(find.byType(CustomPaint))
          .map((paint) => paint.painter)
          .whereType<FortuneSheetPainter>()
          .single;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    final editableFinder = find.byType(EditableText);
    await tester.sendKeyEvent(LogicalKeyboardKey.home);
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.arrowRight);
    await tester.sendKeyEvent(LogicalKeyboardKey.arrowRight);
    await tester.pump();
    await tester.sendKeyDownEvent(LogicalKeyboardKey.shiftLeft);
    for (var count = 0; count < 5; count += 1) {
      await tester.sendKeyEvent(LogicalKeyboardKey.arrowRight);
    }
    await tester.sendKeyUpEvent(LogicalKeyboardKey.shiftLeft);
    await tester.pump();

    var editable = tester.widget<EditableText>(editableFinder);
    final selectedText = editable.controller.text.substring(
      editable.controller.selection.start,
      editable.controller.selection.end,
    );
    expect(selectedText, 'cdefg');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyC);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pumpAndSettle();

    expect(clipboardText, 'cdefg');

    clipboardText = '';
    final editableRect = tester.getRect(find.byType(EditableText));
    final gesture = await tester.startGesture(
      editableRect.center,
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await gesture.up();
    await tester.pumpAndSettle();

    expect(
      painter().contextMenuDisabledItems,
      isNot(contains(fortuneContextCopyCommand)),
    );
    await tester.tapAt(
      topLeft +
          fortuneContextMenuItemCenter(
            painter().contextMenuAt!,
            fortuneContextCopyCommand,
            painter().contextMenuItems,
          ),
    );
    await tester.pumpAndSettle();

    expect(clipboardText, 'cdefg');
    editable = tester.widget<EditableText>(editableFinder);
    expect(editable.controller.selection.start, 2);
    expect(editable.controller.selection.end, 7);
  });

