  testWidgets('editor context menu shows localized inline format inputs', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'abcdefghij',
            ),
          },
          columnWidths: const {0: 180},
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(
            workbook: workbook,
            locale: FortuneSheetLocale.forLocale(const Locale('ko', 'KR')),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester
          .widgetList<CustomPaint>(find.byType(CustomPaint))
          .map((paint) => paint.painter)
          .whereType<FortuneSheetPainter>()
          .single;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    final editable = tester.widget<EditableText>(find.byType(EditableText));
    editable.controller.selection = const TextSelection(
      baseOffset: 0,
      extentOffset: 10,
    );
    await tester.pump();

    final editableRect = tester.getRect(find.byType(EditableText));
    final menuGesture = await tester.startGesture(
      editableRect.center,
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await menuGesture.up();
    await tester.pump();

    expect(painter().contextMenuItems, fortuneEditorContextMenuItems);
    expect(find.text('예: 1.0'), findsOneWidget);
    expect(find.text('예: 90'), findsOneWidget);
    expect(find.text('예: 1.2'), findsOneWidget);
    int contextMenuOverlayIndex(Stack stack) {
      return stack.children.indexWhere((child) {
        if (child is! Positioned || child.child is! IgnorePointer) {
          return false;
        }
        final overlay = (child.child as IgnorePointer).child;
        return overlay is CustomPaint && overlay.painter != null;
      });
    }

    final rootStack = tester
        .widgetList<Stack>(find.byType(Stack))
        .firstWhere(
          (stack) =>
              stack.fit == StackFit.expand &&
              contextMenuOverlayIndex(stack) != -1,
        );
    expect(contextMenuOverlayIndex(rootStack), rootStack.children.length - 2);
    expect(rootStack.children.last, isA<Stack>());

    final menuAt = painter().contextMenuAt!;
    expect(
      fortuneContextMenuRect(menuAt, painter().contextMenuItems).width,
      closeTo(fortuneContextMenuWidth * 2 / 3, 0.01),
    );
    final lineHeightRect = fortuneContextMenuInlineInputRect(
      menuAt,
      fortuneEditorContextLineHeightCommand,
      painter().contextMenuItems,
    )!;
    final editorHeight = math.min(lineHeightRect.height - 2, 12 + 4);
    final expectedInputTop =
        lineHeightRect.top + (lineHeightRect.height - editorHeight) / 2 + 1;
    expect(
      find.byKey(
        const ValueKey(
          'fortune-context-menu-input-$fortuneEditorContextLineHeightCommand',
        ),
      ),
      findsOneWidget,
    );

    Finder inputFor(String command) {
      return find.byKey(ValueKey('fortune-context-menu-input-$command'));
    }

    Future<void> reopenEditorContextMenu() async {
      final rect = tester.getRect(find.byType(EditableText));
      final gesture = await tester.startGesture(
        rect.center,
        kind: PointerDeviceKind.mouse,
        buttons: kSecondaryMouseButton,
      );
      await gesture.up();
      await tester.pump();
    }

    Future<void> applyInlineInput(
      String command,
      String text, {
      bool byMenuSelection = false,
    }) async {
      final input = inputFor(command);
      await tester.tap(input);
      await tester.enterText(input, text);
      if (byMenuSelection) {
        await tester.tapAt(
          topLeft +
              fortuneContextMenuItemCenter(
                painter().contextMenuAt!,
                command,
                painter().contextMenuItems,
              ),
        );
      } else {
        await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      }
      await tester.pump();
      await tester.pump();
    }

    final lineHeightInput = inputFor(fortuneEditorContextLineHeightCommand);
    expect(
      tester.getTopLeft(lineHeightInput).dy - topLeft.dy,
      closeTo(expectedInputTop, 0.01),
    );
    await tester.tap(lineHeightInput);
    await tester.sendKeyEvent(LogicalKeyboardKey.escape);
    await tester.pump();

    expect(painter().contextMenuAt, isNull);
    final escaped = tester.widget<EditableText>(find.byType(EditableText));
    expect(escaped.controller.selection.start, 0);
    expect(escaped.controller.selection.end, 10);

    await reopenEditorContextMenu();
    await applyInlineInput(fortuneEditorContextLetterSpacingCommand, '1.0');
    expect(painter().contextMenuAt, isNull);
    var edited = tester.widget<EditableText>(find.byType(EditableText));
    expect(edited.controller.selection.start, 0);
    expect(edited.controller.selection.end, 10);

    await reopenEditorContextMenu();
    await applyInlineInput(
      fortuneEditorContextFontScaleCommand,
      '90',
      byMenuSelection: true,
    );
    expect(painter().contextMenuAt, isNull);
    edited = tester.widget<EditableText>(find.byType(EditableText));
    expect(edited.controller.selection.start, 0);
    expect(edited.controller.selection.end, 10);

    await reopenEditorContextMenu();
    await applyInlineInput(fortuneEditorContextLineHeightCommand, '1.2');

    expect(painter().contextMenuAt, isNull);
    edited = tester.widget<EditableText>(find.byType(EditableText));
    expect(edited.controller.selection.start, 0);
    expect(edited.controller.selection.end, 10);

    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    final saved =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)];
    expect(saved?.inlineRuns, hasLength(1));
    expect(saved?.inlineRuns?.single.extraFields['letterSpacing'], 1.0);
    expect(saved?.inlineRuns?.single.extraFields['fontScale'], 90.0);
    expect(saved?.inlineRuns?.single.extraFields['lineHeight'], 1.2);

    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();
    edited = tester.widget<EditableText>(find.byType(EditableText));
    edited.controller.selection = const TextSelection(
      baseOffset: 0,
      extentOffset: 10,
    );
    await tester.pump();

    await reopenEditorContextMenu();
    expect(
      tester
          .widget<EditableText>(
            inputFor(fortuneEditorContextLetterSpacingCommand),
          )
          .controller
          .text,
      '1',
    );
    expect(
      tester
          .widget<EditableText>(inputFor(fortuneEditorContextFontScaleCommand))
          .controller
          .text,
      '90',
    );
    expect(
      tester
          .widget<EditableText>(inputFor(fortuneEditorContextLineHeightCommand))
          .controller
          .text,
      '1.2',
    );
  });

  testWidgets('editor context menu prefills typography inputs from caret run', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              inlineRuns: [
                FortuneInlineTextRun(
                  text: 'ab',
                  extraFields: {
                    'letterSpacing': 1.25,
                    'fontScale': 90.0,
                    'lineHeight': 1.2,
                  },
                ),
                FortuneInlineTextRun(text: 'cd'),
                FortuneInlineTextRun(
                  text: 'ef',
                  extraFields: {
                    'letterSpacing': -0.5,
                    'fontScale': 110.0,
                    'lineHeight': 1.75,
                  },
                ),
              ],
            ),
          },
          columnWidths: const {0: 180},
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    Finder inputFor(String command) {
      return find.byKey(ValueKey('fortune-context-menu-input-$command'));
    }

    EditableText activeEditor() {
      return tester
          .widgetList<EditableText>(find.byType(EditableText))
          .singleWhere((editable) => editable.controller.text == 'abcdef');
    }

    Future<void> openMenuAtCaret(int offset) async {
      if (tester
          .widgetList<EditableText>(find.byType(EditableText))
          .where((editable) => editable.controller.text == 'abcdef')
          .isEmpty) {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.tapAt(topLeft + const Offset(83, 100));
        await tester.pump();
        await tester.sendKeyEvent(LogicalKeyboardKey.f2);
        await tester.pump();
      }
      final editable = activeEditor();
      editable.controller.selection = TextSelection.collapsed(offset: offset);
      await tester.pump();

      final editableRect = tester.getRect(
        find.byWidgetPredicate(
          (widget) =>
              widget is EditableText && widget.controller.text == 'abcdef',
        ),
      );
      final gesture = await tester.startGesture(
        editableRect.center,
        kind: PointerDeviceKind.mouse,
        buttons: kSecondaryMouseButton,
      );
      await gesture.up();
      await tester.pump();
    }

    String inputText(String command) {
      return tester.widget<EditableText>(inputFor(command)).controller.text;
    }

    await openMenuAtCaret(1);
    expect(inputText(fortuneEditorContextLetterSpacingCommand), '1.25');
    expect(inputText(fortuneEditorContextFontScaleCommand), '90');
    expect(inputText(fortuneEditorContextLineHeightCommand), '1.2');

    await tester.sendKeyEvent(LogicalKeyboardKey.escape);
    await tester.pump();
    await openMenuAtCaret(3);
    expect(inputText(fortuneEditorContextLetterSpacingCommand), '');
    expect(inputText(fortuneEditorContextFontScaleCommand), '');
    expect(inputText(fortuneEditorContextLineHeightCommand), '');

    await tester.sendKeyEvent(LogicalKeyboardKey.escape);
    await tester.pump();
    await openMenuAtCaret(5);
    expect(inputText(fortuneEditorContextLetterSpacingCommand), '-0.5');
    expect(inputText(fortuneEditorContextFontScaleCommand), '110');
    expect(inputText(fortuneEditorContextLineHeightCommand), '1.75');
  });

