  testWidgets(
    'editor context script applies after multiline line height formatting',
    (tester) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(
                value: 'aa\nbb\ncc',
                textWrap: '2',
              ),
            },
            columnWidths: const {0: 180},
            rowHeights: const {0: 96},
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 640,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester
            .widgetList<CustomPaint>(find.byType(CustomPaint))
            .map((paint) => paint.painter)
            .whereType<FortuneSheetPainter>()
            .single;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + const Offset(83, 100));
      await tester.pump();
      await tester.sendKeyEvent(LogicalKeyboardKey.f2);
      await tester.pump();

      var editable = tester.widget<EditableText>(find.byType(EditableText));
      editable.controller.selection = const TextSelection.collapsed(offset: 4);
      await tester.pump();

      Future<void> openEditorContextMenu() async {
        final rect = tester.getRect(find.byType(EditableText));
        final gesture = await tester.startGesture(
          Offset(rect.left + 24, rect.center.dy),
          kind: PointerDeviceKind.mouse,
          buttons: kSecondaryMouseButton,
        );
        await gesture.up();
        await tester.pump();
      }

      await openEditorContextMenu();
      final lineHeightInput = find.byKey(
        const ValueKey(
          'fortune-context-menu-input-$fortuneEditorContextLineHeightCommand',
        ),
      );
      await tester.tap(lineHeightInput);
      await tester.enterText(lineHeightInput, '1.7');
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();
      await tester.pump();

      Finder cellEditor() => find.byWidgetPredicate(
        (widget) =>
            widget is EditableText && widget.controller.text == 'aa\nbb\ncc',
      );

      editable = tester.widget<EditableText>(cellEditor());
      editable.controller.selection = const TextSelection(
        baseOffset: 3,
        extentOffset: 5,
      );
      await tester.pump();

      await openEditorContextMenu();
      editable = tester.widget<EditableText>(cellEditor());
      editable.controller.selection = const TextSelection.collapsed(offset: 4);
      await tester.pump();

      await tester.tapAt(
        topLeft +
            fortuneContextMenuItemCenter(
              painter().contextMenuAt!,
              fortuneEditorContextSuperscriptCommand,
              painter().contextMenuItems,
            ),
      );
      await tester.pump();
      await tester.pump();

      editable = tester.widget<EditableText>(cellEditor());
      expect(editable.controller.selection.start, 3);
      expect(editable.controller.selection.end, 5);

      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();

      final runs = painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(0, 0)]!
          .inlineRuns!;
      final scriptRun = runs.singleWhere((run) => run.text == 'bb');
      expect(scriptRun.extraFields['lineHeight'], 1.7);
      expect(scriptRun.extraFields['script'], 'superscript');
      expect(scriptRun.fontSize, closeTo(6, 0.001));
    },
  );

