            const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'B1'),
            const FortuneCellCoord(1, 1): const FortuneCell(value: 'B2'),
            const FortuneCellCoord(2, 1): const FortuneCell(value: 'B3'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();

    await tester.sendKeyEvent(LogicalKeyboardKey.arrowRight);
    await tester.pump();
    expect(painter().selection.row, 0);
    expect(painter().selection.column, 1);
