    var selectionSave = painter().workbook.activeSheet.selectionSave! as List;
    var range = selectionSave.single as Map;
    expect(range['row'], [0, 0]);
    expect(range['column'], [1, 1]);
    expect(range['row_focus'], 0);
    expect(range['column_focus'], 1);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.shiftLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.arrowDown);
    await tester.sendKeyEvent(LogicalKeyboardKey.arrowDown);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.shiftLeft);
    await tester.pump();

    selectionSave = painter().workbook.activeSheet.selectionSave! as List;
