    range = selectionSave.single as Map;
    expect(range['row'], [0, 0]);
    expect(range['column'], [0, 1]);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(1, 0)]?.value, '1');
    expect(sheet.cells[const FortuneCellCoord(2, 0)]?.value, '1');
    expect(sheet.cells[const FortuneCellCoord(1, 1)]?.formula, '=A2+1');
    expect(sheet.cells[const FortuneCellCoord(2, 1)]?.formula, '=A3+1');
  });

