  testWidgets(
    'selection and fill handle drags auto scroll near viewport edge',
    (tester) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 360,
            height: 180,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final canvasSize = tester.getSize(find.byType(FortuneSheetCanvas));
      final rightEdgeX = canvasSize.width - 2;
      final selectionDrag = await tester.startGesture(
        topLeft + const Offset(83, 100),
        kind: PointerDeviceKind.mouse,
      );
      await selectionDrag.moveTo(topLeft + Offset(rightEdgeX, 100));
      await tester.pump();
      await selectionDrag.up();
      await tester.pump();

      expect(painter().selection.columnEnd, greaterThan(0));
      expect(painter().scrollOffset.dx, greaterThan(0));

      final fillWorkbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            },
          ),
        ],
      );
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 360,
            height: 180,
            child: FortuneSheetCanvas(workbook: fillWorkbook),
          ),
        ),
      );
      await tester.pump();

      await tester.tapAt(topLeft + const Offset(83, 100));
      await tester.pump();
      final fillDrag = await tester.startGesture(
        topLeft + const Offset(118, 108),
        kind: PointerDeviceKind.mouse,
      );
      await fillDrag.moveTo(topLeft + Offset(rightEdgeX, 108));
      await tester.pump();
      await fillDrag.up();
      await tester.pump();

      final sheet = painter().workbook.activeSheet;
      expect(painter().scrollOffset.dx, greaterThan(0));
      expect(sheet.cells[const FortuneCellCoord(0, 1)]?.value, 'A1');
    },
  );

  testWidgets('paste into dragged range starts at top left cell', (
    tester,
  ) async {
    const clipboardText = 'A\tB\nC\tD';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        if (call.method == 'Clipboard.getData') {
          return <String, Object?>{'text': clipboardText};
        }
        return null;
      },
    );
    addTearDown(() {
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });

    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.dragFrom(
      topLeft + const Offset(156, 138),
      const Offset(-73, -38),
    );
    await tester.pump();

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyV);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    final cells = painter().workbook.activeSheet.cells;
    expect(cells[const FortuneCellCoord(0, 0)]?.renderedText, 'A');
    expect(cells[const FortuneCellCoord(0, 1)]?.renderedText, 'B');
    expect(cells[const FortuneCellCoord(1, 0)]?.renderedText, 'C');
    expect(cells[const FortuneCellCoord(1, 1)]?.renderedText, 'D');
    expect(cells[const FortuneCellCoord(2, 0)]?.renderedText, 'A');
    expect(cells[const FortuneCellCoord(2, 1)]?.renderedText, 'B');
  });

