  testWidgets('clear commands clear content and preserve metadata', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: '=B1',
              displayValue: '10',
              formula: '=B1',
              sparkline: {'type': 'line'},
              comment: FortuneCellComment(value: 'note'),
              hyperlink: FortuneHyperlink(linkAddress: 'https://example.test'),
              background: Color(0xfffff2cc),
              bold: true,
            ),
            const FortuneCellCoord(0, 1): const FortuneCell(
              value: 'delete key',
              background: Color(0xffd9eaf7),
              italic: true,
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> openContextMenuAt(Offset local) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final gesture = await tester.startGesture(
        topLeft + local,
        kind: PointerDeviceKind.mouse,
        buttons: kSecondaryMouseButton,
      );
      await gesture.up();
      await tester.pump();
    }

    Future<void> tapContextCommand(String command) async {
      const rowHeight = 28.0;
      const dividerHeight = 9.0;
      var y = 6.0;
      for (final item in painter().contextMenuItems) {
        if (item == '|') {
          y += dividerHeight;
          continue;
        }
        if (item == command) {
          final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
          await tester.tapAt(
            topLeft + painter().contextMenuAt! + Offset(40, y + rowHeight / 2),
          );
          await tester.pump();
          return;
        }
        y += rowHeight;
      }
      fail('context command not found: $command');
    }

    await openContextMenuAt(const Offset(58, 100));
    await tapContextCommand('clear');

    var cell =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)];
    expect(cell?.renderedText, '');
    expect(cell?.formula, isNull);
    expect(cell?.sparkline, isNull);
    expect(cell?.comment?.value, 'note');
    expect(cell?.hyperlink?.linkAddress, 'https://example.test');
    expect(cell?.background, const Color(0xfffff2cc));
    expect(cell?.bold, isTrue);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(130, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.delete);
    await tester.pump();

    cell = painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 1)];
    expect(cell?.renderedText, '');
    expect(cell?.background, const Color(0xffd9eaf7));
    expect(cell?.italic, isTrue);

    await tester.sendKeyEvent(LogicalKeyboardKey.delete);
    await tester.pump();

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    cell = painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 1)];
    expect(cell?.renderedText, 'delete key');
    expect(cell?.background, const Color(0xffd9eaf7));
    expect(cell?.italic, isTrue);
    expect(
      painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(0, 0)]
          ?.renderedText,
      '',
    );
  });

