              'c': 0,
              'v': {
                'v': '=SUM(4,5)',
                'm': '9',
                'f': '=SUM(4,5)',
                'bg': '#ddebf7',
                'rawOnly': true,
              },
            },
          ],
        },
      ],
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> tapContextCommand(String command) async {
      const rowHeight = 28.0;
      const dividerHeight = 9.0;
      var y = 6.0;
      for (final item in painter().contextMenuItems) {
        if (item == '|') {
          y += dividerHeight;
          continue;
        }
        if (item == command) {
          final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
          await tester.tapAt(
            topLeft + painter().contextMenuAt! + Offset(40, y + rowHeight / 2),
          );
          await tester.pump();
          return;
        }
        y += rowHeight;
      }
      fail('context command not found: $command');
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final gesture = await tester.startGesture(
      topLeft + const Offset(58, 100),
      kind: PointerDeviceKind.mouse,
      buttons: kSecondaryMouseButton,
    );
    await gesture.up();
    await tester.pump();
    await tapContextCommand('clear');

    final sheet = painter().workbook.activeSheet;
    final json = FortuneSheetCodec.sheetToJson(sheet);
    final celldata = json['celldata']! as List;
    final cellJson = (celldata.single as Map)['v']! as Map;

    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.formula, isNull);
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText, '');
    expect(cellJson['v'], '');
    expect(cellJson.containsKey('f'), isFalse);
    expect(cellJson.containsKey('m'), isFalse);
    expect(cellJson['bg'], '#ddebf7');
    expect(cellJson['rawOnly'], isTrue);
    expect(painter().contextMenuAt, isNull);
  });

