      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      expect(sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText, 'Green');
      expect(sheet.cells[const FortuneCellCoord(0, 1)]?.renderedText, 'Yellow');
      expect(sheet.cells[const FortuneCellCoord(1, 0)], isNull);
      expect(
        sheet.cells[const FortuneCellCoord(1, 1)]?.renderedText,
        'Keep B2',
      );
      rules = sheet.dataVerification;
      expect((rules['0_0'] as Map)['value1'], 'Green,Yellow');
      expect((rules['0_1'] as Map)['value1'], 'Yellow,Orange');
      expect((rules['1_0'] as Map)['value1'], 'Red,Green,Blue');
      expect((rules['1_0'] as Map)['hintShow'], isFalse);
      expect((rules['1_1'] as Map)['value1'], 'Red,Green,Blue');
      expect((rules['1_1'] as Map)['hintShow'], isFalse);
    },
  );

