    final cutSheet = painter().workbook.activeSheet;
    expect(cutSheet.cells[const FortuneCellCoord(0, 0)], isNull);
    expect(cutSheet.cells[const FortuneCellCoord(3, 2)]?.hyperlink?.row, 3);
    expect(cutSheet.cells[const FortuneCellCoord(3, 2)]?.hyperlink?.column, 2);
    expect(cutSheet.hyperlinks.keys, containsAll(['3_1', '3_2']));
    expect(cutSheet.hyperlinks.keys, isNot(contains('0_0')));
    rawHyperlinks = cutSheet.rawHyperlinks! as Map;
    expect(rawHyperlinks.keys, containsAll(['3_1', '3_2', 'legacy']));
    expect(rawHyperlinks.keys, isNot(contains('0_0')));
    expect((rawHyperlinks['3_2'] as Map)['rawExtra'], 'source-link');
    expect(rawHyperlinks['legacy'], 'kept');

    (rawHyperlinks['3_2'] as Map)['rawExtra'] = 'mutated';
    expect((rawHyperlinks['3_1'] as Map)['rawExtra'], 'source-link');
  });

