  testWidgets(
    'cell editing commands respect locked cells and sheet protection',
    (tester) async {
      var clipboardText = 'blocked';
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        (call) async {
          if (call.method == 'Clipboard.getData') {
            return <String, Object?>{'text': clipboardText};
          }
          return null;
        },
      );
      addTearDown(() {
        tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
          SystemChannels.platform,
          null,
        );
      });

      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            authority: {'sheet': 1},
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(
                value: 'locked',
                locked: true,
              ),
              const FortuneCellCoord(1, 0): const FortuneCell(
                value: 'editable',
                locked: false,
              ),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 640,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      Future<void> openContextMenuAt(Offset local) async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        final gesture = await tester.startGesture(
          topLeft + local,
          kind: PointerDeviceKind.mouse,
          buttons: kSecondaryMouseButton,
        );
        await gesture.up();
        await tester.pump();
      }

      Future<void> tapContextCommand(String command) async {
        const rowHeight = 28.0;
        const dividerHeight = 9.0;
        var y = 6.0;
        for (final item in painter().contextMenuItems) {
          if (item == '|') {
            y += dividerHeight;
            continue;
          }
          if (item == command) {
            final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
            await tester.tapAt(
              topLeft +
                  painter().contextMenuAt! +
                  Offset(40, y + rowHeight / 2),
            );
            await tester.pump();
            return;
          }
          y += rowHeight;
        }
        fail('context command not found: $command');
      }

      await openContextMenuAt(const Offset(58, 100));
      await tapContextCommand('paste');
      expect(
        painter()
            .workbook
            .activeSheet
            .cells[const FortuneCellCoord(0, 0)]
            ?.renderedText,
        'locked',
      );

      await openContextMenuAt(const Offset(58, 100));
      await tapContextCommand('clear');
      expect(
        painter()
            .workbook
            .activeSheet
            .cells[const FortuneCellCoord(0, 0)]
            ?.renderedText,
        'locked',
      );

      clipboardText = 'changed\tdefault locked';
      await openContextMenuAt(const Offset(58, 120));
      await tapContextCommand('paste');

      final cells = painter().workbook.activeSheet.cells;
      expect(cells[const FortuneCellCoord(1, 0)]?.renderedText, 'changed');
      expect(cells[const FortuneCellCoord(1, 1)], isNull);
    },
  );

