    expect(sheet.dataVerification.containsKey('0_1'), isTrue);
    expect(sheet.dataVerification.containsKey('0_2'), isFalse);
    expect(sheet.hyperlinks.containsKey('2_1'), isTrue);
    expect(sheet.hyperlinks.containsKey('2_2'), isFalse);
    expect(sheet.filter.containsKey('1'), isTrue);
    expect(sheet.filter.containsKey('2'), isFalse);
    expect(sheet.borderInfo.single.ranges.single.columnStart, 0);
    expect(sheet.borderInfo.single.ranges.single.columnEnd, 1);
    expect(sheet.images.single.left, 74);
