    expect(positionedCell?.comment?.top, 40);
    expect(positionedCell?.comment?.left, 74);
    expect(positionedCell?.hyperlink?.row, 2);
    expect(positionedCell?.hyperlink?.column, 1);
    expect(sheet.frozen?.columnFocus, 1);
    final shiftedSelectionSave = sheet.selectionSave! as List;
    expect((shiftedSelectionSave.single as Map)['column'], [1, 1]);
    expect((shiftedSelectionSave.single as Map)['column_focus'], 1);
    expect(((sheet.filterSelect! as Map)['column'] as List), [1, 1]);
    expect(((sheet.calcChain! as List).single as Map)['c'], 1);
    final shiftedConditionFormat =
        (sheet.conditionFormats! as List).single as Map;
    final shiftedConditionRange =
        (shiftedConditionFormat['cellrange'] as List).single as Map;
    expect(shiftedConditionRange['column'], [1, 1]);
    final shiftedAlternateFormat =
        (sheet.alternateFormats! as List).single as Map;
    expect((shiftedAlternateFormat['cellrange'] as Map)['column'], [1, 1]);
    pivotTable = sheet.pivotTable! as Map;
    expect((pivotTable['pivot_select_save'] as Map)['column'], [1, 1]);
    expect((pivotTable['pivot_select_save'] as Map)['column_focus'], 1);
    expect(((pivotTable['source'] as List).single as Map)['c'], 1);
    expect((sheet.dynamicArrayCompute! as Map).containsKey('2_1'), isTrue);
    expect(((sheet.dynamicArray! as List).single as Map)['c'], 1);

