  testWidgets(
    'context menu insert and delete row column apply to dragged range',
    (tester) async {
      Future<FortuneSheetPainter> pumpCanvas(FortuneWorkbook workbook) async {
        await tester.pumpWidget(
          Directionality(
            textDirection: TextDirection.ltr,
            child: SizedBox(
              width: 640,
