        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      Future<void> dragRows1To3() async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.dragFrom(
          topLeft + const Offset(20, 100),
          const Offset(0, 38),
        );
        await tester.pump();
      }

      Future<void> dragColumnsAtoB() async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.dragFrom(
          topLeft + const Offset(83, 80),
          const Offset(73, 0),
        );
        await tester.pump();
      }

      Future<void> openContextMenuAt(Offset local) async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        final gesture = await tester.startGesture(
          topLeft + local,
          kind: PointerDeviceKind.mouse,
          buttons: kSecondaryMouseButton,
        );
        await gesture.up();
        await tester.pump();
      }

      Future<void> tapContextCommand(String command) async {
        const rowHeight = 28.0;
        const dividerHeight = 9.0;
        var y = 6.0;
        for (final item in painter().contextMenuItems) {
          if (item == '|') {
            y += dividerHeight;
            continue;
          }
          if (item == command) {
            final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
            await tester.tapAt(
              topLeft +
                  painter().contextMenuAt! +
                  Offset(40, y + rowHeight / 2),
            );
            await tester.pump();
            return;
          }
          y += rowHeight;
        }
        fail('context command not found: $command');
      }

      await pumpCanvas(
        FortuneWorkbook(
          sheets: [
            FortuneSheet(
              id: 's1',
              name: 'Sheet1',
              cells: {
                const FortuneCellCoord(0, 2): const FortuneCell(value: 'C1'),
                const FortuneCellCoord(3, 0): const FortuneCell(value: 'A4'),
              },
              rowHeights: {3: 31},
              columnWidths: {2: 105},
              hiddenRows: {4},
              hiddenColumns: {3},
              hiddenRowValues: {4: 0},
              hiddenColumnValues: {3: 0},
            ),
          ],
        ),
      );
      await dragRows1To3();
      await openContextMenuAt(const Offset(20, 120));
      await tapContextCommand('insert-row');

      var sheet = painter().workbook.activeSheet;
      expect(sheet.rowCount, 87);
      expect(sheet.cells[const FortuneCellCoord(3, 2)]?.renderedText, 'C1');
      expect(sheet.cells[const FortuneCellCoord(6, 0)]?.renderedText, 'A4');
      expect(sheet.rowHeights[6], 31);
      expect(sheet.hiddenRows, contains(7));
      expect(sheet.hiddenRowValues[7], 0);

      await dragColumnsAtoB();
      await openContextMenuAt(const Offset(130, 80));
      await tapContextCommand('insert-column');

      sheet = painter().workbook.activeSheet;
      expect(sheet.columnCount, 62);
      expect(sheet.cells[const FortuneCellCoord(3, 4)]?.renderedText, 'C1');
      expect(sheet.columnWidths[4], 105);
      expect(sheet.hiddenColumns, contains(5));
      expect(sheet.hiddenColumnValues[5], 0);

      await pumpCanvas(
        FortuneWorkbook(
          sheets: [
            FortuneSheet(
              id: 's1',
              name: 'Sheet1',
              cells: {
                const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
                const FortuneCellCoord(2, 1): const FortuneCell(value: 'B3'),
                const FortuneCellCoord(3, 0): const FortuneCell(value: 'A4'),
                const FortuneCellCoord(0, 2): const FortuneCell(value: 'C1'),
              },
              rowHeights: {3: 31},
              columnWidths: {2: 105},
              hiddenRows: {3},
              hiddenColumns: {2},
              hiddenRowValues: {3: 0},
              hiddenColumnValues: {2: 0},
            ),
          ],
        ),
      );
      await dragRows1To3();
      await openContextMenuAt(const Offset(20, 120));
      await tapContextCommand('delete-row');

      sheet = painter().workbook.activeSheet;
      expect(sheet.rowCount, 81);
      expect(sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText, 'A4');
      expect(sheet.cells[const FortuneCellCoord(0, 2)]?.renderedText, isNull);
      expect(sheet.rowHeights[0], 31);
