      await tapContextCommand('delete-column');

      final json = FortuneSheetCodec.sheetToJson(
        painter().workbook.activeSheet,
      );
      final config = json['config']! as Map;
      final celldata = json['celldata']! as List;
      final shiftedEntry = celldata.cast<Map>().singleWhere(
        (entry) => entry['r'] == 0 && entry['c'] == 1,
      );
      final shiftedCell = shiftedEntry['v']! as Map;
      final shiftedCellHyperlink = shiftedCell['hl']! as Map;
      final shiftedComment = shiftedCell['ps']! as Map;
      final shiftedNullEntry = celldata.cast<Map>().singleWhere(
        (entry) => entry['r'] == 2 && entry['c'] == 1,
      );
      final merge = config['merge']! as Map;
      final shiftedMerge = merge['0_1']! as Map;
      final borderInfo = (config['borderInfo']! as List).single as Map;
      final borderRange = (borderInfo['range']! as List).single as Map;
      final image = (json['images']! as List).single as Map;
      final dataVerification = json['dataVerification']! as Map;
      final hyperlinks = json['hyperlink']! as Map;
      final filter = json['filter']! as Map;
      final frozen = json['frozen']! as Map;
      final frozenRange = frozen['range']! as Map;
      final selectionSave = json['luckysheet_select_save']! as List;
      final selection = selectionSave.single as Map;
      final selectionRange =
          (json['luckysheet_selection_range']! as List).single as Map;
      final filterSelect = json['filter_select']! as Map;
      final calcChain = (json['calcChain']! as List).single as Map;
      final conditionFormats = json['luckysheet_conditionformat_save']! as List;
      final conditionFormat = conditionFormats.single as Map;
      final conditionRange =
          (conditionFormat['cellrange']! as List).single as Map;
      final alternateFormats = json['luckysheet_alternateformat_save']! as List;
      final alternateFormat = alternateFormats.single as Map;
      final alternateRange = alternateFormat['cellrange']! as Map;
      final pivotTable = json['pivotTable']! as Map;
      final pivotSelection = pivotTable['pivot_select_save']! as Map;
      final pivotSource = (pivotTable['source']! as List).single as Map;
      final dynamicArrayCompute = json['dynamicArray_compute']! as Map;
      final dynamicArray = (json['dynamicArray']! as List).single as Map;

      expect(json['column'], 2);
      expect(json['sheetExtra'], isTrue);
      expect(celldata.cast<Map>().any((entry) => entry['c'] == 2), isFalse);
      expect(shiftedCell['v'], 'C1');
      expect(shiftedCell['cellExtra'], isTrue);
      expect(shiftedCellHyperlink['r'], 0);
      expect(shiftedCellHyperlink['c'], 1);
      expect(shiftedCellHyperlink['hlExtra'], isTrue);
      expect(shiftedComment['top'], 15);
      expect(shiftedComment['left'], 96);
      expect(shiftedComment['commentExtra'], isTrue);
      expect(shiftedNullEntry['v'], isNull);
      expect((config['columnlen'] as Map).containsKey('2'), isFalse);
      expect((config['columnlen'] as Map)['1'], 101);
      expect((config['customWidth'] as Map)['1'], 1);
      expect((config['colhidden'] as Map)['1'], 9);
      expect(config['colReadOnly'], {'1': 'locked', 'rawOnly': 'keep'});
      expect(merge.containsKey('0_2'), isFalse);
      expect(shiftedMerge['r'], 0);
      expect(shiftedMerge['c'], 1);
      expect(shiftedMerge['cs'], 2);
      expect(shiftedMerge['mergeExtra'], isTrue);
      expect(borderInfo['borderExtra'], isTrue);
      expect(borderRange['column'], [1, 1]);
      expect(borderRange['column_focus'], 1);
      expect(borderRange['rangeExtra'], 'keep');
      expect(image['left'], 86);
      expect(image['top'], 10);
      expect(image['imageExtra'], isTrue);
      expect(dataVerification.containsKey('0_2'), isFalse);
      expect((dataVerification['0_1'] as Map)['dvExtra'], isTrue);
      expect(hyperlinks.containsKey('0_2'), isFalse);
      expect((hyperlinks['0_1'] as Map)['linkExtra'], isTrue);
      expect(filter.containsKey('2'), isFalse);
      expect((filter['1'] as Map)['filterExtra'], isTrue);
      expect(frozen['frozenExtra'], isTrue);
      expect(frozenRange['column_focus'], 1);
      expect(frozenRange['rangeExtra'], 'keep');
      expect(selection['column'], [1, 1]);
      expect(selection['column_focus'], 1);
      expect(selectionRange['column'], [1, 1]);
      expect(selectionRange['rangeExtra'], 'keep');
      expect(filterSelect['column'], [1, 1]);
      expect(filterSelect['filterSelectExtra'], 'keep');
      expect(calcChain['c'], 1);
      expect(calcChain['calcExtra'], isTrue);
      expect(conditionFormat['cfExtra'], isTrue);
      expect(conditionRange['row'], [0, 0]);
      expect(conditionRange['column'], [1, 1]);
      expect(conditionRange['rangeExtra'], 'keep');
      expect(alternateFormat['alternateExtra'], isTrue);
      expect(alternateRange['row'], [0, 0]);
      expect(alternateRange['column'], [1, 1]);
      expect(alternateRange['rangeExtra'], 'keep');
      expect(pivotTable['pivotExtra'], isTrue);
      expect(pivotSelection['column'], [1, 1]);
      expect(pivotSelection['column_focus'], 1);
      expect(pivotSelection['selectExtra'], 'keep');
      expect(pivotSource['c'], 1);
      expect(pivotSource['sourceExtra'], isTrue);
      expect(dynamicArrayCompute.containsKey('0_2'), isFalse);
      expect((dynamicArrayCompute['0_1'] as Map)['computeExtra'], isTrue);
      expect(dynamicArray['c'], 1);
      expect(dynamicArray['arrayExtra'], isTrue);
    },
  );

  testWidgets(
    'context menu set row height and column width commits input sizes',
    (tester) async {
      final workbook = FortuneWorkbook(
        settings: const FortuneSettings(
          defaultRowHeight: 21,
          defaultColWidth: 88,
        ),
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            rowHeights: {1: 30},
            columnWidths: {1: 110},
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 640,
            height: 560,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      Future<void> openContextMenuAt(Offset local) async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        final gesture = await tester.startGesture(
          topLeft + local,
          kind: PointerDeviceKind.mouse,
          buttons: kSecondaryMouseButton,
        );
        await gesture.up();
        await tester.pump();
      }

      Future<void> tapContextCommand(String command) async {
        const rowHeight = 28.0;
        const dividerHeight = 9.0;
        var y = 6.0;
        for (final item in painter().contextMenuItems) {
          if (item == '|') {
            y += dividerHeight;
            continue;
          }
          if (item == command) {
            final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
            await tester.tapAt(
              topLeft +
                  painter().contextMenuAt! +
                  Offset(40, y + rowHeight / 2),
            );
            await tester.pump();
            return;
          }
          y += rowHeight;
        }
        fail('context command not found: $command');
      }

      await openContextMenuAt(const Offset(20, 100));
      await tapContextCommand('set-row-height');
      expect(painter().axisSizeDialogOpen, isFalse);
      final rowHeightInput = find.byKey(
        const ValueKey('fortune-context-menu-input-set-row-height'),
      );
      expect(rowHeightInput, findsOneWidget);
      await tester.enterText(rowHeightInput, '42');
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();

      var sheet = painter().workbook.activeSheet;
      expect(sheet.rowHeights[0], 42);
      expect(sheet.customHeight[0], 1);
      expect(painter().contextMenuAt, isNull);
      expect(painter().axisSizeDialogOpen, isFalse);

      await openContextMenuAt(const Offset(150, 80));
      await tapContextCommand('set-column-width');
      expect(painter().axisSizeDialogOpen, isFalse);
      final columnWidthInput = find.byKey(
        const ValueKey('fortune-context-menu-input-set-column-width'),
      );
      expect(columnWidthInput, findsOneWidget);
      await tester.enterText(columnWidthInput, '132');
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      expect(sheet.columnWidths[1], 132);
      expect(sheet.customWidth[1], 1);
      expect(painter().contextMenuAt, isNull);
      expect(painter().axisSizeDialogOpen, isFalse);

      await openContextMenuAt(const Offset(150, 80));
      await tapContextCommand('set-column-width');
      expect(painter().axisSizeDialogOpen, isFalse);
      final unchangedColumnWidthInput = find.byKey(
        const ValueKey('fortune-context-menu-input-set-column-width'),
      );
      expect(unchangedColumnWidthInput, findsOneWidget);
      await tester.enterText(unchangedColumnWidthInput, '132');
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      expect(sheet.columnWidths[1], 132);
      expect(sheet.customWidth[1], 1);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      expect(sheet.rowHeights[0], 42);
      expect(sheet.columnWidths[1], 110);
      expect(sheet.customWidth.containsKey(1), isFalse);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      expect(sheet.rowHeights.containsKey(0), isFalse);
      expect(sheet.customHeight.containsKey(0), isFalse);
      expect(sheet.columnWidths[1], 110);
    },
  );

