    await openContextMenuAt(const Offset(150, 80));
    await tapContextCommand('set-column-width');

    expect(painter().axisSizeDialogOpen, isFalse);
    expect(painter().workbook.activeSheet.columnWidths, isEmpty);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    const sheetTop = 41.0 + 29.0;
    final columnGesture = await tester.startGesture(
      topLeft + const Offset(119, sheetTop + 10),
      kind: PointerDeviceKind.mouse,
    );
    await columnGesture.moveTo(topLeft + const Offset(160, sheetTop + 10));
    await tester.pump();
    await columnGesture.up();
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.columnWidths, isEmpty);
    expect(sheet.customWidth, isEmpty);
    expect(painter().resizeDragLineX, isNull);

    await tester.tapAt(topLeft + const Offset(119, sheetTop + 10));
    await tester.tapAt(topLeft + const Offset(119, sheetTop + 10));
    await tester.tapAt(topLeft + const Offset(20, sheetTop + 39));
    await tester.tapAt(topLeft + const Offset(20, sheetTop + 39));
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.columnWidths, isEmpty);
    expect(sheet.customWidth, isEmpty);
    expect(sheet.rowHeights, isEmpty);
    expect(sheet.customHeight, isEmpty);
  });

