  testWidgets(
    'row and column deletion do not resurrect stale raw metadata on export',
    (tester) async {
      Future<FortuneSheetPainter> pumpWorkbook(FortuneWorkbook workbook) async {
        await tester.pumpWidget(
          Directionality(
            textDirection: TextDirection.ltr,
            child: SizedBox(
              width: 640,
              height: 360,
              child: FortuneSheetCanvas(workbook: workbook),
            ),
          ),
        );
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      Future<void> openContextMenuAt(Offset local) async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        final gesture = await tester.startGesture(
          topLeft + local,
          kind: PointerDeviceKind.mouse,
          buttons: kSecondaryMouseButton,
        );
        await gesture.up();
        await tester.pump();
      }

      Future<void> tapContextCommand(String command) async {
        const rowHeight = 28.0;
        const dividerHeight = 9.0;
        var y = 6.0;
        for (final item in painter().contextMenuItems) {
          if (item == '|') {
            y += dividerHeight;
            continue;
          }
          if (item == command) {
            final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
            await tester.tapAt(
              topLeft +
                  painter().contextMenuAt! +
                  Offset(40, y + rowHeight / 2),
            );
            await tester.pump();
            return;
          }
          y += rowHeight;
        }
        fail('context command not found: $command');
      }

      await pumpWorkbook(
        FortuneSheetCodec.workbookFromJson({
          'data': [
            {
              'id': 's1',
              'name': 'Sheet1',
              'dataVerification': {
                '0_0': {'type': 'dropdown'},
              },
              'hyperlink': {
                '0_0': {
                  'linkType': 'webpage',
                  'linkAddress': 'https://example.test',
                },
              },
              'config': {
                'rowlen': {'0': 30},
                'customHeight': {'0': 1},
                'borderInfo': [
                  {
                    'rangeType': 'range',
                    'borderType': 'border-all',
                    'color': '#000000',
                    'style': 1,
                    'range': [
                      {
                        'row': [0, 0],
                        'column': [0, 0],
                      },
                    ],
                  },
                ],
              },
            },
          ],
        }),
      );

      await openContextMenuAt(const Offset(20, 100));
      await tapContextCommand('delete-row');

      var json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
      expect(json.containsKey('dataVerification'), isFalse);
      expect(json.containsKey('hyperlink'), isFalse);
      expect(json.containsKey('config'), isFalse);

      await pumpWorkbook(
        FortuneSheetCodec.workbookFromJson({
          'data': [
            {
              'id': 's1',
              'name': 'Sheet1',
              'dataVerification': {
                '0_0': {'type': 'dropdown'},
              },
              'filter': {
                '0': {'caljs': <String, Object?>{}},
              },
              'hyperlink': {
                '0_0': {
                  'linkType': 'webpage',
                  'linkAddress': 'https://example.test',
                },
              },
              'config': {
                'columnlen': {'0': 90},
                'customWidth': {'0': 1},
                'borderInfo': [
                  {
                    'rangeType': 'range',
                    'borderType': 'border-all',
                    'color': '#000000',
                    'style': 1,
                    'range': [
                      {
                        'row': [0, 0],
                        'column': [0, 0],
                      },
                    ],
                  },
                ],
              },
            },
          ],
        }),
      );

      await openContextMenuAt(const Offset(58, 80));
      await tapContextCommand('delete-column');

      json = FortuneSheetCodec.sheetToJson(painter().workbook.activeSheet);
      expect(json.containsKey('dataVerification'), isFalse);
      expect(json.containsKey('filter'), isFalse);
      expect(json.containsKey('hyperlink'), isFalse);
      expect(json.containsKey('config'), isFalse);
    },
  );

