        y += rowHeight;
      }
      fail('context command not found: $command');
    }

    await openContextMenuAt(const Offset(20, 120));
    await tapContextCommand('hide-row');

    var sheet = painter().workbook.activeSheet;
    expect(sheet.hiddenRows, contains(1));

    await openContextMenuAt(const Offset(20, 120));
    await tapContextCommand('show-hidden-row');

    sheet = painter().workbook.activeSheet;
    expect(sheet.hiddenRows, isNot(contains(1)));
    expect(sheet.hiddenRowValues.containsKey(1), isFalse);

    await openContextMenuAt(const Offset(130, 80));
    await tapContextCommand('hide-column');

    sheet = painter().workbook.activeSheet;
    expect(sheet.hiddenColumns, contains(1));

    await openContextMenuAt(const Offset(130, 80));
    await tapContextCommand('show-hidden-column');

    sheet = painter().workbook.activeSheet;
    expect(sheet.hiddenColumns, isNot(contains(1)));
    expect(sheet.hiddenColumnValues.containsKey(1), isFalse);
  });

