    await tapContextCommand('hide-column');

    sheet = painter().workbook.activeSheet;
    expect(sheet.hiddenColumns, containsAll([0, 1]));
    expect(sheet.hiddenColumnValues[0], 0);
    expect(sheet.hiddenColumnValues[1], 0);
  });

