  testWidgets('dragging row and column header edges resizes axes', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    const sheetTop = 41.0 + 29.0;

    final hover = await tester.createGesture(kind: PointerDeviceKind.mouse);
    await hover.addPointer(
      location: topLeft + const Offset(124, sheetTop + 10),
    );
    await hover.moveTo(topLeft + const Offset(124, sheetTop + 10));
    await tester.pump();
    expect(
      tester.widget<MouseRegion>(find.byType(MouseRegion).first).cursor,
      SystemMouseCursors.resizeLeftRight,
    );
    await hover.moveTo(topLeft + const Offset(20, sheetTop + 45));
    await tester.pump();
    expect(
      tester.widget<MouseRegion>(find.byType(MouseRegion).first).cursor,
      SystemMouseCursors.resizeUpDown,
    );
    await hover.removePointer();

    final columnGesture = await tester.startGesture(
      topLeft + const Offset(124, sheetTop + 10),
      kind: PointerDeviceKind.mouse,
    );
    await columnGesture.moveTo(topLeft + const Offset(154, sheetTop + 10));
    await tester.pump();

    expect(painter().resizeDragLineX, isNotNull);
    expect(painter().workbook.activeSheet.columnWidths[0], 103);
    expect(painter().workbook.activeSheet.customWidth[0], 1);

    await columnGesture.up();
    await tester.pump();

    expect(painter().resizeDragLineX, isNull);
    expect(painter().workbook.activeSheet.columnWidths[0], 103);

    final rowGesture = await tester.startGesture(
      topLeft + const Offset(20, sheetTop + 45),
      kind: PointerDeviceKind.mouse,
    );
    await rowGesture.moveTo(topLeft + const Offset(20, sheetTop + 57));
    await tester.pump();

    expect(painter().resizeDragLineY, isNotNull);
    expect(painter().workbook.activeSheet.rowHeights[0], 31);
    expect(painter().workbook.activeSheet.customHeight[0], 1);

    await rowGesture.up();
    await tester.pump();

    expect(painter().resizeDragLineY, isNull);
    expect(painter().workbook.activeSheet.rowHeights[0], 31);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.activeSheet.rowHeights.containsKey(0), isFalse);
    expect(painter().workbook.activeSheet.columnWidths[0], 103);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.activeSheet.columnWidths.containsKey(0), isFalse);
  });

