              value: 'line one\nline two\nline three',
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    const sheetTop = 41.0 + 29.0;

    await tester.tapAt(topLeft + const Offset(119, sheetTop + 10));
    await tester.tapAt(topLeft + const Offset(119, sheetTop + 10));
    await tester.pump();

    var sheet = painter().workbook.activeSheet;
    expect(sheet.columnWidths[0], greaterThan(73));
    expect(sheet.customWidth[0], 1);
    expect(painter().resizeDragLineX, isNull);

    await tester.tapAt(topLeft + const Offset(20, sheetTop + 59));
    await tester.tapAt(topLeft + const Offset(20, sheetTop + 59));
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.rowHeights[1], greaterThan(19));
    expect(sheet.customHeight[1], 1);
    expect(painter().resizeDragLineY, isNull);

    final fittedRowHeight = sheet.rowHeights[1];
    await tester.tapAt(topLeft + const Offset(20, sheetTop + 59));
    await tester.tapAt(topLeft + const Offset(20, sheetTop + 59));
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.rowHeights[1], fittedRowHeight);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.rowHeights.containsKey(1), isFalse);
    expect(sheet.columnWidths[0], greaterThan(73));

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.activeSheet.columnWidths.containsKey(0), isFalse);
  });

