            'columnlen': {'0': 73, 'rawColumnOnly': true},
            'customHeight': {'rawCustomHeightOnly': true},
            'customWidth': {'rawCustomWidthOnly': true},
            'configExtra': 'keep',
          },
        },
      ],
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
