    final config = json['config']! as Map;
    final rowlen = config['rowlen']! as Map;
    final columnlen = config['columnlen']! as Map;
    final customHeight = config['customHeight']! as Map;
    final customWidth = config['customWidth']! as Map;
    final celldata = json['celldata']! as List;
    final wideCell = celldata.cast<Map>().singleWhere(
      (entry) => entry['r'] == 0 && entry['c'] == 0,
    );
    final tallCell = celldata.cast<Map>().singleWhere(
      (entry) => entry['r'] == 1 && entry['c'] == 1,
    );

    expect(config['configExtra'], 'keep');
