    expect(columnlen.containsKey('rawColumnOnly'), isFalse);
    expect(customHeight, {'1': 1});
    expect(customWidth, {'0': 1});
    expect((wideCell['v'] as Map)['rawOnly'], isTrue);
    expect((tallCell['v'] as Map)['rowCellExtra'], isTrue);
  });

