  testWidgets('toolbar hover exposes tooltip label for hovered button', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1000, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });
    var clipboardText = '';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        switch (call.method) {
          case 'Clipboard.setData':
            clipboardText = (call.arguments as Map)['text'] as String;
            return null;
          case 'Clipboard.getData':
            return <String, Object?>{'text': clipboardText};
        }
        return null;
      },
    );

    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1000,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final gesture = await tester.createGesture(kind: PointerDeviceKind.mouse);
    await gesture.addPointer(location: topLeft + const Offset(1, 1));
    await gesture.moveTo(topLeft + toolbarCenter(fortuneToolbarBoldCommand));
    await tester.pump();

    expect(painter().toolbarHoveredKey, fortuneToolbarBoldCommand);
    expect(
      fortuneToolbarTooltipLabels[painter().toolbarHoveredKey],
      'Bold (Ctrl+B)',
    );

    await gesture.moveTo(topLeft + const Offset(80, 120));
    await tester.pump();

    expect(painter().toolbarHoveredKey, isNull);

    await gesture.removePointer();
  });

