      viewportHeight: 160,
      naturalHeight: naturalHeight,
    );

    final mouse = await tester.createGesture(kind: PointerDeviceKind.mouse);
    await mouse.addPointer(location: topLeft + const Offset(1, 1));
    await mouse.moveTo(
      topLeft +
          toolbarPopupItemCenterForKey(
            popupLeft: popupLeft,
            toolbarKey: fortuneToolbarBorderPopupKey,
            itemIndex: 0,
          ),
    );
    await tester.pump();

    expect(painter().toolbarBorderHoveredTopLevelIndex, 0);

    await mouse.moveTo(
      topLeft +
          Offset(
            popupLeft +
                fortuneToolbarPopupWidthFor(fortuneToolbarBorderPopupKey) / 2,
            fortuneToolbarPopupTop +
                visibleHeight -
                fortuneToolbarPopupScrollIndicatorInset -
                fortuneToolbarPopupScrollIndicatorHeight / 2,
          ),
    );
    await tester.pump();

    expect(painter().toolbarBorderHoveredTopLevelIndex, isNull);
    expect(painter().toolbarPopupHoveredIndex, isNull);

    await mouse.removePointer();
  });

