  test('toolbar keeps text combos wide before overflowing later buttons', () {
    final narrowEntries = fortuneVisibleToolbarItemRects(900);
    final narrowRects = Map<String, Rect>.fromEntries(narrowEntries);

    expect(narrowRects[fortuneToolbarFormatCommand]?.width, 78);
    expect(narrowRects[fortuneToolbarFontPopupKey]?.width, 126);
    expect(narrowRects[fortuneToolbarFontSizePopupKey]?.width, 36);
    expect(
      fortuneToolbarComboArrowRect(
        narrowRects[fortuneToolbarFontSizePopupKey]!,
      ),
      const Rect.fromLTWH(543, 7, 14, 28),
    );
    expect(
      narrowRects.containsKey(fortuneToolbarConditionFormatPopupKey),
      isFalse,
    );
    expect(narrowRects.containsKey(fortuneToolbarFontColorPopupKey), isTrue);
    expect(narrowRects.containsKey('more'), isTrue);

    final moreIndex = narrowEntries.indexWhere((entry) => entry.key == 'more');
    expect(moreIndex, greaterThan(0));
    final previousRect = narrowEntries[moreIndex - 1].value;
    final moreRect = narrowEntries[moreIndex].value;
    expect(moreRect.left - previousRect.right, 8);
  });

  test('toolbar reserves combo arrow width before moving items into more', () {
    final narrowEntries = fortuneVisibleToolbarItemRects(900);
    final overflowItems = fortuneToolbarOverflowItems(900);

    expect(narrowEntries.last.key, 'more');
    expect(overflowItems, isNotEmpty);

    for (final entry in narrowEntries.where((entry) => entry.key != 'more')) {
      if (!fortuneToolbarItemUsesCombo(entry.key, 900)) {
        continue;
      }
      if (fortuneToolbarItemUsesTextCombo(entry.key, 900)) {
        continue;
      }
      final arrowRect = fortuneToolbarComboArrowRect(entry.value);
      expect(
        fortuneToolbarItemAdvance(entry.key, width: 900),
        fortuneToolbarIconComboAdvance,
      );
      expect(entry.value.width, greaterThanOrEqualTo(38));
      expect(arrowRect.left, greaterThanOrEqualTo(entry.value.left));
      expect(arrowRect.top, greaterThanOrEqualTo(entry.value.top));
      expect(arrowRect.right, lessThanOrEqualTo(entry.value.right));
      expect(arrowRect.bottom, lessThanOrEqualTo(entry.value.bottom));
    }

    final lastVisibleItem = narrowEntries[narrowEntries.length - 2].key;
    expect(
      fortuneToolbarItems.indexOf(overflowItems.first),
      greaterThan(fortuneToolbarItems.indexOf(lastVisibleItem)),
    );
  });

