    await tester.pump();

    var cell =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
    expect(cell.value, 'styled');
    expect(cell.bold, isTrue);
    expect(cell.italic, isTrue);
    expect(cell.underline, isTrue);
    expect(cell.strikeThrough, isTrue);
