  testWidgets('controller undo and redo restore workbook snapshots', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final controller = FortuneSheetController();
    final ops = <List<FortuneOp>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'styled'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            onOp: ops.add,
          ),
        ),
      ),
    );

    FortuneCell activeCell() {
      final painter =
          tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter;
      return painter.workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

    FortuneOp singleCellOp() {
      final cellOps = ops
          .expand((batch) => batch)
          .where(
            (op) => op['id'] == 's1' && op['path'].toString() == '[data, 0, 0]',
          );
      return cellOps.single;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarBoldCommand));
    await tester.pump();
    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarItalicCommand));
    await tester.pump();

    expect(controller.isAttached, isTrue);
    expect(activeCell().bold, isTrue);
    expect(activeCell().italic, isTrue);

    ops.clear();
    controller.handleUndo();
    await tester.pump();

    expect(activeCell().bold, isTrue);
    expect(activeCell().italic, isFalse);
    expect(singleCellOp()['op'], 'replace');
    final undoValue = singleCellOp()['value']! as Map;
    expect(undoValue['bl'], 1);
    expect(undoValue.containsKey('it'), isFalse);

    ops.clear();
    controller.handleUndo();
    await tester.pump();

    expect(activeCell().bold, isFalse);
    expect(activeCell().italic, isFalse);
    expect(singleCellOp()['op'], 'replace');
    expect(singleCellOp()['value'], {'v': 'styled'});

    ops.clear();
    controller.handleRedo();
    await tester.pump();

    expect(activeCell().bold, isTrue);
    expect(activeCell().italic, isFalse);
    expect(singleCellOp()['op'], 'replace');
    final redoBoldValue = singleCellOp()['value']! as Map;
    expect(redoBoldValue['bl'], 1);
    expect(redoBoldValue.containsKey('it'), isFalse);

    ops.clear();
    controller.handleRedo();
    await tester.pump();

    expect(activeCell().bold, isTrue);
    expect(activeCell().italic, isTrue);
    expect(singleCellOp()['op'], 'replace');
    final redoItalicValue = singleCellOp()['value']! as Map;
    expect(redoItalicValue['bl'], 1);
    expect(redoItalicValue['it'], 1);
  });

