          rawCelldata: const [
            {
              'r': 0,
              'c': 1,
              'v': {'v': 'stale'},
            },
          ],
          hasRawCelldata: true,
          calcChain: const [
            {'r': 0, 'c': 1, 'id': 's1'},
          ],
          cells: {
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'fresh'),
          },
        ).setSelection(const [
          FortuneRange(rowStart: 0, rowEnd: 1, columnStart: 1, columnEnd: 2),
        ]),
        FortuneSheet(
          id: 's2',
          name: 'Sheet2',
          rowHeights: const {4: 55.0},
          columnWidths: const {2: 99.0},
        ).setSelection(const [
          FortuneRange(rowStart: 4, rowEnd: 5, columnStart: 2, columnEnd: 3),
        ]),
      ],
      settings: FortuneSettings(
        beforeActivateSheet: (id) {
          activationCalls.add({'hook': 'beforeActivate', 'id': id});
          return true;
        },
        afterActivateSheet: (id) {
          activationCalls.add({'hook': 'afterActivate', 'id': id});
        },
        beforeUpdateSheetName: (id, oldName, newName) {
          renameCalls.add({
            'hook': 'beforeRename',
            'id': id,
            'old': oldName,
            'new': newName,
          });
          return true;
        },
        afterUpdateSheetName: (id, oldName, newName) {
          renameCalls.add({
            'hook': 'afterRename',
            'id': id,
            'old': oldName,
            'new': newName,
          });
        },
        beforePaste: (selection, content) {
          pasteHookCalls.add({
            'rowStart': selection?.single.rowStart,
            'rowEnd': selection?.single.rowEnd,
            'columnStart': selection?.single.columnStart,
            'columnEnd': selection?.single.columnEnd,
            'content': content,
          });
          return true;
        },
        afterSelectionChange: (sheetId, selection) {
          selectionCalls.add({
            'sheetId': sheetId,
            'row': selection.row,
            'column': selection.column,
            'rowEnd': selection.rowEnd,
            'columnEnd': selection.columnEnd,
          });
        },
      ),
    );

    expect(controller.dataToCelldata(null), isEmpty);
    expect(controller.celldataToData([]), [
      [null],
    ]);
    expect(
      controller.dataToCelldata([
        [
          null,
          {'v': 2},
        ],
      ]),
      [
        {
          'r': 0,
          'c': 1,
          'v': {'v': 2},
        },
      ],
    );
    expect(
      controller.celldataToData(
        [
          {
            'r': 1,
            'c': 1,
            'v': {'v': 9},
          },
        ],
        rowCount: 3,
        columnCount: 3,
      ),
      [
        [null, null, null],
        [
          null,
          {'v': 9},
          null,
        ],
        [null, null, null],
      ],
    );

    expect(controller.getAllSheets(), isNull);
    expect(controller.getSheet(), isNull);
    expect(controller.getSheetWithLatestCelldata(), isNull);
    expect(controller.getFlowdata(), isNull);
    expect(controller.getAllFunctionGroup(), isNull);
    expect(controller.getRowHeight([0]), isNull);
    expect(controller.getColumnWidth([0]), isNull);
    expect(controller.paste('A'), isNull);
    controller.activateSheet(id: 's2');
    controller.setSheetName('Detached', id: 's1');

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    final allSheets = controller.getAllSheets();
    expect(allSheets, hasLength(2));
    expect(allSheets![0].id, 's1');
    expect(allSheets[0].name, 'Sheet1');
    expect(allSheets[1].id, 's2');
    expect(controller.getSheet()?.id, 's1');
    expect(controller.getSheet(id: 's1')?.name, 'Sheet1');
    expect(controller.getSheet(index: 0)?.id, 's1');
    expect(controller.getSheet(id: 'missing'), isNull);
    expect(controller.getSheet(index: 99), isNull);
    expect(controller.getSheet(), isNot(same(workbook.activeSheet)));
    final latestCelldata = controller.getSheetWithLatestCelldata(id: 's1')!;
    expect(latestCelldata['id'], 's1');
    expect((latestCelldata['celldata'] as List).single, {
      'r': 0,
      'c': 1,
      'v': {'v': 'fresh'},
    });
    expect(controller.getSheetWithLatestCelldata(id: 'missing'), isNull);
    final flowdata = controller.getFlowdata(id: 's1')!;
    expect(flowdata, hasLength(1));
    expect(flowdata[0], hasLength(2));
    expect(flowdata[0][1]?.value, 'fresh');
    expect(controller.getFlowdata(index: 1), const []);
    expect(controller.getFlowdata(id: 'missing'), isNull);
    expect(controller.getAllFunctionGroup(), [
      {'r': 0, 'c': 1, 'id': 's1'},
    ]);
    final copyPayload = controller.copy()!;
    expect(copyPayload['luckysheetCopySave'], {
      'dataSheetId': 's1',
      'copyRange': [
        {
          'row': [0, 1],
          'column': [1, 2],
        },
      ],
      'RowlChange': false,
      'HasMC': false,
    });
    expect(copyPayload['luckysheetSelectionRange'], [
      {
        'row': [0, 1],
        'column': [1, 2],
      },
    ]);
    expect(copyPayload['pasteIsCut'], isFalse);
    expect(copyPayload['copyHtml'], contains('fortune-copy-action-table'));
    expect(copyPayload['copyHtml'], contains('fresh'));
    expect(controller.paste('A\tB'), {
      'type': 'plainTextPaste',
      'text': 'A\tB',
      'writeHtml': 'A\tB',
    });
    expect(pasteHookCalls.last, {
      'rowStart': 0,
      'rowEnd': 1,
      'columnStart': 1,
      'columnEnd': 2,
      'content': 'A\tB',
    });
    expect(
      controller.paste('=SUM(A1:A2)'),
      containsPair('type', 'formulaStringPaste'),
    );
    final inactiveCopyPayload = controller.copy(const {'id': 's2'})!;
    expect(inactiveCopyPayload['luckysheetCopySave'], {
      'dataSheetId': 's2',
      'copyRange': [
        {
          'row': [4, 5],
          'column': [2, 3],
        },
      ],
      'RowlChange': true,
      'HasMC': false,
    });
    expect(
      inactiveCopyPayload['copyHtml'],
      contains('fortune-copy-action-table'),
    );
    expect(
      controller.paste('<table><tr><td>Z</td></tr></table>', const {
        'id': 's2',
      }),
      containsPair('type', 'htmlTablePaste'),
    );
    expect(pasteHookCalls.last, {
      'rowStart': 4,
      'rowEnd': 5,
      'columnStart': 2,
      'columnEnd': 3,
      'content': '<table><tr><td>Z</td></tr></table>',
    });
    expect(controller.getRowHeight([-1, 0, 2]), {0: 19, 2: 44});
    expect(controller.getColumnWidth([-1, 1, 3]), {1: 88, 3: 73});
    expect(controller.getRowHeight([0, 4], const {'id': 's2'}), {0: 19, 4: 55});
    expect(controller.getColumnWidth([2, 3], const {'index': '1'}), {
      2: 99,
      3: 73,
    });
    expect(controller.getSheet()?.id, 's1');
    expect(() => controller.getRowHeight(const []), throwsA(INVALID_PARAMS));
    expect(() => controller.getColumnWidth(const []), throwsA(INVALID_PARAMS));
    expect(
      () => controller.activateSheet(id: 'missing'),
      throwsA(SHEET_NOT_FOUND),
    );
    expect(() => controller.activateSheet(index: 99), throwsA(SHEET_NOT_FOUND));
    expect(
      () => controller.setSheetName('Missing', id: 'missing'),
      throwsA(SHEET_NOT_FOUND),
    );

    expect(selectionCalls, [
      {'sheetId': 's1', 'row': 0, 'column': 1, 'rowEnd': 1, 'columnEnd': 2},
    ]);

    final selection = controller.getSelection();
    expect(selection, hasLength(1));
    expect(selection!.single.rowStart, 0);
    expect(selection.single.rowEnd, 1);
    expect(selection.single.columnStart, 1);
    expect(selection.single.columnEnd, 2);

    controller.setSelection(const [
      FortuneRange(rowStart: 2, rowEnd: 3, columnStart: 0, columnEnd: 1),
    ]);
    await tester.pump();

    expect(selectionCalls.last, {
      'sheetId': 's1',
      'row': 2,
      'column': 0,
      'rowEnd': 3,
      'columnEnd': 1,
    });

    final updatedSelection = controller.getSelection();
    expect(updatedSelection, hasLength(1));
    expect(updatedSelection!.single.rowStart, 2);
    expect(updatedSelection.single.rowEnd, 3);
    expect(updatedSelection.single.columnStart, 0);
    expect(updatedSelection.single.columnEnd, 1);

    final painter =
        tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
    final rawSelection = painter.workbook.activeSheet.selectionRange! as List;
    expect((rawSelection.single as Map)['row'], [2, 3]);
    expect((rawSelection.single as Map)['column'], [0, 1]);

    controller.setSheetName('Renamed', id: 's2');
    await tester.pump();

    expect(controller.getSheet()?.id, 's1');
    expect(controller.getSheet(id: 's1')?.name, 'Sheet1');
    expect(controller.getSheet(id: 's2')?.name, 'Renamed');
    expect(renameCalls, [
      {'hook': 'beforeRename', 'id': 's2', 'old': 'Sheet2', 'new': 'Renamed'},
      {'hook': 'afterRename', 'id': 's2', 'old': 'Sheet2', 'new': 'Renamed'},
    ]);

    controller.setSheetName('Renamed', id: 's1');
    controller.setSheetName('', id: 's2');
    await tester.pump();

    expect(controller.getSheet(id: 's1')?.name, 'Sheet1');
    expect(controller.getSheet(id: 's2')?.name, 'Renamed');
    expect(renameCalls, hasLength(2));

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet(id: 's2')?.name, 'Sheet2');

    controller.handleRedo();
    await tester.pump();

    expect(controller.getSheet(id: 's2')?.name, 'Renamed');

    controller.activateSheet(id: 's2');
    await tester.pump();

    expect(activationCalls, [
      {'hook': 'beforeActivate', 'id': 's2'},
      {'hook': 'afterActivate', 'id': 's2'},
    ]);
    expect(controller.getSheet()?.id, 's2');
    expect(selectionCalls.last, {
      'sheetId': 's2',
      'row': 4,
      'column': 2,
      'rowEnd': 5,
      'columnEnd': 3,
    });

    controller.activateSheet(index: 0);
    await tester.pump();

    expect(controller.getSheet()?.id, 's1');
  });

  testWidgets('controller reorders sheets by id', (tester) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1', order: 0),
        FortuneSheet(id: 's2', name: 'Sheet2', order: 1),
        FortuneSheet(id: 's3', name: 'Sheet3', order: 2),
      ],
      activeSheetIndex: 1,
    );

    controller.setSheetOrder({'s3': 0});

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);

    controller.setSheetOrder({'s3': 0, 's1': 2});
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's3',
      's2',
      's1',
    ]);
    expect(controller.getAllSheets()!.map((sheet) => sheet.order), [0, 1, 2]);
    expect(controller.getSheet()?.id, 's2');

    controller.setSheetOrder({'missing': 0});
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's3',
      's2',
      's1',
    ]);

    controller.handleUndo();
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);
    expect(controller.getSheet()?.id, 's2');

    controller.handleRedo();
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's3',
      's2',
      's1',
    ]);
    expect(controller.getSheet()?.id, 's2');

    final disabledController = FortuneSheetController();
    final disabledWorkbook = workbook.copyWith(
      settings: const FortuneSettings(allowEdit: false),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: disabledWorkbook,
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.setSheetOrder({'s3': 0, 's1': 2});
    await tester.pump();

    expect(disabledController.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);
  });

  testWidgets('controller adds sheets through workbook API policy', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final calls = <Map<String, Object?>>[];
    var nextGeneratedId = 'generated-sheet';
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1', order: 0)],
      settings: FortuneSettings(
        generateSheetId: () => nextGeneratedId,
        beforeAddSheet: (sheet) {
          calls.add({
            'hook': 'beforeAdd',
            'id': sheet.id,
            'name': sheet.name,
            'order': sheet.order,
          });
          return true;
        },
        afterAddSheet: (sheet) {
          calls.add({
            'hook': 'afterAdd',
            'id': sheet.id,
            'name': sheet.name,
            'order': sheet.order,
          });
        },
      ),
    );

    controller.addSheet(name: 'Detached');

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s1']);

    controller.addSheet(name: 'Generated');
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      'generated-sheet',
    ]);
    expect(controller.getSheet()?.id, 'generated-sheet');
    expect(controller.getSheet()?.name, 'Generated');
    expect(calls, [
      {
        'hook': 'beforeAdd',
        'id': 'generated-sheet',
        'name': 'Generated',
        'order': 1,
      },
      {
        'hook': 'afterAdd',
        'id': 'generated-sheet',
        'name': 'Generated',
        'order': 1,
      },
    ]);

    controller.addSheet(id: 'explicit', name: 'Explicit', rowCount: 12);
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      'generated-sheet',
      'explicit',
    ]);
    expect(controller.getSheet()?.id, 'generated-sheet');
    expect(controller.getSheet(id: 'explicit')?.rowCount, 12);
    expect(calls.last, {
      'hook': 'afterAdd',
      'id': 'explicit',
      'name': 'Explicit',
      'order': 2,
    });

    calls.clear();
    controller.addSheet(id: 'explicit', name: 'Duplicate');
    await tester.pump();

    expect(controller.getAllSheets(), hasLength(3));
    expect(calls, isEmpty);

    controller.handleUndo();
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      'generated-sheet',
    ]);
    expect(controller.getSheet()?.id, 'generated-sheet');

    controller.handleRedo();
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      'generated-sheet',
      'explicit',
    ]);
    expect(controller.getSheet()?.id, 'generated-sheet');

    final disabledController = FortuneSheetController();
    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook.copyWith(
              settings: const FortuneSettings(allowEdit: false),
            ),
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.addSheet(id: 'blocked', name: 'Blocked');
    await tester.pump();

    expect(disabledController.getAllSheets()!.map((sheet) => sheet.id), ['s1']);
  });

