  testWidgets('controller clearSheet resets sheet data in place', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          order: 0,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'typed'),
          },
          rowHeights: const {0: 44},
          columnWidths: const {1: 120},
          conditionFormats: const [
            {'type': 'cellIs'},
          ],
          hasRawConditionFormats: true,
        ).setSelection(const [
          FortuneRange(rowStart: 0, rowEnd: 0, columnStart: 0, columnEnd: 0),
        ]),
        FortuneSheet(id: 's2', name: 'Sheet2', order: 1),
      ],
    );
    final changes = <FortuneWorkbook>[];

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            onChange: changes.add,
          ),
        ),
      ),
    );
    await tester.pump();
    changes.clear();

    controller.clearSheet(id: 's1', rowCount: 12, columnCount: 8);
    await tester.pump();

    final cleared = controller.getSheet(id: 's1')!;
    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s1', 's2']);
    expect(controller.getSheet()?.id, 's1');
    expect(cleared.name, 'Sheet1');
    expect(cleared.order, 0);
    expect(cleared.rowCount, 12);
    expect(cleared.columnCount, 8);
    expect(cleared.cells, isEmpty);
    expect(cleared.rowHeights, isEmpty);
    expect(cleared.columnWidths, isEmpty);
    expect(cleared.conditionFormats, isNull);
    expect(controller.getSelection(), isEmpty);
    expect(changes, hasLength(1));

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet(id: 's1')?.getCellValue(0, 0), 'typed');
    expect(controller.getSheet(id: 's1')?.rowHeights, {0: 44});

    changes.clear();
    controller.batchCallApis(const [
      {
        'name': 'clearSheet',
        'args': [
          {'id': 's1', 'rowCount': '4', 'columnCount': '5'},
        ],
      },
    ]);
    await tester.pump();

    expect(controller.getSheet(id: 's1')?.rowCount, 4);
    expect(controller.getSheet(id: 's1')?.columnCount, 5);
    expect(controller.getSheet(id: 's1')?.cells, isEmpty);
    expect(changes, hasLength(1));
  });

