  testWidgets('controller deletes sheets with canvas-safe policy', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final calls = <Map<String, Object?>>[];
    final ops = <List<FortuneOp>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1', order: 0),
        FortuneSheet(id: 's2', name: 'Sheet2', order: 1).setSelection(const [
          FortuneRange(rowStart: 3, rowEnd: 4, columnStart: 1, columnEnd: 2),
        ]),
        FortuneSheet(id: 's3', name: 'Sheet3', order: 2),
      ],
      activeSheetIndex: 1,
      settings: FortuneSettings(
        beforeDeleteSheet: (id) {
          calls.add({'hook': 'beforeDelete', 'id': id});
          return id != 's3';
        },
        afterDeleteSheet: (id) {
          calls.add({'hook': 'afterDelete', 'id': id});
        },
      ),
    );

    controller.deleteSheet(id: 's1');

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            onOp: ops.add,
          ),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);
    expect(
      () => controller.deleteSheet(id: 'missing'),
      throwsA(SHEET_NOT_FOUND),
    );

    controller.deleteSheet(id: 's1');
    await tester.pump();

    expect(ops, hasLength(1));
    expect(ops.single, [
      {
        'op': 'deleteSheet',
        'id': 's1',
        'path': [],
        'value': {'id': 's1', 'name': 'Sheet1', 'order': 0, 'status': 0},
      },
      {
        'op': 'replace',
        'id': 's2',
        'path': ['order'],
        'value': 0,
      },
      {
        'op': 'replace',
        'id': 's3',
        'path': ['order'],
        'value': 1,
      },
    ]);
    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s2', 's3']);
    expect(controller.getAllSheets()!.map((sheet) => sheet.order), [0, 1]);
    expect(controller.getSheet()?.id, 's2');
    expect(calls, [
      {'hook': 'beforeDelete', 'id': 's1'},
      {'hook': 'afterDelete', 'id': 's1'},
    ]);

    ops.clear();
    controller.deleteSheet(id: 's3');
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s2', 's3']);
    expect(calls.last, {'hook': 'beforeDelete', 'id': 's3'});

    ops.clear();
    controller.deleteSheet(index: 0);
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s3']);
    expect(controller.getSheet()?.id, 's3');
    expect(controller.getSelection(), isEmpty);
    expect(calls.last, {'hook': 'afterDelete', 'id': 's2'});

    controller.deleteSheet(id: 's3');
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s3']);
    expect(calls.where((call) => call['id'] == 's3'), hasLength(1));

    controller.handleUndo();
    await tester.pump();

    expect(ops.last, [
      {
        'op': 'addSheet',
        'id': 's2',
        'path': [],
        'value': {
          'id': 's2',
          'name': 'Sheet2',
          'order': 0,
          'luckysheet_select_save': [
            {
              'row': [3, 4],
              'column': [1, 2],
            },
          ],
          'status': 1,
        },
      },
      {
        'op': 'replace',
        'id': 's2',
        'path': ['name'],
        'value': 'Sheet2',
      },
      {
        'op': 'replace',
        'id': 's3',
        'path': ['order'],
        'value': 1,
      },
    ]);
    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s2', 's3']);
    expect(controller.getSheet()?.id, 's2');

    controller.handleRedo();
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), ['s3']);
    expect(controller.getSheet()?.id, 's3');
  });

  testWidgets('controller copies hides and shows sheets', (tester) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1', order: 0).setSelection(const [
          FortuneRange(rowStart: 1, rowEnd: 1, columnStart: 1, columnEnd: 1),
        ]),
        FortuneSheet(id: 's2', name: 'Sheet2', order: 1).setSelection(const [
          FortuneRange(rowStart: 3, rowEnd: 3, columnStart: 2, columnEnd: 2),
        ]),
        FortuneSheet(id: 's3', name: 'Hidden', order: 2, hide: 1),
      ],
      activeSheetIndex: 1,
    );

    controller.copySheet(id: 's1', newSheetId: 'detached-copy');
    controller.hideSheet(id: 's2');
    controller.showSheet(id: 's3');

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);
    expect(() => controller.copySheet(id: 'missing'), throwsA(SHEET_NOT_FOUND));
    expect(() => controller.hideSheet(id: 'missing'), throwsA(SHEET_NOT_FOUND));
    expect(() => controller.showSheet(id: 'missing'), throwsA(SHEET_NOT_FOUND));

    controller.copySheet(id: 's1', newSheetId: 's1-copy');
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's1-copy',
      's2',
      's3',
    ]);
    expect(controller.getAllSheets()!.map((sheet) => sheet.order), [
      0,
      1,
      2,
      3,
    ]);
    expect(controller.getSheet(id: 's1-copy')?.name, 'Sheet1(copy)');
    expect(controller.getSheet()?.id, 's2');

    controller.hideSheet(id: 's2');
    await tester.pump();

    expect(controller.getSheet(id: 's2')?.hide, 1);
    expect(controller.getSheet()?.id, 's1');
    expect(controller.getSelection()!.single.rowStart, 1);

    controller.showSheet(id: 's3');
    await tester.pump();

    expect(controller.getSheet(id: 's3')?.hide, isNull);
    expect(controller.getSheet()?.id, 's1');

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet(id: 's3')?.hide, 1);
    expect(controller.getSheet()?.id, 's1');

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet(id: 's2')?.hide, isNull);
    expect(controller.getSheet()?.id, 's2');

    controller.handleUndo();
    await tester.pump();

    expect(controller.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);

    final disabledController = FortuneSheetController();
    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook.copyWith(
              settings: const FortuneSettings(allowEdit: false),
            ),
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.copySheet(id: 's1', newSheetId: 'blocked-copy');
    disabledController.hideSheet(id: 's2');
    disabledController.showSheet(id: 's3');
    await tester.pump();

    expect(disabledController.getAllSheets()!.map((sheet) => sheet.id), [
      's1',
      's2',
      's3',
    ]);
    expect(disabledController.getSheet(id: 's2')?.hide, isNull);
    expect(disabledController.getSheet(id: 's3')?.hide, 1);
  });

