  testWidgets('controller paste respects beforePaste rejection', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final pasteHookCalls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1').setSelection(const [
          FortuneRange(rowStart: 2, rowEnd: 3, columnStart: 1, columnEnd: 4),
        ]),
      ],
      settings: FortuneSettings(
        beforePaste: (selection, content) {
          pasteHookCalls.add({
            'rowStart': selection?.single.rowStart,
            'rowEnd': selection?.single.rowEnd,
            'columnStart': selection?.single.columnStart,
            'columnEnd': selection?.single.columnEnd,
            'content': content,
          });
          return false;
        },
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.paste('blocked'), {
      'type': 'pasteBlockedBeforeHook',
      'text': 'blocked',
    });
    expect(pasteHookCalls, [
      {
        'rowStart': 2,
        'rowEnd': 3,
        'columnStart': 1,
        'columnEnd': 4,
        'content': 'blocked',
      },
    ]);
  });

