  testWidgets('controller batchCallApis dispatches ref API calls', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );
    final changes = <FortuneWorkbook>[];

    controller.batchCallApis(const [
      {
        'name': 'setCellValue',
        'args': [0, 0, 'detached'],
      },
    ]);

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            onChange: changes.add,
          ),
        ),
      ),
    );
    await tester.pump();
    changes.clear();

    controller.batchCallApis(const [
      {
        'name': 'setCellValue',
        'args': [0, 0, 'batched'],
      },
      {
        'name': 'setCellFormat',
        'args': [0, 0, 'bg', '#ffeeaa'],
      },
      {'name': 'missingApi', 'args': []},
    ]);
    await tester.pump();

    final cell = controller.getSheet()!.cells[const FortuneCellCoord(0, 0)]!;
    expect(cell.value, 'batched');
    expect(cell.background, const Color(0xffffeeaa));
    expect(changes, hasLength(1));

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet()!.cells[const FortuneCellCoord(0, 0)], isNull);

    controller.handleRedo();
    await tester.pump();

    final redoneCell = controller
        .getSheet()!
        .cells[const FortuneCellCoord(0, 0)]!;
    expect(redoneCell.value, 'batched');
    expect(redoneCell.background, const Color(0xffffeeaa));
  });

