  testWidgets('controller sets active sheet row heights and column widths', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    controller.setRowHeight({2: 44});
    controller.setColumnWidth({1: 88});

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getSheet()?.rowHeights, isEmpty);
    expect(controller.getSheet()?.columnWidths, isEmpty);

    controller.setRowHeight({2: 44, -1: 20, 3: -5}, custom: true);
    controller.setColumnWidth({1: 88, -1: 20, 3: double.nan}, custom: true);
    await tester.pump();

    expect(controller.getRowHeight([2, 5]), {2: 44, 5: 19});
    expect(controller.getColumnWidth([1, 5]), {1: 88, 5: 73});
    expect(controller.getSheet()?.customHeight, {2: 1});
    expect(controller.getSheet()?.customWidth, {1: 1});

    controller.setRowHeight({-1: 20, 3: -5});
    controller.setColumnWidth({-1: 20, 3: double.infinity});
    await tester.pump();

    expect(controller.getSheet()?.rowHeights, {2: 44});
    expect(controller.getSheet()?.columnWidths, {1: 88});

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet()?.columnWidths, isEmpty);
    expect(controller.getSheet()?.rowHeights, {2: 44});

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet()?.rowHeights, isEmpty);
    expect(controller.getSheet()?.columnWidths, isEmpty);

    controller.handleRedo();
    await tester.pump();
    controller.handleRedo();
    await tester.pump();

    expect(controller.getSheet()?.rowHeights, {2: 44});
    expect(controller.getSheet()?.columnWidths, {1: 88});

    final disabledController = FortuneSheetController();
    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook.copyWith(
              settings: const FortuneSettings(allowEdit: false),
            ),
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.setRowHeight({2: 44});
    disabledController.setColumnWidth({1: 88});
    await tester.pump();

    expect(disabledController.getSheet()?.rowHeights, isEmpty);
    expect(disabledController.getSheet()?.columnWidths, isEmpty);
  });

  testWidgets('controller hides and shows active sheet rows and columns', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          hiddenRows: const {4},
          hiddenRowValues: const {4: 'custom'},
          hiddenColumns: const {5},
          hiddenColumnValues: const {5: 'custom'},
        ),
      ],
    );

    controller.hideRowOrColumn([2], 'row');
    controller.showRowOrColumn([4], 'row');

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getSheet()?.hiddenRows, {4});
    expect(controller.getSheet()?.hiddenColumns, {5});

    controller.hideRowOrColumn([-1, 2, 4], 'row');
    controller.hideRowOrColumn([1, 5], 'column');
    await tester.pump();

    expect(controller.getSheet()?.hiddenRows, {2, 4});
    expect(controller.getSheet()?.hiddenRowValues, {4: 0, 2: 0});
    expect(controller.getSheet()?.hiddenColumns, {1, 5});
    expect(controller.getSheet()?.hiddenColumnValues, {5: 0, 1: 0});
    expect(
      () => controller.hideRowOrColumn([1], 'diagonal'),
      throwsA(INVALID_PARAMS),
    );

    controller.showRowOrColumn([2], 'row');
    controller.showRowOrColumn([1], 'column');
    await tester.pump();

    expect(controller.getSheet()?.hiddenRows, {4});
    expect(controller.getSheet()?.hiddenRowValues, {4: 0});
    expect(controller.getSheet()?.hiddenColumns, {5});
    expect(controller.getSheet()?.hiddenColumnValues, {5: 0});
    expect(
      () => controller.showRowOrColumn([1], 'diagonal'),
      throwsA(INVALID_PARAMS),
    );

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet()?.hiddenColumns, {1, 5});
    expect(controller.getSheet()?.hiddenRows, {4});

    controller.handleUndo();
    await tester.pump();

    expect(controller.getSheet()?.hiddenRows, {2, 4});
    expect(controller.getSheet()?.hiddenColumns, {1, 5});

    controller.handleRedo();
    await tester.pump();
    controller.handleRedo();
    await tester.pump();

    expect(controller.getSheet()?.hiddenRows, {4});
    expect(controller.getSheet()?.hiddenColumns, {5});

    final disabledController = FortuneSheetController();
    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook.copyWith(
              settings: const FortuneSettings(allowEdit: false),
            ),
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.hideRowOrColumn([2], 'row');
    disabledController.hideRowOrColumn([1], 'column');
    await tester.pump();

    expect(disabledController.getSheet()?.hiddenRows, {4});
    expect(disabledController.getSheet()?.hiddenColumns, {5});
  });

  testWidgets('controller merges active sheet cells', (tester) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );
    const range = FortuneRange(
      rowStart: 0,
      rowEnd: 1,
      columnStart: 1,
      columnEnd: 2,
    );

    controller.mergeCells(const [range], 'merge-all');

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getSheet()?.cells, isEmpty);

    controller.mergeCells(const [range], 'merge-all');
    await tester.pump();

    final merge = controller
        .getSheet()
        ?.cells[const FortuneCellCoord(0, 1)]
        ?.merge;
    expect(merge?.rowSpan, 2);
    expect(merge?.columnSpan, 2);
    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(1, 2)]?.merge?.row,
      0,
    );

    controller.mergeCells(const [range], 'merge-all');
    await tester.pump();

    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 1)]?.merge,
      isNull,
    );

    controller.mergeCells(const [
      FortuneRange(rowStart: 0, rowEnd: 0, columnStart: 0, columnEnd: 2),
    ], 'merge-horizontal');
    await tester.pump();

    expect(
      controller
          .getSheet()
          ?.cells[const FortuneCellCoord(0, 0)]
          ?.merge
          ?.columnSpan,
      3,
    );

    controller.mergeCells(const [range], 'unsupported');
    controller.mergeCells(const [], 'merge-all');
    await tester.pump();

    expect(
      controller
          .getSheet()
          ?.cells[const FortuneCellCoord(0, 0)]
          ?.merge
          ?.columnSpan,
      3,
    );

    controller.cancelMerge(const [
      FortuneRange(rowStart: 0, rowEnd: 0, columnStart: 0, columnEnd: 2),
    ]);
    await tester.pump();

    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 0)]?.merge,
      isNull,
    );
    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 1)]?.merge,
      isNull,
    );

    controller.handleUndo();
    await tester.pump();

    expect(
      controller
          .getSheet()
          ?.cells[const FortuneCellCoord(0, 0)]
          ?.merge
          ?.columnSpan,
      3,
    );

    controller.handleRedo();
    await tester.pump();

    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 0)]?.merge,
      isNull,
    );

    controller.cancelMerge(const []);
    await tester.pump();

    expect(controller.getSheet()?.cells, isEmpty);

    controller.handleUndo();
    await tester.pump();

    expect(
      controller
          .getSheet()
          ?.cells[const FortuneCellCoord(0, 0)]
          ?.merge
          ?.columnSpan,
      3,
    );

    controller.handleRedo();
    await tester.pump();

    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 0)]?.merge,
      isNull,
    );

    final disabledController = FortuneSheetController();
    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook.copyWith(
              settings: const FortuneSettings(allowEdit: false),
            ),
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.mergeCells(const [range], 'merge-all');
    disabledController.cancelMerge(const [range]);
    await tester.pump();

    expect(disabledController.getSheet()?.cells, isEmpty);
  });

