  testWidgets(
    'controller undo and redo restore row insert and delete snapshots',
    (tester) async {
      final controller = FortuneSheetController();
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            rowCount: 2,
            columnCount: 1,
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: 'origin'),
              const FortuneCellCoord(1, 0): const FortuneCell(value: 'bottom'),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 360,
            height: 240,
            child: FortuneSheetCanvas(
              workbook: workbook,
              controller: controller,
            ),
          ),
        ),
      );
      await tester.pump();

      controller.insertRowOrColumn('row', 0, 1);
      await tester.pump();

      expect(controller.getSheet()?.rowCount, 3);
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(0, 0)]?.value,
        'origin',
      );
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(2, 0)]?.value,
        'bottom',
      );

      controller.handleUndo();
      await tester.pump();

      expect(controller.getSheet()?.rowCount, 2);
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(1, 0)]?.value,
        'bottom',
      );

      controller.handleRedo();
      await tester.pump();

      expect(controller.getSheet()?.rowCount, 3);
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(2, 0)]?.value,
        'bottom',
      );

      controller.deleteRowOrColumn('row', 1, 1);
      await tester.pump();

      expect(controller.getSheet()?.rowCount, 2);
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(1, 0)]?.value,
        'bottom',
      );

      controller.handleUndo();
      await tester.pump();

      expect(controller.getSheet()?.rowCount, 3);
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(2, 0)]?.value,
        'bottom',
      );

      controller.handleRedo();
      await tester.pump();

      expect(controller.getSheet()?.rowCount, 2);
      expect(
        controller.getSheet()?.cells[const FortuneCellCoord(1, 0)]?.value,
        'bottom',
      );
    },
  );

