  testWidgets('controller gets sets and clears active sheet cell values', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 2,
          columnCount: 2,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'fortune'),
          },
        ),
        FortuneSheet(
          id: 's2',
          name: 'Sheet2',
          rowCount: 2,
          columnCount: 2,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'target'),
            const FortuneCellCoord(0, 1): const FortuneCell(formula: '=A1'),
          },
        ),
      ],
    );

    expect(controller.getCellValue(0, 0), isNull);
    controller.setCellValue(0, 0, 'detached');
    controller.clearCell(0, 0);

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    expect(controller.getCellValue(0, 0), 'fortune');
    expect(controller.getCellValue(0, 0, id: 's2'), 'target');
    expect(controller.getCellValue(0, 1, type: 'f', index: 1), contains('A1'));
    expect(controller.getSheet()?.id, 's1');

    controller.setCellValue(1, 0, 'target-write', id: 's2');
    controller.setCellFormat(1, 0, 'bg', '#ddeeff', index: 1);
    controller.clearCell(0, 0, id: 's2');
    await tester.pump();

    expect(controller.getSheet()?.id, 's1');
    expect(controller.getCellValue(0, 0), 'fortune');
    expect(controller.getCellValue(0, 0, id: 's2'), isNull);
    expect(controller.getCellValue(1, 0, id: 's2'), 'target-write');
    expect(
      controller
          .getSheet(id: 's2')
          ?.cells[const FortuneCellCoord(1, 0)]
          ?.rawBackground,
      '#ddeeff',
    );

    controller.handleUndo();
    await tester.pump();

    expect(controller.getCellValue(0, 0, id: 's2'), 'target');
    expect(controller.getCellValue(1, 0, id: 's2'), 'target-write');
    expect(
      controller
          .getSheet(id: 's2')
          ?.cells[const FortuneCellCoord(1, 0)]
          ?.rawBackground,
      '#ddeeff',
    );

    controller.handleUndo();
    await tester.pump();

    expect(controller.getCellValue(0, 0, id: 's2'), 'target');
    expect(controller.getCellValue(1, 0, id: 's2'), 'target-write');
    expect(
      controller
          .getSheet(id: 's2')
          ?.cells[const FortuneCellCoord(1, 0)]
          ?.rawBackground,
      isNull,
    );

    controller.handleUndo();
    await tester.pump();

    expect(controller.getCellValue(0, 0, id: 's2'), 'target');
    expect(controller.getCellValue(1, 0, id: 's2'), isNull);

    controller.setCellValue(0, 0, 'changed');
    await tester.pump();

    expect(controller.getCellValue(0, 0), 'changed');
    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 0)]?.value,
      'changed',
    );

    controller.setCellValue(0, 1, '=A1');
    await tester.pump();

    expect(controller.getCellValue(0, 1, type: 'f'), contains('A1'));
    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 1)]?.formula,
      '=A1',
    );

    controller.setCellValue(0, 1, '=A1');
    controller.setCellValue(-1, 0, 'ignored');
    await tester.pump();

    expect(controller.getSheet()?.cells.length, 2);

    controller.clearCell(0, 1);
    await tester.pump();

    expect(controller.getCellValue(0, 1), isNull);
    expect(
      controller.getSheet()?.cells[const FortuneCellCoord(0, 1)]?.value,
      '',
    );

    controller.handleUndo();
    await tester.pump();

    expect(controller.getCellValue(0, 1, type: 'f'), contains('A1'));

    controller.handleRedo();
    await tester.pump();

    expect(controller.getCellValue(0, 1), isNull);

    final disabledController = FortuneSheetController();
    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook.copyWith(
              settings: const FortuneSettings(allowEdit: false),
            ),
            controller: disabledController,
          ),
        ),
      ),
    );
    await tester.pump();

    disabledController.setCellValue(0, 0, 'blocked');
    disabledController.clearCell(0, 0);
    await tester.pump();

    expect(disabledController.getCellValue(0, 0), 'fortune');
  });

