  testWidgets('controller calculates formulas by sheet and range', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 'initial', name: 'Initial')],
    );

    controller.calculateFormula();

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(workbook: workbook, controller: controller),
        ),
      ),
    );
    await tester.pump();

    controller.updateSheet([
      FortuneSheet(
        id: 's1',
        name: 'Sheet1',
        cells: {
          const FortuneCellCoord(0, 0): const FortuneCell(value: '2'),
          const FortuneCellCoord(0, 1): const FortuneCell(
            formula: '=A1+1',
            displayValue: 'old-b',
            rawDisplayValue: 'old-b',
            hasRawDisplayValue: true,
          ),
          const FortuneCellCoord(0, 2): const FortuneCell(
            formula: '=A1+2',
            displayValue: 'old-c',
            rawDisplayValue: 'old-c',
            hasRawDisplayValue: true,
          ),
        },
      ),
      FortuneSheet(
        id: 's2',
        name: 'Sheet2',
        cells: {
          const FortuneCellCoord(0, 0): const FortuneCell(value: '5'),
          const FortuneCellCoord(0, 1): const FortuneCell(
            formula: '=A1+1',
            displayValue: 'old-s2',
            rawDisplayValue: 'old-s2',
            hasRawDisplayValue: true,
          ),
        },
      ),
    ]);
    await tester.pump();

    expect(
      controller
          .getSheet(id: 's1')
          ?.cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      'old-b',
    );
    expect(
      controller
          .getSheet(id: 's2')
          ?.cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      'old-s2',
    );

    controller.calculateFormula(
      id: 's1',
      range: const FortuneRange(
        rowStart: 0,
        rowEnd: 0,
        columnStart: 1,
        columnEnd: 1,
      ),
    );
    await tester.pump();

    expect(
      controller
          .getSheet(id: 's1')
          ?.cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      '3',
    );
    expect(
      controller
          .getSheet(id: 's1')
          ?.cells[const FortuneCellCoord(0, 2)]
          ?.renderedText,
      'old-c',
    );
    expect(
      controller
          .getSheet(id: 's2')
          ?.cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      'old-s2',
    );

    controller.calculateFormula();
    await tester.pump();

    expect(
      controller
          .getSheet(id: 's1')
          ?.cells[const FortuneCellCoord(0, 2)]
          ?.renderedText,
      '4',
    );
    expect(
      controller
          .getSheet(id: 's2')
          ?.cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      '6',
    );

    controller.handleUndo();
    await tester.pump();

    expect(controller.getAllSheets()?.single.id, 'initial');
  });

