    expect(controller.getCellValue(0, 0), 'fresh');

    controller.handleUndo();
    await tester.pump();

    expect(controller.getCellValue(0, 0), 'fresh');
  });

  testWidgets('controller refreshes affected formulas', (tester) async {
    final controller = FortuneSheetController();
    final changes = <FortuneWorkbook>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: '2'),
            const FortuneCellCoord(0, 1): const FortuneCell(
              formula: '=A1+1',
              displayValue: 'old-b',
              rawDisplayValue: 'old-b',
              hasRawDisplayValue: true,
            ),
          },
          calcChain: const [
            {'r': 0, 'c': 1, 'id': 's1'},
          ],
          hasRawCalcChain: true,
        ),
      ],
    );

    controller.refreshAffectedFormulas(
      row: 0,
      column: 0,
      id: 's1',
      value: 'detached',
    );
    expect(
      controller.setFormulaCellInfo(<String, Map<String, Object?>>{}, const {
        'r': 0,
        'c': 1,
        'id': 's1',
      }),
      isNull,
    );
    expect(
      controller.setFormulaCellInfoMap(<String, Map<String, Object?>>{}, const [
        {'r': 0, 'c': 1, 'id': 's1'},
      ]),
      isNull,
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            onChange: changes.add,
          ),
        ),
      ),
    );
    await tester.pump();
    changes.clear();

    controller.refreshAffectedFormulas(row: 0, column: 0, id: 's1', value: '5');
    await tester.pump();

    expect(controller.getCellValue(0, 0), 5);
    expect(
      controller
          .getSheet(id: 's1')
          ?.cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      '6',
    );
    expect(changes, hasLength(1));

    final executed = controller.executeAffectedFormulas(
      const [
        {'r': 0, 'c': 2, 'id': 's1', 'calc_funcStr': '=A1+2'},
      ],
      const [
        {'r': 0, 'c': 2, 'id': 's1'},
      ],
    )!;
    expect(executed['calcChainSet'], {'0_2_s1'});
    expect(executed['groupValuesRefreshData'], [
      {
        'r': 0,
        'c': 2,
        'v': '7',
        'm': '7',
        'f': '=A1+2',
        'spe': null,
        'id': 's1',
      },
    ]);
    expect(changes, hasLength(1));

    final formulaInfoMap = <String, Map<String, Object?>>{};
    expect(
      identical(
        controller.setFormulaCellInfo(formulaInfoMap, const {
          'r': 0,
          'c': 1,
          'id': 's1',
        }),
        formulaInfoMap,
      ),
      isTrue,
    );
    expect(formulaInfoMap['r0c1is1'], {
      'formulaDependency': [
        {
          'row': [0, 0],
          'column': [0, 0],
          'sheetId': 's1',
        },
      ],
      'calc_funcStr': '=A1+1',
      'key': 'r0c1is1',
      'r': 0,
      'c': 1,
      'id': 's1',
      'parents': <String, Object?>{},
      'chidren': <String, Object?>{},
      'color': 'w',
    });

    final batchFormulaInfoMap = <String, Map<String, Object?>>{};
    expect(
      identical(
        controller.setFormulaCellInfoMap(batchFormulaInfoMap, const [
          {'r': 0, 'c': 1, 'id': 's1'},
        ]),
        batchFormulaInfoMap,
      ),
      isTrue,
    );
    expect(batchFormulaInfoMap.keys, ['r0c1is1']);
    expect(changes, hasLength(1));

    controller.refreshAffectedFormulas(
      row: 0,
      column: 0,
      id: 'missing',
      value: 'ignored',
    );
    await tester.pump();

    expect(changes, hasLength(1));

    controller.handleUndo();
    await tester.pump();

    expect(controller.getCellValue(0, 0), 5);
  });

