              rowStart: 0,
              rowEnd: 0,
              columnStart: 0,
              columnEnd: 1,
            ),
            const {'id': 's2'},
          )
          ?.single
          .map((cell) => cell?.value)
          .toList(),
      ['X', 'Y'],
    );
    expect(controller.getHtmlByRange(const [range]), contains('A'));
    expect(
      controller.getHtmlByRange(
        const [
          FortuneRange(rowStart: 0, rowEnd: 0, columnStart: 0, columnEnd: 1),
        ],
        const {'index': '1'},
      ),
      contains('X'),
    );
    expect(controller.getSheet()?.id, 's1');

    final explicitFlattened = controller.getFlattenRange(const [
      FortuneRange(rowStart: 0, rowEnd: 0, columnStart: 1, columnEnd: 1),
    ]);
    expect(explicitFlattened, const [FortuneCellCoord(0, 1)]);
    expect(controller.getCellsByFlattenRange()?.first?.value, 'A');

    controller.setSelection(const [
      FortuneRange(rowStart: 0, rowEnd: 0, columnStart: 0, columnEnd: 1),
      FortuneRange(rowStart: 2, rowEnd: 3, columnStart: 2, columnEnd: 3),
    ]);
    await tester.pump();

    final upstreamFlattened = controller.getFlattenRange();
    expect(controller.getSelectionCoordinates(), ['A1:B1', 'C3:D4']);
    expect(upstreamFlattened, const [
      FortuneCellCoord(0, 0),
      FortuneCellCoord(0, 1),
      FortuneCellCoord(2, 2),
      FortuneCellCoord(2, 3),
      FortuneCellCoord(3, 2),
      FortuneCellCoord(3, 3),
    ]);
    expect(
      controller
          .getCellsByFlattenRange(upstreamFlattened)
          ?.map((cell) => cell?.value)
          .toList(),
      ['A', 'B', 'C3', 'D3', 'C4', 'D4'],
    );
  });

  testWidgets('controller writes active sheet ranges', (tester) async {
