  testWidgets('controller updates workbook presences', (tester) async {
    final controller = FortuneSheetController();
    final changes = <FortuneWorkbook>[];
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    controller.addPresences(const [
      {'username': 'Detached'},
    ]);

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 240,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            onChange: changes.add,
          ),
        ),
      ),
    );
    await tester.pump();
    changes.clear();

    controller.removePresences(const [
      {'username': 'Missing'},
    ]);
    await tester.pump();
    expect(changes, isEmpty);

    controller.addPresences(const [
      {
        'sheetId': 's1',
        'username': 'Alice',
        'color': '#f00',
        'selection': {'r': 0, 'c': 0},
      },
      {
        'sheetId': 's1',
        'username': 'Bob',
        'userId': 'u2',
        'color': '#0f0',
        'selection': {'r': 1, 'c': 1},
      },
    ]);
    await tester.pump();

    var presences = changes.last.extraFields['presences'] as List;
    expect(presences, hasLength(2));
    expect((presences[0] as Map)['username'], 'Alice');
    expect((presences[1] as Map)['username'], 'Bob');

    controller.addPresences(const [
      {
        'sheetId': 's2',
        'username': 'Bobby',
        'userId': 'u2',
        'color': '#00f',
        'selection': {'r': 2, 'c': 2},
      },
    ]);
    await tester.pump();

    presences = changes.last.extraFields['presences'] as List;
    expect(presences, hasLength(2));
    expect((presences[1] as Map)['username'], 'Bobby');
    expect((presences[1] as Map)['sheetId'], 's2');

    controller.removePresences(const [
      {'username': 'Alice'},
    ]);
    await tester.pump();

    presences = changes.last.extraFields['presences'] as List;
    expect(presences, hasLength(1));
    expect((presences.single as Map)['userId'], 'u2');

    controller.handleUndo();
    await tester.pump();

    presences = changes.last.extraFields['presences'] as List;
    expect(presences, hasLength(1));
    expect((presences.single as Map)['username'], 'Bobby');
  });

