  testWidgets('workbook undo and redo restore scroll offset snapshot', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 80,
          columnCount: 20,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'styled'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    FortuneCell activeCell() {
      return painter().workbook.activeSheet.cells[const FortuneCellCoord(
        0,
        0,
      )]!;
    }

    Future<void> scrollDownTicks(int ticks) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      for (var tick = 0; tick < ticks; tick += 1) {
        await tester.sendEventToBinding(
          PointerScrollEvent(
            position: topLeft + const Offset(240, 180),
            scrollDelta: const Offset(0, 120),
          ),
        );
        await tester.pump();
      }
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await scrollDownTicks(5);
    final scrollA = painter().scrollOffset;
    expect(scrollA.dy, 120);

    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarBoldCommand));
    await tester.pump();
    expect(activeCell().bold, isTrue);

    await scrollDownTicks(5);
    final scrollB = painter().scrollOffset;
    expect(scrollB.dy, 220);

    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarUndoCommand));
    await tester.pump();
    expect(activeCell().bold, isFalse);
    expect(painter().scrollOffset, scrollA);

    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarRedoCommand));
    await tester.pump();
    expect(activeCell().bold, isTrue);
    expect(painter().scrollOffset, scrollB);
  });

  testWidgets('workbook undo and redo restore sheet tab scroll snapshot', (
