  testWidgets('format painter copies data verification metadata', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final sourceRule = <String, Object?>{
      'type': 'dropdown',
      'value1': 'red,green,blue',
      'checked': true,
    };
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'source'),
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'target'),
          },
          dataVerification: {'0_0': sourceRule},
          rawDataVerification: const {
            '0_0': {
              'type': 'dropdown',
              'value1': 'red,green,blue',
              'rawExtra': 'source-rule',
            },
            'legacy': 'kept',
          },
          hasRawDataVerification: true,
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarFormatPainterCommand),
    );
    await tester.pump();
    await tester.tapAt(topLeft + const Offset(130, 100));
    await tester.pump();

    final sheet = painter().workbook.activeSheet;
    expect(sheet.dataVerification['0_1'], sourceRule);
    expect(sheet.dataVerification['0_1'], isNot(same(sourceRule)));
    final rawDataVerification = sheet.rawDataVerification! as Map;
    expect(rawDataVerification.keys, containsAll(['0_0', '0_1', 'legacy']));
    expect((rawDataVerification['0_1'] as Map)['rawExtra'], 'source-rule');
    expect(rawDataVerification['legacy'], 'kept');
    expect(sheet.hasRawDataVerification, isTrue);

    (rawDataVerification['0_1'] as Map)['rawExtra'] = 'mutated';
    expect((rawDataVerification['0_0'] as Map)['rawExtra'], 'source-rule');
  });

