  testWidgets('toolbar currency popup formats use workbook currency', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    double formatPopupRowCenterY(String command) {
      var top =
          fortuneToolbarPopupTop + fortuneToolbarFormatPopupContentTopPadding;
      for (final option in fortuneToolbarFormatCommands) {
        if (option == '|') {
          top += fortuneToolbarFormatPopupDividerHeight;
          continue;
        }
        final center = top + fortuneToolbarFormatPopupRowHeight / 2;
        if (option == command) {
          return center;
        }
        top += fortuneToolbarFormatPopupRowHeight;
      }
      throw ArgumentError.value(command, 'command');
    }

    final workbook = FortuneWorkbook(
      settings: const FortuneSettings(currency: 'USD'),
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: '1000.12'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final popupLeft = toolbarPopupLeftForKey(
      fortuneToolbarFormatCommand,
      width: 1688,
    );

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarFormatCommand, width: 1688),
    );
    await tester.pump();
    await tester.tapAt(
      topLeft +
          Offset(
            popupLeft + 16,
            formatPopupRowCenterY(fortuneToolbarFormatAccountingCommand),
          ),
    );
    await tester.pump();

    var cell =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
    expect(cell.cellType?.type, 'n');
    expect(cell.cellType?.format, 'USD(0.00)');

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarFormatCommand, width: 1688),
    );
    await tester.pump();
    await tester.tapAt(
      topLeft +
          Offset(
            popupLeft + 16,
            formatPopupRowCenterY(fortuneToolbarFormatCurrencyCommand),
          ),
    );
    await tester.pump();

    cell = painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
    expect(cell.cellType?.type, 'n');
    expect(cell.cellType?.format, 'USD0.00');
  });

