  testWidgets('toolbar popup paints above active cell editor', (tester) async {
    tester.view.physicalSize = const Size(640, 360);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final repaintKey = GlobalKey();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowHeights: const {0: 140},
          columnWidths: const {6: 220},
          cells: {
            const FortuneCellCoord(0, 6): const FortuneCell(
              value: 'ABCDEFGHIJKLMN\nABCDEFGHIJKLMN\nABCDEFGHIJKLMN',
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 640,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(540, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();
    expect(find.byType(EditableText), findsOneWidget);

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarFontSizePopupKey, width: 640),
    );
    await tester.pump();

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final popupLeft = toolbarPopupLeftForKey(
      fortuneToolbarFontSizePopupKey,
      width: 640,
    );
    final editableRect = tester.getRect(find.byType(EditableText));
    final popupVisibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: 600,
      naturalHeight: fortuneToolbarPopupHeightFor(
        fortuneToolbarFontSizePopupKey,
        fortuneToolbarFontSizeCommands,
      ),
    );
    final popupRect = Rect.fromLTWH(
      topLeft.dx + popupLeft,
      topLeft.dy + fortuneToolbarPopupTop,
      fortuneToolbarPopupWidthFor(fortuneToolbarFontSizePopupKey),
      popupVisibleHeight,
    );
    final overlap = editableRect.intersect(popupRect);
    expect(
      overlap.isEmpty,
      isFalse,
      reason: 'editable=$editableRect popup=$popupRect',
    );
    final sampleGlobal = overlap.center;
    final sampleLocal = sampleGlobal - topLeft;
    final mouse = await tester.createGesture(kind: PointerDeviceKind.mouse);
    await mouse.addPointer(location: sampleGlobal);
    await mouse.moveTo(sampleGlobal);
    await tester.pump();

    expect(editableRect.contains(sampleGlobal), isTrue);

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final sampleX = sampleLocal.dx.round();
    final sampleY = sampleLocal.dy.round();
    final offset = (sampleY * image.width + sampleX) * 4;
    expect(pixels!.getUint8(offset), inInclusiveRange(232, 246));
    expect(pixels.getUint8(offset + 1), inInclusiveRange(232, 246));
    expect(pixels.getUint8(offset + 2), inInclusiveRange(232, 246));

    await mouse.removePointer();

    int? overlappingItemIndex;
    Offset? overlappingItemCenter;
    for (
      var index = 0;
      index < fortuneToolbarFontSizeCommands.length;
      index += 1
    ) {
      final itemCenter = toolbarPopupItemCenterForKey(
        popupLeft: popupLeft,
        toolbarKey: fortuneToolbarFontSizePopupKey,
        itemIndex: index,
      );
      final globalCenter = topLeft + itemCenter;
      if (editableRect.contains(globalCenter) &&
          popupRect.contains(globalCenter)) {
        overlappingItemIndex = index;
        overlappingItemCenter = globalCenter;
        break;
      }
    }
    expect(overlappingItemIndex, isNotNull);
    await tester.tapAt(overlappingItemCenter!);
    await tester.pump();

    expect(find.byType(EditableText), findsOneWidget);
    expect(painter().toolbarPopupKey, isNull);
  });

