              inlineRuns: [FortuneInlineTextRun(text: 'abcdefghijk')],
            ),
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'next'),
          },
          columnWidths: const {0: 180},
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    final editableRect = tester.getRect(find.byType(EditableText));
    final dragY = editableRect.center.dy;
    final gesture = await tester.startGesture(
      Offset(editableRect.left + 24, dragY),
      kind: PointerDeviceKind.mouse,
    );
    await gesture.moveTo(Offset(editableRect.left + 88, dragY));
    await gesture.up();
    await tester.pump();

    var editable = tester.widget<EditableText>(find.byType(EditableText));
    final selectedRange = TextRange(
      start: editable.controller.selection.start,
      end: editable.controller.selection.end,
    );
    expect(selectedRange.isValid, isTrue);
    expect(selectedRange.isCollapsed, isFalse);
    final selectedText = editable.controller.text.substring(
      selectedRange.start,
      selectedRange.end,
    );
    expect(selectedText, isNotEmpty);

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarFontSizePopupKey, width: 1688),
    );
    await tester.pump();
    editable.controller.selection = const TextSelection.collapsed(offset: 7);
    await tester.pump();
    await tester.tapAt(
      topLeft +
          toolbarPopupItemCenterForKey(
            popupLeft: toolbarPopupLeftForKey(
              fortuneToolbarFontSizePopupKey,
              width: 1688,
            ),
            toolbarKey: fortuneToolbarFontSizePopupKey,
            itemIndex: fortuneToolbarFontSizeCommands.indexOf(
              fortuneToolbarFontSize18Command,
            ),
          ),
    );
    await tester.pump();
    await tester.pump();

    editable = tester.widget<EditableText>(find.byType(EditableText));
    expect(editable.controller.selection.start, selectedRange.start);
    expect(editable.controller.selection.end, selectedRange.end);

    await tester.tapAt(
      topLeft + toolbarItemArrowCenter(fortuneToolbarFontPopupKey, width: 1688),
    );
    await tester.pump();
    await tester.tapAt(
      topLeft +
          toolbarPopupItemCenterForKey(
            popupLeft: toolbarPopupLeftForKey(
              fortuneToolbarFontPopupKey,
              width: 1688,
            ),
            toolbarKey: fortuneToolbarFontPopupKey,
            itemIndex: fortuneToolbarFontCommands.indexOf(
              fortuneToolbarFontArialCommand,
            ),
          ),
    );
    await tester.pump();
    await tester.pump();

    editable = tester.widget<EditableText>(find.byType(EditableText));
    expect(editable.controller.selection.start, selectedRange.start);
    expect(editable.controller.selection.end, selectedRange.end);

    await tester.tapAt(topLeft + const Offset(240, 100));
    await tester.pump();

    final runs = painter()
        .workbook
        .activeSheet
        .cells[const FortuneCellCoord(0, 0)]!
        .inlineRuns!;
    final formattedRun = runs.singleWhere((run) => run.text == selectedText);
    expect(formattedRun.fontSize, 18);
    expect(formattedRun.fontFamily, 'Arial');
  });

