  testWidgets('toolbar dropdown arrows keep active editor open', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    Future<void> pumpSheet() async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: 'abcd'),
              const FortuneCellCoord(0, 1): const FortuneCell(value: 'next'),
            },
            columnWidths: const {0: 180},
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );
    }

    FortuneSheetPainter painter() {
      return tester
          .widgetList<CustomPaint>(find.byType(CustomPaint))
          .map((paint) => paint.painter)
          .whereType<FortuneSheetPainter>()
          .single;
    }

    Future<void> openEditorWithSelection() async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + const Offset(83, 100));
      await tester.pump();
      await tester.sendKeyEvent(LogicalKeyboardKey.f2);
      await tester.pump();
      final editable = tester.widget<EditableText>(find.byType(EditableText));
      editable.controller.selection = const TextSelection(
        baseOffset: 1,
        extentOffset: 3,
      );
      await tester.pump();
    }

    Future<void> expectArrowKeepsEditing(String key) async {
      await pumpSheet();
      await openEditorWithSelection();
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + toolbarItemArrowCenter(key, width: 1688));
      await tester.pump();

      expect(find.byType(EditableText), findsOneWidget);
      final editable = tester.widget<EditableText>(find.byType(EditableText));
      expect(editable.controller.selection.start, 1);
      expect(editable.controller.selection.end, 3);
      expect(painter().toolbarPopupKey, key);
    }

    await expectArrowKeepsEditing(fortuneToolbarFontPopupKey);
    await expectArrowKeepsEditing(fortuneToolbarFontSizePopupKey);
    await expectArrowKeepsEditing(fortuneToolbarFontColorPopupKey);
    await expectArrowKeepsEditing(fortuneToolbarBackgroundPopupKey);
    await expectArrowKeepsEditing(fortuneToolbarBorderPopupKey);
    await expectArrowKeepsEditing(fortuneToolbarHorizontalAlignPopupKey);
  });

