    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'abcd'),
          },
          columnWidths: const {0: 180},
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    var editable = tester.widget<EditableText>(find.byType(EditableText));
    editable.controller.selection = const TextSelection(
      baseOffset: 1,
      extentOffset: 3,
    );
    await tester.pump();

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarBackgroundPopupKey, width: 1688),
    );
    await tester.pump();
    await tester.tapAt(
      topLeft +
          toolbarFontColorPaletteItemCenter(
            popupLeft: toolbarPopupLeftForKey(
              fortuneToolbarBackgroundPopupKey,
              width: 1688,
            ),
            hex: '#fff2cc',
          ),
    );
    await tester.pump();

    expect(find.byType(EditableText), findsOneWidget);
    editable = tester.widget<EditableText>(find.byType(EditableText));
    expect(editable.controller.selection.start, 1);
    expect(editable.controller.selection.end, 3);

    editable.controller.selection = const TextSelection(
      baseOffset: 2,
      extentOffset: 3,
    );
    await tester.pump();

    final editorSpan = editable.controller.buildTextSpan(
      context: tester.element(find.byType(EditableText)),
      style: const TextStyle(color: Color(0xff000000), fontSize: 14),
      withComposing: false,
    );
    final textSpans = editorSpan.children!.whereType<TextSpan>().toList();
    expect(textSpans.map((span) => span.text), ['a', 'b', 'c', 'd']);
    expect(textSpans[1].style?.backgroundColor, const Color(0xfffff2cc));
    final selectedBackground = textSpans[2].style!.backgroundColor!;
    expect(selectedBackground, isNot(const Color(0xfffff2cc)));
    expect(
      (selectedBackground.b * 255.0).round(),
      greaterThan((selectedBackground.r * 255.0).round()),
    );

    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    final cell =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
    expect(cell.background, isNull);
    expect(cell.inlineRuns!.map((run) => run.text), ['a', 'bc', 'd']);
    expect(cell.inlineRuns!.map((run) => run.extraFields['bg']), [
      null,
      '#fff2cc',
      null,
    ]);
    final cellJson = FortuneSheetCodec.cellToJson(cell);
    final runs = (cellJson['ct']! as Map)['s']! as List;
    expect(runs[1], containsPair('bg', '#fff2cc'));
    expect(cellJson.containsKey('bg'), isFalse);
  });

