  testWidgets('active editor line spacing follows selected font size', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowHeights: const {0: 260},
          columnWidths: const {0: 300},
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'AAAA\nBBBB\nCCCC',
              textWrap: '2',
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 420,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    final editable = tester.widget<EditableText>(find.byType(EditableText));
    editable.controller.value = const TextEditingValue(
      text: 'AAAA\nBBBB\nCCCC',
      selection: TextSelection(baseOffset: 5, extentOffset: 9),
    );
    await tester.pump();

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarFontSizePopupKey, width: 1688),
    );
    await tester.pump();
    final popupLeft = toolbarPopupLeftForKey(
      fortuneToolbarFontSizePopupKey,
      width: 1688,
    );
    await tester.sendEventToBinding(
      PointerScrollEvent(
        position: topLeft + Offset(popupLeft + 20, fortuneToolbarPopupTop + 40),
        scrollDelta: const Offset(0, 500),
      ),
    );
    await tester.pump();
    final painter =
        tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
    final scrollOffset = painter.toolbarPopupScrollOffset;
    await tester.tapAt(
      topLeft +
          toolbarPopupItemCenterForKey(
            popupLeft: popupLeft,
            toolbarKey: fortuneToolbarFontSizePopupKey,
            itemIndex: fortuneToolbarFontSizeCommands.indexOf(
              fortuneToolbarFontSize72Command,
            ),
          ) -
          Offset(0, scrollOffset),
    );
    await tester.pump();

    final editableState = tester.state<EditableTextState>(
      find.byType(EditableText),
    );
    double lineBoxHeight(TextSelection selection) {
      final boxes = editableState.renderEditable.getBoxesForSelection(
        selection,
      );
      var top = double.infinity;
      var bottom = -double.infinity;
      for (final box in boxes) {
        top = math.min(top, box.top);
        bottom = math.max(bottom, box.bottom);
      }
      return bottom - top;
    }

    final firstLineHeight = lineBoxHeight(
      const TextSelection(baseOffset: 0, extentOffset: 4),
    );
    final secondLineHeight = lineBoxHeight(
      const TextSelection(baseOffset: 5, extentOffset: 9),
    );
    final thirdLineHeight = lineBoxHeight(
      const TextSelection(baseOffset: 10, extentOffset: 14),
    );
    expect(firstLineHeight, lessThan(35));
    expect(secondLineHeight, greaterThan(60));
    expect(thirdLineHeight, lessThan(35));
  });

