  testWidgets('visible comment boxes expose upstream content semantics', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'A1',
              comment: FortuneCellComment(
                value: 'visible note',
                left: 180,
                top: 70,
                width: 144,
                height: 84,
                isShow: true,
              ),
            ),
            const FortuneCellCoord(1, 0): const FortuneCell(
              value: 'A2',
              comment: FortuneCellComment(value: 'hover note'),
            ),
          },
        ),
      ],
    );

    FortuneSheetPainter painterWith({FortuneCellCoord? editingCommentCoord}) {
      return FortuneSheetPainter(
        workbook: workbook,
        selection: const FortuneSelection(row: 0, column: 0),
        scrollOffset: Offset.zero,
        sheetTabScrollOffset: 0,
        textDirection: TextDirection.ltr,
        hoveredCommentCoord: const FortuneCellCoord(1, 0),
        editingCommentCoord: editingCommentCoord,
      );
    }

    final semantics = painterWith().semanticsBuilder(const Size(640, 360));
    final visibleNode = semantics.singleWhere(
      (node) => node.properties.label == 'visible note',
    );
    final hoverNode = semantics.singleWhere(
      (node) => node.properties.label == 'hover note',
    );

    expect(visibleNode.properties.textField, isTrue);
    expect(visibleNode.rect.left, workbook.settings.rowHeaderWidth + 180);
    expect(visibleNode.rect.top, workbook.settings.columnHeaderHeight + 70);
    expect(hoverNode.properties.textField, isTrue);

    final editingSemantics = painterWith(
      editingCommentCoord: const FortuneCellCoord(0, 0),
    ).semanticsBuilder(const Size(640, 360));
    expect(
      editingSemantics.where((node) => node.properties.label == 'visible note'),
      isEmpty,
    );
  });

