  testWidgets('blocked cell mouse down still commits active comment editor', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final calls = <String>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'B1'),
          },
        ),
      ],
      settings: FortuneSettings(
        beforeCellMouseDown: (cell, cellInfo) {
          calls.add('before:${cellInfo['row']}:${cellInfo['column']}');
          return false;
        },
        afterCellMouseDown: (cell, cellInfo) {
          calls.add('after');
        },
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
