  testWidgets('toolbar comment lifecycle hooks wrap edits', (tester) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1')},
        ),
      ],
      settings: FortuneSettings(
        beforeInsertComment: (row, column) {
          calls.add({'hook': 'beforeInsert', 'row': row, 'column': column});
          return true;
        },
        afterInsertComment: (row, column) {
          calls.add({'hook': 'afterInsert', 'row': row, 'column': column});
        },
        beforeUpdateComment: (row, column, value) {
          calls.add({
            'hook': 'beforeUpdate',
            'row': row,
            'column': column,
            'value': value,
          });
          return true;
        },
        afterUpdateComment: (row, column, oldValue, value) {
          calls.add({
            'hook': 'afterUpdate',
            'row': row,
            'column': column,
            'old': oldValue,
            'value': value,
          });
        },
        beforeDeleteComment: (row, column) {
          calls.add({'hook': 'beforeDelete', 'row': row, 'column': column});
          return true;
        },
        afterDeleteComment: (row, column) {
          calls.add({'hook': 'afterDelete', 'row': row, 'column': column});
        },
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarCommentCommand));
    await tester.pump();

    await tester.enterText(find.byType(EditableText), 'comment text');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarCommentCommand));
    await tester.pump();

    expect(calls, [
      {'hook': 'beforeInsert', 'row': 0, 'column': 0},
      {'hook': 'afterInsert', 'row': 0, 'column': 0},
      {'hook': 'beforeUpdate', 'row': 0, 'column': 0, 'value': 'comment text'},
      {
        'hook': 'afterUpdate',
        'row': 0,
        'column': 0,
        'old': '',
        'value': 'comment text',
      },
      {'hook': 'beforeDelete', 'row': 0, 'column': 0},
      {'hook': 'afterDelete', 'row': 0, 'column': 0},
    ]);
    final cell =
        painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)];
    expect(cell?.comment, isNull);
  });

  test('painter beforeRenderCellArea hook receives flowdata', () {
    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1')},
        ),
      ],
      settings: FortuneSettings(
        beforeRenderCellArea: (cells, canvas) {
          final firstRow = cells.isEmpty ? null : cells.first;
          final firstCell = firstRow == null || firstRow.isEmpty
              ? null
              : firstRow.first;
          calls.add({
            'rows': cells.length,
            'columns': firstRow?.length ?? 0,
            'value': firstCell?.value,
            'canvas': canvas,
          });
          return false;
        },
      ),
    );
    final recorder = ui.PictureRecorder();
    final canvas = ui.Canvas(recorder);
    final painter = FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    );

    painter.paint(canvas, const Size(320, 240));
    final picture = recorder.endRecording();
    picture.dispose();

    expect(calls, hasLength(1));
    expect(calls.single['rows'], 1);
    expect(calls.single['columns'], 1);
    expect(calls.single['value'], 'A1');
    expect(calls.single['canvas'], same(canvas));
  });

  test('painter header render hooks wrap visible headers', () {
    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1', rowCount: 1, columnCount: 1),
      ],
      settings: FortuneSettings(
        row: 1,
        column: 1,
        beforeRenderColumnHeaderCell:
            (columnChar, columnIndex, left, width, height, canvas) {
              calls.add({
                'hook': 'beforeColumn',
                'char': columnChar,
                'index': columnIndex,
                'left': left,
                'width': width,
                'height': height,
                'canvas': canvas,
              });
              return true;
            },
        afterRenderColumnHeaderCell:
            (columnChar, columnIndex, left, width, height, canvas) {
              calls.add({
                'hook': 'afterColumn',
                'char': columnChar,
                'index': columnIndex,
                'left': left,
                'width': width,
                'height': height,
                'canvas': canvas,
              });
            },
        beforeRenderRowHeaderCell:
            (rowNumber, rowIndex, top, width, height, canvas) {
              calls.add({
                'hook': 'beforeRow',
                'rowNumber': rowNumber,
                'index': rowIndex,
                'top': top,
                'width': width,
                'height': height,
                'canvas': canvas,
              });
              return false;
            },
        afterRenderRowHeaderCell:
            (rowNumber, rowIndex, top, width, height, canvas) {
              calls.add({
                'hook': 'afterRow',
                'rowNumber': rowNumber,
                'index': rowIndex,
                'top': top,
                'width': width,
                'height': height,
                'canvas': canvas,
              });
            },
      ),
    );
    final recorder = ui.PictureRecorder();
    final canvas = ui.Canvas(recorder);
    final painter = FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    );

    painter.paint(canvas, const Size(160, 120));
    final picture = recorder.endRecording();
    picture.dispose();

    expect(calls.map((call) => call['hook']), [
      'beforeColumn',
      'afterColumn',
      'beforeRow',
    ]);
    expect(calls[0]['char'], 'A');
    expect(calls[0]['index'], 0);
    expect(calls[0]['left'], 46);
    expect(calls[0]['width'], 74);
    expect(calls[0]['height'], 19);
    expect(calls[0]['canvas'], same(canvas));
    expect(calls[2]['rowNumber'], '1');
    expect(calls[2]['index'], 0);
    expect(calls[2]['top'], 20);
    expect(calls[2]['width'], 45);
    expect(calls[2]['height'], 20);
    expect(calls[2]['canvas'], same(canvas));
  });

  test('painter cell render hooks wrap visible cells', () {
    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 1,
          columnCount: 2,
          cells: {const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1')},
        ),
      ],
      settings: FortuneSettings(
        row: 1,
        column: 2,
        beforeRenderCell: (cell, cellInfo, canvas) {
          calls.add({
            'hook': 'before',
            'value': cell?.value,
            'info': Map<String, num>.of(cellInfo),
            'canvas': canvas,
          });
          return cellInfo['column'] != 1;
        },
        afterRenderCell: (cell, cellInfo, canvas) {
          calls.add({
            'hook': 'after',
            'value': cell?.value,
            'info': Map<String, num>.of(cellInfo),
            'canvas': canvas,
          });
        },
      ),
    );
    final recorder = ui.PictureRecorder();
    final canvas = ui.Canvas(recorder);
    final painter = FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    );

    painter.paint(canvas, const Size(240, 120));
    final picture = recorder.endRecording();
    picture.dispose();

    expect(calls.map((call) => call['hook']), ['before', 'before', 'after']);
    expect(calls[0]['value'], 'A1');
    expect(calls[0]['canvas'], same(canvas));
    expect(calls[0]['info'], containsPair('row', 0));
    expect(calls[0]['info'], containsPair('column', 0));
    expect(calls[0]['info'], containsPair('startX', 46));
    expect(calls[0]['info'], containsPair('startY', 20));
    expect(calls[0]['info'], containsPair('endX', 120));
    expect(calls[0]['info'], containsPair('endY', 40));
    expect(calls[1]['value'], isNull);
    expect(calls[1]['info'], containsPair('row', 0));
    expect(calls[1]['info'], containsPair('column', 1));
    expect(calls[1]['info'], containsPair('startX', 120));
    expect(calls[2]['value'], 'A1');
    expect(calls[2]['info'], calls[0]['info']);
    expect(calls[2]['canvas'], same(canvas));
  });

