  testWidgets('toolbar link cell range selector fills and commits address', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            const FortuneCellCoord(1, 1): const FortuneCell(value: 'B2'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarLinkCommand));
    await tester.pump();

    final initialPainter = painter();
    final settings = initialPainter.workbook.settings;
    final metrics = initialPainter.workbook.activeSheet.metrics(settings);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final initialCellRect = Rect.fromLTWH(
      settings.rowHeaderWidth + metrics.columnStart(0),
      sheetTop + settings.columnHeaderHeight + metrics.rowStart(0),
      metrics.columnEnd(0) - metrics.columnStart(0),
      metrics.rowEnd(0) - metrics.rowStart(0),
    );
    Rect cellRect(int row, int column) => Rect.fromLTWH(
      settings.rowHeaderWidth + metrics.columnStart(column),
      sheetTop + settings.columnHeaderHeight + metrics.rowStart(row),
      metrics.columnEnd(column) - metrics.columnStart(column),
      metrics.rowEnd(row) - metrics.rowStart(row),
    );
    final initialDialogRect = fortuneHyperlinkDialogRect(
      const Size(1688, 360),
      initialCellRect,
    );
    const pickedRange = FortuneRange(
      rowStart: 1,
      rowEnd: 1,
      columnStart: 6,
      columnEnd: 6,
    );
    final expectedAddress = getRangetxt(
      initialPainter.workbook,
      initialPainter.workbook.activeSheet.id,
      pickedRange,
      currentSheetId: initialPainter.workbook.activeSheet.id,
    );
    final typeSelectCenter =
        topLeft +
        fortuneHyperlinkDialogTypeSelectRect(initialDialogRect).center;
    await tester.tapAt(typeSelectCenter);
    await tester.pump();

    var semantics = painter().semanticsBuilder(const Size(1688, 360));
    expect(
      semantics.singleWhere(
        (node) =>
            node.properties.label == 'Select cell range' &&
            node.properties.textField == true,
      ),
      isNotNull,
    );

    await tester.tapAt(topLeft + cellRect(1, 6).center);
    await tester.pump();

    semantics = painter().semanticsBuilder(const Size(1688, 360));
    final addressNode = semantics.singleWhere(
      (node) =>
          node.properties.label == 'Select cell range' &&
          node.properties.textField == true,
    );
    expect(addressNode.properties.value, expectedAddress);

    final rangeSelectionDialogRect = fortuneHyperlinkRangeSelectionDialogRect(
      const Size(1688, 360),
      initialCellRect,
    );
    await tester.tapAt(
      topLeft +
          fortuneHyperlinkRangeSelectionOkButtonRect(
            rangeSelectionDialogRect,
          ).center,
    );
    await tester.pump();

    semantics = painter().semanticsBuilder(const Size(1688, 360));
    expect(
      semantics
          .singleWhere(
            (node) =>
                node.properties.label == 'Cell range' &&
                node.properties.textField == true,
          )
          .properties
          .value,
      expectedAddress,
    );

    await tester.tapAt(
      topLeft + fortuneHyperlinkDialogOkButtonRect(initialDialogRect).center,
    );
    await tester.pump();

    final sheet = painter().workbook.activeSheet;
    final cell = sheet.cells[const FortuneCellCoord(0, 0)];
    expect(cell?.hyperlink?.linkType, 'cellrange');
    expect(cell?.hyperlink?.linkAddress, expectedAddress);
    expect(sheet.hyperlinks['0_0'], {
      'linkType': 'cellrange',
      'linkAddress': expectedAddress,
    });
    expect(cell?.value, 'A1');
    expect(find.byType(EditableText), findsNothing);
  });

