            as FortuneSheetPainter;
      }

      Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarLinkCommand));
      await tester.pump();

      expect(
        find.byKey(const ValueKey('fortune-hyperlink-display-input')),
        findsOneWidget,
      );
