      final sheet = painter().workbook.activeSheet;
      final json = FortuneSheetCodec.sheetToJson(sheet);
      final hyperlinkMap = json['hyperlink']! as Map;
      final celldata = json['celldata']! as List;
      final cellJson = (celldata.single as Map)['v']! as Map;
      final cellHyperlink = cellJson['hl']! as Map;

      expect(
        sheet.cells[const FortuneCellCoord(0, 0)]?.hyperlink?.linkAddress,
        'https://new.example',
      );
      expect(hyperlinkMap['0_0'], {
        'linkType': 'webpage',
        'linkAddress': 'https://new.example',
      });
      expect(cellHyperlink['r'], 0);
      expect(cellHyperlink['c'], 0);
      expect(cellHyperlink['id'], 's1');
      expect(cellHyperlink.containsKey('rawOnly'), isFalse);
      expect(cellJson['rawOnly'], isTrue);
    },
  );

