      final cellJson = (celldata.single as Map)['v']! as Map;

      expect(
        sheet.cells[const FortuneCellCoord(0, 0)]?.hyperlink?.linkAddress,
        'https://example.test',
      );
      expect(sheet.hyperlinks['0_0'], {
        'linkType': 'webpage',
        'linkAddress': 'https://example.test',
        'rawOnly': true,
      });
      expect((json['hyperlink'] as Map)['0_0'], {
        'linkType': 'webpage',
        'linkAddress': 'https://example.test',
        'rawOnly': true,
      });
      expect(cellJson.containsKey('hl'), isTrue);
    },
  );

  testWidgets('toolbar filter toggles selected column filter metadata', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final sheetTop =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth +
                10,
            sheetTop + workbook.settings.columnHeaderHeight + 10,
          ),
    );
    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarFilterCommand));
    await tester.pump();

    var filter = painter().workbook.activeSheet.filter;
    expect(filter.keys, contains('column_1'));
    final filterConfig = filter['column_1']! as Map;
    expect(filterConfig['rangeType'], 'column');
    expect(filterConfig['column'], [1, 1]);
    expect(filterConfig['column_focus'], 1);
    expect(painter().toolbarPopupKey, isNull);

    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarFilterCommand));
    await tester.pump();

    filter = painter().workbook.activeSheet.filter;
    expect(filter.containsKey('column_1'), isFalse);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    filter = painter().workbook.activeSheet.filter;
    expect(filter.keys, contains('column_1'));
    expect((filter['column_1']! as Map)['column_focus'], 1);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    filter = painter().workbook.activeSheet.filter;
    expect(filter.containsKey('column_1'), isFalse);
  });

