    final sheetTop =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    final rowCenter = sheetTop + workbook.settings.columnHeaderHeight + 10;
    final col0Center = workbook.settings.rowHeaderWidth + 36.5;
    final col2Center =
        workbook.settings.rowHeaderWidth +
        workbook.settings.defaultColWidth * 2 +
        36.5;
    await tester.dragFrom(
      topLeft + Offset(col0Center, rowCenter),
      Offset(col2Center - col0Center, 0),
    );
    await tester.pump();

    await tester.tapAt(
      topLeft +
          toolbarItemArrowCenter(fortuneToolbarFilterCommand, width: 1688),
    );
    await tester.pump();

