    expect(sheet.selectionSave, [
      {
        'row': [0, 2],
        'column': [0, 2],
        'row_focus': 0,
        'column_focus': 0,
      },
    ]);

    final sheetTopAfterCreate =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth * 2 -
                8,
            sheetTopAfterCreate + 10,
          ),
    );
    await tester.pump();
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth +
                14,
            sheetTopAfterCreate +
                workbook.settings.columnHeaderHeight +
                1 +
                fortuneFilterDropdownRowHeight * 3.5,
          ),
    );
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.filter.keys, ['1']);
    expect((sheet.filter['1'] as Map)['row'], [0, 2]);
    expect((sheet.filter['1'] as Map)['column_focus'], 1);
    expect((sheet.filter['1'] as Map)['filterValue'], 'Open');
    expect((sheet.filter['1'] as Map)['rowhidden'], {'2': 0});
    expect((sheet.filter['1'] as Map)['optionstate'], isTrue);
    expect((sheet.filter['1'] as Map)['caljs'], isNull);
    expect((sheet.filter['1'] as Map)['str'], 0);
    expect((sheet.filter['1'] as Map)['edr'], 2);
    expect((sheet.filter['1'] as Map)['cindex'], 1);
    expect((sheet.filter['1'] as Map)['stc'], 0);
    expect((sheet.filter['1'] as Map)['edc'], 2);
    expect(sheet.hiddenRows, {2});
  });

