  testWidgets('filter dropdown normalizes date values', (tester) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final firstSerial = DateTime(
      2026,
      5,
      15,
    ).difference(DateTime(1899, 12, 30)).inDays;
    final secondSerial = DateTime(
      2026,
      5,
      16,
    ).difference(DateTime(1899, 12, 30)).inDays;
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 3,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'Date'),
            FortuneCellCoord(1, 0): FortuneCell(
              value: '$firstSerial',
              rawValue: firstSerial,
              hasRawValue: true,
              cellType: const FortuneCellType(type: 'd'),
            ),
            FortuneCellCoord(2, 0): FortuneCell(
              value: '$secondSerial',
