    var pureWhitePixelsInOldWideArea = 0;
    final yStart = (sheetTop + workbook.settings.columnHeaderHeight + 5)
        .round();
    for (var y = yStart; y < yStart + 16; y += 1) {
      for (var x = 0; x < 2; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 252 && green > 252 && blue > 252) {
          pureWhitePixelsInOldWideArea += 1;
        }
      }
    }
    expect(pureWhitePixelsInOldWideArea, lessThan(10));
  });

