      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final topBorderX = workbook.settings.rowHeaderWidth.round() + 20;
    final topBorderY =
        (sheetTop + workbook.settings.columnHeaderHeight).round() - 1;
    final topBorderOffset = (topBorderY * image.width + topBorderX) * 4;
    expect(pixels!.getUint8(topBorderOffset), greaterThan(180));
    expect(pixels.getUint8(topBorderOffset + 1), lessThan(20));
    expect(pixels.getUint8(topBorderOffset + 2), lessThan(20));

    final thickTopBorderOffset =
        ((topBorderY + 1) * image.width + topBorderX) * 4;
    expect(pixels.getUint8(thickTopBorderOffset), greaterThan(180));
    expect(pixels.getUint8(thickTopBorderOffset + 1), lessThan(20));
    expect(pixels.getUint8(thickTopBorderOffset + 2), lessThan(20));

    final leftBorderX = workbook.settings.rowHeaderWidth.round() - 1;
    final leftBorderY =
        (sheetTop + workbook.settings.columnHeaderHeight).round() + 8;
    final leftBorderOffset = (leftBorderY * image.width + leftBorderX) * 4;
    expect(pixels.getUint8(leftBorderOffset), greaterThan(180));
    expect(pixels.getUint8(leftBorderOffset + 1), lessThan(20));
    expect(pixels.getUint8(leftBorderOffset + 2), lessThan(20));

    final thickLeftBorderOffset =
        (leftBorderY * image.width + leftBorderX + 1) * 4;
    expect(pixels.getUint8(thickLeftBorderOffset), greaterThan(180));
    expect(pixels.getUint8(thickLeftBorderOffset + 1), lessThan(20));
    expect(pixels.getUint8(thickLeftBorderOffset + 2), lessThan(20));

    final cellInteriorOffset =
        ((topBorderY + 4) * image.width + leftBorderX + 4) * 4;
    expect(pixels.getUint8(cellInteriorOffset), greaterThan(245));
    expect(pixels.getUint8(cellInteriorOffset + 1), greaterThan(245));
    expect(pixels.getUint8(cellInteriorOffset + 2), greaterThan(245));
  });

  testWidgets('adjusted sheet merged cells hide inner viewport grid lines', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(420, 320);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    const merge = FortuneCellMerge(
      row: 0,
      column: 0,
      rowSpan: 2,
      columnSpan: 2,
    );
    final repaintKey = GlobalKey();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 4,
          columnCount: 3,
          rowHeights: const {0: 24, 1: 24, 2: 24, 3: 24},
          columnWidths: const {0: 40, 1: 40, 2: 40},
          extraFields: const {
            fortuneSheetGridClientWidthMmKey: 80,
            fortuneSheetGridClientHeightMmKey: 40,
          },
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(merge: merge),
            const FortuneCellCoord(0, 1): const FortuneCell(merge: merge),
            const FortuneCellCoord(1, 0): const FortuneCell(merge: merge),
            const FortuneCellCoord(1, 1): const FortuneCell(merge: merge),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 420,
            height: 320,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester
              .widgetList<CustomPaint>(find.byType(CustomPaint))
              .singleWhere((paint) => paint.painter is FortuneSheetPainter)
              .painter!
          as FortuneSheetPainter;
    }

    final currentPainter = painter();
    final settings = currentPainter.workbook.settings;
    final metrics = currentPainter.workbook.activeSheet.metrics(settings);
    final sheetTop =
        settings.effectiveToolbarHeight + settings.effectiveFormulaBarHeight;
    final dataLeft = settings.rowHeaderWidth;
    final dataTop = sheetTop + settings.columnHeaderHeight;
    final internalGridX = (dataLeft + metrics.columnEnd(0) - 1).round();
    final internalGridY = (dataTop + metrics.rowStart(0) + 12).round();
    final outsideGridY = (dataTop + metrics.rowStart(2) + 12).round();

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final internalOffset = (internalGridY * image.width + internalGridX) * 4;
    expect(pixels!.getUint8(internalOffset), greaterThan(245));
    expect(pixels.getUint8(internalOffset + 1), greaterThan(245));
    expect(pixels.getUint8(internalOffset + 2), greaterThan(245));

    final outsideOffset = (outsideGridY * image.width + internalGridX) * 4;
    expect(pixels.getUint8(outsideOffset), lessThan(245));
    expect(pixels.getUint8(outsideOffset + 1), lessThan(245));
    expect(pixels.getUint8(outsideOffset + 2), lessThan(245));
  });

  testWidgets('filter dropdown marks active value with check indicator', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(420, 360);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final repaintKey = GlobalKey();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 3,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'Status'),
            const FortuneCellCoord(1, 0): const FortuneCell(value: 'Open'),
            const FortuneCellCoord(2, 0): const FortuneCell(value: 'Closed'),
          },
          filter: {
            'column_0': {
              'rangeType': 'column',
              'row': [0, 2],
              'column': [0, 0],
              'column_focus': 0,
              'filterValue': 'Open',
              'rowhidden': {'2': 0},
            },
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 420,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final sheetTop =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth -
                8,
            sheetTop + 10,
          ),
    );
    await tester.pump();

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final activeRowTop =
        sheetTop +
        workbook.settings.columnHeaderHeight +
        1 +
        fortuneFilterDropdownRowHeight * 3;
    final inactiveRowTop =
        sheetTop +
        workbook.settings.columnHeaderHeight +
        1 +
        fortuneFilterDropdownRowHeight * 4;
    var grayCheckboxPixels = 0;
    var inactiveBluePixels = 0;
    for (var y = inactiveRowTop.round() + 4; y < inactiveRowTop + 20; y += 1) {
      for (var x = 0; x < 44; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final maxChannel = math.max(red, math.max(green, blue));
        final minChannel = math.min(red, math.min(green, blue));
        if (maxChannel > 60 &&
            maxChannel < 170 &&
            maxChannel - minChannel < 50) {
          grayCheckboxPixels += 1;
        }
        if (blue > 180 && green > 90 && red < 80) {
          inactiveBluePixels += 1;
        }
      }
    }
    expect(grayCheckboxPixels, greaterThan(2));
    expect(inactiveBluePixels, 0);

    var blueCheckPixels = 0;
    for (var y = activeRowTop.round() + 4; y < activeRowTop + 20; y += 1) {
      for (var x = 0; x < 44; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (blue > 180 && green > 90 && red < 80) {
          blueCheckPixels += 1;
        }
      }
    }
    expect(blueCheckPixels, greaterThan(4));
  });

