    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 420,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final sheetTop =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth -
                8,
            sheetTop + 10,
          ),
    );
    await tester.pump();

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    int blueCheckPixelsForChoiceRow(int rowIndex) {
      final rowTop =
          sheetTop +
          workbook.settings.columnHeaderHeight +
          1 +
          fortuneFilterDropdownRowHeight * rowIndex;
      var count = 0;
      for (var y = rowTop.round() + 4; y < rowTop + 20; y += 1) {
        for (var x = 0; x < 44; x += 1) {
          final offset = (y * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          if (blue > 180 && green > 90 && red < 80) {
            count += 1;
          }
        }
      }
      return count;
    }

    expect(blueCheckPixelsForChoiceRow(3), greaterThan(4));
    expect(blueCheckPixelsForChoiceRow(4), greaterThan(4));
  });

