    final sheet = painter().workbook.activeSheet;
    final filter = sheet.filter['0'] as Map;
    expect(filter['filterValue'], 'Item 10');
    expect(filter['rowhidden'], {
      for (var row = 1; row <= 9; row += 1) '$row': 0,
    });
    expect(sheet.hiddenRows, {for (var row = 1; row <= 9; row += 1) row});
    expect(painter().filterDropdownColumn, isNull);
  });

