      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 3,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'Status'),
            const FortuneCellCoord(1, 0): const FortuneCell(
              value: 'Open',
              background: Color(0xffff0000),
            ),
            const FortuneCellCoord(2, 0): const FortuneCell(
              value: 'Closed',
              background: Color(0xff0000ff),
            ),
          },
          filterSelect: {
            'row': [0, 2],
            'column': [0, 0],
          },
          hasRawFilterSelect: true,
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 420,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final sheetTop =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth -
                8,
            sheetTop + 10,
          ),
    );
    await tester.pump();

    final searchY =
        sheetTop +
        workbook.settings.columnHeaderHeight +
        1 +
        fortuneFilterDropdownRowHeight * 7 +
        fortuneFilterDropdownSearchGap +
        fortuneFilterDropdownSearchHeight / 2;
    await tester.tapAt(topLeft + Offset(50, searchY));
    await tester.enterText(find.byType(EditableText), 'zzz');
    await tester.pump();

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final dropdownTop = sheetTop + workbook.settings.columnHeaderHeight + 1;
    var blueSwatchPixels = 0;
    for (
      var y = (dropdownTop + fortuneFilterDropdownRowHeight * 3 + 6).round();
      y < dropdownTop + fortuneFilterDropdownRowHeight * 3 + 18;
      y += 1
    ) {
      for (var x = 25; x < 37; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (blue > 200 && red < 60 && green < 80) {
          blueSwatchPixels += 1;
        }
      }
    }
    expect(blueSwatchPixels, greaterThan(30));

    var noMatchTextPixels = 0;
    for (
      var y = (dropdownTop + fortuneFilterDropdownRowHeight * 5 + 5).round();
      y < dropdownTop + fortuneFilterDropdownRowHeight * 5 + 19;
      y += 1
    ) {
      for (var x = 8; x < 130; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 90 &&
            red < 190 &&
            green > 90 &&
            green < 190 &&
            blue > 90 &&
            blue < 190) {
          noMatchTextPixels += 1;
        }
      }
    }
    expect(noMatchTextPixels, greaterThan(12));

    await tester.tapAt(
      topLeft + Offset(70, dropdownTop + fortuneFilterDropdownRowHeight * 5.5),
    );
    await tester.pump();

    final painter =
        tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
    final sheet = painter.workbook.activeSheet;
    expect(painter.filterDropdownColumn, 0);
    expect(sheet.filter, isEmpty);
    expect(sheet.hiddenRows, isEmpty);
  });

