  testWidgets('filter dropdown search keeps editor shortcuts local', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(420, 360);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
      tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
        SystemChannels.platform,
        null,
      );
    });
    var clipboardText = '';
    tester.binding.defaultBinaryMessenger.setMockMethodCallHandler(
      SystemChannels.platform,
      (call) async {
        switch (call.method) {
          case 'Clipboard.setData':
            clipboardText = (call.arguments as Map)['text'] as String;
            return null;
          case 'Clipboard.getData':
            return <String, Object?>{'text': clipboardText};
        }
        return null;
      },
    );

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 3,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'Status'),
            const FortuneCellCoord(1, 0): const FortuneCell(value: 'Open'),
            const FortuneCellCoord(2, 0): const FortuneCell(value: 'Closed'),
          },
          filterSelect: {
            'row': [0, 2],
            'column': [0, 0],
          },
          hasRawFilterSelect: true,
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 420,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final sheetTop =
        workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
    await tester.tapAt(
      topLeft +
          Offset(
            workbook.settings.rowHeaderWidth +
                workbook.settings.defaultColWidth -
                8,
            sheetTop + 10,
          ),
    );
    await tester.pump();

    final searchY =
        sheetTop +
        workbook.settings.columnHeaderHeight +
        1 +
        fortuneFilterDropdownRowHeight * 5 +
        fortuneFilterDropdownSearchGap +
        fortuneFilterDropdownSearchHeight / 2;
    await tester.tapAt(topLeft + Offset(50, searchY));
    await tester.enterText(find.byType(EditableText), 'closed');
    await tester.pump();

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyA);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    final editor = tester.widget<EditableText>(find.byType(EditableText));
    expect(painter().filterDropdownColumn, 0);
    expect(editor.controller.text, 'closed');
    expect(editor.controller.selection.start, 0);
    expect(editor.controller.selection.end, 'closed'.length);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyC);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();
    expect((await Clipboard.getData(Clipboard.kTextPlain))?.text, 'closed');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyX);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();
    expect(editor.controller.text, isEmpty);
    expect(painter().filterDropdownColumn, 0);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyV);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();
    expect(editor.controller.text, 'closed');
    expect(painter().filterDropdownSearchText, 'closed');
  });

