  testWidgets('filter markers distinguish active filtered columns', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(420, 180);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final repaintKey = GlobalKey();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 4,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'Status'),
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'Region'),
            const FortuneCellCoord(1, 0): const FortuneCell(value: 'Open'),
            const FortuneCellCoord(1, 1): const FortuneCell(value: 'East'),
          },
          filter: {
            '1': {
              'rangeType': 'column',
              'row': [0, 3],
              'column': [1, 1],
              'column_focus': 1,
              'filterValue': 'East',
              'rowhidden': {'2': 0, '3': 0},
            },
          },
          filterSelect: {
            'row': [0, 3],
            'column': [0, 1],
          },
          hasRawFilterSelect: true,
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 420,
            height: 180,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );
    await tester.pump();

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    int purplePixelsInMarker(int column) {
      final left =
          workbook.settings.rowHeaderWidth +
          workbook.settings.defaultColWidth * (column + 1) -
          18;
      final top =
          workbook.settings.toolbarHeight +
          workbook.settings.formulaBarHeight +
          3;
      var count = 0;
      for (var y = top; y < top + 15; y += 1) {
        for (var x = left.round(); x < left.round() + 15; x += 1) {
          final offset = (y.round() * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          if (blue > 150 && red > 70 && green > 60 && blue > red + 35) {
            count += 1;
          }
        }
      }
      return count;
    }

    final inactivePurple = purplePixelsInMarker(0);
    final activePurple = purplePixelsInMarker(1);
    expect(inactivePurple, greaterThan(0));
    expect(activePurple, greaterThan(inactivePurple + 60));
  });

