            const FortuneCellCoord(3, 0): const FortuneCell(value: 'Pending'),
          },
          filterSelect: {
            'row': [0, 3],
            'column': [0, 0],
          },
          hasRawFilterSelect: true,
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 420,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> openDropdown() async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final sheetTop =
          workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
      await tester.tapAt(
        topLeft +
            Offset(
              workbook.settings.rowHeaderWidth +
                  workbook.settings.defaultColWidth -
                  8,
              sheetTop + 10,
            ),
      );
      await tester.pump();
    }

    Future<void> tapBulk(double localX) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final sheetTop =
          workbook.settings.toolbarHeight + workbook.settings.formulaBarHeight;
      await tester.tapAt(
        topLeft +
            Offset(
              localX,
              sheetTop +
                  workbook.settings.columnHeaderHeight +
                  1 +
                  fortuneFilterDropdownRowHeight * 2.5,
            ),
      );
      await tester.pump();
    }

    await openDropdown();
    expect(painter().filterDropdownColumn, 0);

    await tapBulk(128);
    var sheet = painter().workbook.activeSheet;
    expect(painter().filterDropdownColumn, 0);
    expect(sheet.filter['0'], isA<Map>());
    expect((sheet.filter['0'] as Map)['rowhidden'], {'1': 0, '2': 0, '3': 0});
    expect(sheet.hiddenRows, {1, 2, 3});

    await tapBulk(90);
    sheet = painter().workbook.activeSheet;
    expect(painter().filterDropdownColumn, 0);
    expect(sheet.filter.containsKey('0'), false);
    expect(sheet.hiddenRows, isEmpty);

    await tapBulk(165);
    sheet = painter().workbook.activeSheet;
    expect((sheet.filter['0'] as Map)['rowhidden'], {'1': 0, '2': 0, '3': 0});
    expect(sheet.hiddenRows, {1, 2, 3});

    await tapBulk(165);
    sheet = painter().workbook.activeSheet;
    expect(sheet.filter.containsKey('0'), false);
    expect(sheet.hiddenRows, isEmpty);
  });

