      expect(sheet.cells[const FortuneCellCoord(1, 1)]?.value, '3');
      expect(sheet.cells[const FortuneCellCoord(2, 0)]?.value, 'Bravo');
      expect(sheet.cells[const FortuneCellCoord(2, 1)]?.value, '2');
      expect(sheet.cells[const FortuneCellCoord(3, 0)]?.value, 'Alpha');
      expect(sheet.cells[const FortuneCellCoord(3, 1)]?.value, '1');
      expect(sheet.cells[const FortuneCellCoord(0, 2)]?.bold, isTrue);
      expect(painter().filterDropdownColumn, isNull);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

