    await tester.pump();

    Offset checkboxForRow(double rowIndex) {
      return topLeft +
          Offset(
            13,
            sheetTop +
                workbook.settings.columnHeaderHeight +
                1 +
                fortuneFilterDropdownRowHeight * rowIndex,
          );
