  testWidgets('data verification dropdown options expose focusable semantics', (
    tester,
  ) async {
    final closedPainter = FortuneSheetPainter(
      workbook: FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            dataVerification: {
              '0_0': {'type': 'dropdown', 'value1': 'Red,Green,Blue'},
            },
          ),
        ],
      ),
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
    );
    final closedSemantics = closedPainter.semanticsBuilder(
      const Size(900, 600),
    );
    final dropdownMarker = closedSemantics.singleWhere(
      (node) => node.properties.label == 'Dropdown',
    );

