          dataVerification: {
            '0_0': {
              'type': 'dropdown',
              'type2': 'dropdown',
              'value1': ' Red , Green , Blue ',
              'prohibitInput': 1,
            },
            '0_1': {
              'type': 'dropdown',
              'type2': 1,
              'value1': ' Red , Green , Blue ',
              'prohibitInput': 1,
            },
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 900,
          height: 360,
