    expect(
      painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(0, 0)]
          ?.renderedText,
      ' Green ',
    );

    await pasteAt(1, ' Red , Blue ');
    expect(
      painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      ' Red , Blue ',
    );
    await pasteAt(1, ' Red , Yellow ');
    expect(
      painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(0, 1)]
          ?.renderedText,
      ' Red , Blue ',
    );
  });

