  testWidgets('data verification blocked input keeps undo stack', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 2): const FortuneCell(value: 'undo'),
          },
          dataVerification: {
            '0_0': {'type': 'dropdown', 'value1': 'Z1:Z2', 'prohibitInput': 1},
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Offset toolbarCenter(String key) => toolbarItemCenter(key, width: 1688);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(229, 100));
    await tester.pump();
    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarBoldCommand));
    await tester.pump();

    var sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 2)]?.bold, isTrue);

    await tester.tapAt(topLeft + const Offset(58, 100));
    await tester.pump();
    await tester.tapAt(topLeft + const Offset(180, 54));
    await tester.pump();
    await tester.enterText(find.byType(EditableText), 'Yellow');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 0)], isNull);
    expect(sheet.cells[const FortuneCellCoord(0, 2)]?.bold, isTrue);
    await dismissFortuneLocationMessageDialog(
      tester,
      canvasSize: const Size(1688, 360),
    );

    await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarUndoCommand));
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 0)], isNull);
    expect(sheet.cells[const FortuneCellCoord(0, 2)]?.bold, isFalse);
  });

