              '0_2': rule('earlierThan', value1: '2026-05-10'),
              '0_3': rule('noEarlierThan', value1: '2026-05-10'),
              '0_4': rule('laterThan', value1: '2026-05-10'),
              '0_5': rule('noLaterThan', value1: '2026-05-10'),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 900,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      Future<void> pasteAt(int column, String text) async {
        clipboardText = text;
        await tester.tapAt(topLeft + Offset(58 + column * 73, 100));
        await tester.pump();
        await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
        await tester.sendKeyEvent(LogicalKeyboardKey.keyV);
        await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
        await tester.pump();
      }

      const cases = [
        (column: 0, allowed: '2026-04-30', blocked: '2026-05-10'),
        (column: 1, allowed: '2026-05-09', blocked: '2026-05-10'),
        (column: 2, allowed: '2026-05-09', blocked: '2026-05-10'),
        (column: 3, allowed: '2026-05-10', blocked: '2026-05-09'),
        (column: 4, allowed: '2026-05-11', blocked: '2026-05-10'),
        (column: 5, allowed: '2026-05-10', blocked: '2026-05-11'),
      ];

      for (final item in cases) {
        final coord = FortuneCellCoord(0, item.column);
        await pasteAt(item.column, item.allowed);
        expect(
          painter().workbook.activeSheet.cells[coord]?.renderedText,
          item.allowed,
        );

        await pasteAt(item.column, item.blocked);
        expect(
          painter().workbook.activeSheet.cells[coord]?.renderedText,
          item.allowed,
        );
      }
    },
  );

