      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarImageCommand));
      await tester.pumpAndSettle();

      var images = painter().workbook.activeSheet.images;
      expect(images, hasLength(1));
      expect(images.single.id, startsWith('img_'));
      expect(images.single.src, fortuneTestImageSrc());
      expect(images.single.left, 0);
      expect(images.single.top, 0);
      expect(images.single.width, 0.5);
      expect(images.single.height, 0.5);
      expect(images.single.extraFields['originWidth'], 1);
      expect(images.single.extraFields['originHeight'], 1);
      expect(painter().toolbarPopupKey, isNull);

      await tester.tapAt(topLeft + toolbarCenter(fortuneToolbarImageCommand));
      await tester.pumpAndSettle();

      images = painter().workbook.activeSheet.images;
      expect(images, hasLength(2));

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      images = painter().workbook.activeSheet.images;
      expect(images, hasLength(1));
      expect(images.single.id, startsWith('img_'));

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      images = painter().workbook.activeSheet.images;
      expect(images, hasLength(2));
    },
  );

