  testWidgets('toolbar split text confirms before overwriting cells', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'A,B'),
            const FortuneCellCoord(0, 1): const FortuneCell(value: 'Existing'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final canvasSize = tester.getSize(find.byType(FortuneSheetCanvas));

    Future<void> requestSplit() async {
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarSplitColumnCommand, width: 1688),
      );
      await tester.pumpAndSettle();
      final splitRect = fortuneSplitTextDialogRect(canvasSize);
      await tester.tapAt(
        topLeft + fortuneSplitTextDelimiterRowRect(splitRect, 'comma').center,
      );
      await tester.pump();
      await tester.tapAt(
        topLeft + fortuneSplitTextOkButtonRect(splitRect).center,
      );
      await tester.pump();
    }

    await requestSplit();

    expect(painter().splitTextDialogOpen, isFalse);
    expect(
      painter().locationMessageDialogText,
      'There is already data here, do you want to replace it?',
    );
    var sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.value, 'A,B');
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.value, 'Existing');

    var messageRect = fortuneLocationMessageDialogRect(
      canvasSize,
      message: painter().locationMessageDialogText,
    );
    await tester.tapAt(
      topLeft +
          fortuneLocationMessageConfirmCancelButtonRect(messageRect).center,
    );
    await tester.pump();

    expect(painter().locationMessageDialogText, isNull);
    sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.value, 'A,B');
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.value, 'Existing');

    await requestSplit();

    messageRect = fortuneLocationMessageDialogRect(
      canvasSize,
      message: painter().locationMessageDialogText,
    );
    await tester.tapAt(
      topLeft + fortuneLocationMessageConfirmOkButtonRect(messageRect).center,
    );
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(painter().locationMessageDialogText, isNull);
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.value, 'A');
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.value, 'B');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.value, 'A,B');
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.value, 'Existing');
  });

