  testWidgets('toolbar screenshot opens successful preview dialog', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      settings: const FortuneSettings(devicePixelRatio: 2),
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'Capture'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 600,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
    );
    await tester.pumpAndSettle();

    expect(painter().screenshotDialogOpen, isTrue);
    expect(painter().screenshotRange?.rowStart, 0);
    expect(painter().screenshotRange?.columnStart, 0);
    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImageDataUrl != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }
    final imageDataUrl = painter().screenshotImageDataUrl;
    expect(imageDataUrl, startsWith('data:image/png;base64,'));
    expect(painter().screenshotImage, isNotNull);
    expect(painter().screenshotImage!.width, greaterThan(0));
    expect(painter().screenshotImage!.height, greaterThan(0));
    final metrics = workbook.activeSheet.metrics(workbook.settings);
    expect(
      painter().screenshotImage!.width,
      (metrics.visibleDataColumns[0] * workbook.settings.devicePixelRatio)
          .ceil(),
    );
    expect(
      painter().screenshotImage!.height,
      (metrics.visibleDataRows[0] * workbook.settings.devicePixelRatio).ceil(),
    );
    final pngBytes = base64Decode(
      imageDataUrl!.substring('data:image/png;base64,'.length),
    );
    expect(pngBytes.take(8), [137, 80, 78, 71, 13, 10, 26, 10]);

    final dialogRect = fortuneScreenshotDialogRect(
      tester.getSize(find.byType(FortuneSheetCanvas)),
    );
    await tester.tapAt(
      topLeft + fortuneScreenshotOkButtonRect(dialogRect).center,
    );
    await tester.pump();

    expect(painter().screenshotDialogOpen, isFalse);
    expect(painter().screenshotImageDataUrl, isNull);
    expect(painter().screenshotImage, isNull);
  });

  testWidgets('toolbar screenshot renders captured image in preview dialog', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final repaintKey = GlobalKey();
    const captureColor = Color(0xff22aa44);
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          defaultColWidth: 80,
          defaultRowHeight: 80,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: '',
              background: captureColor,
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
    );
    await tester.pumpAndSettle();
    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    expect(painter().screenshotImage, isNotNull);

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await tester.runAsync(() => boundary.toImage(pixelRatio: 1));
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final previewRect = fortuneScreenshotPreviewRect(
      fortuneScreenshotDialogRect(const Size(1688, 600)),
    );
    final sampleX = previewRect.center.dx.toInt();
    final sampleY = previewRect.center.dy.toInt();
    final offset = (sampleY * image!.width + sampleX) * 4;
    expect(pixels!.getUint8(offset), closeTo(0x22, 1));
    expect(pixels.getUint8(offset + 1), closeTo(0xaa, 1));
    expect(pixels.getUint8(offset + 2), closeTo(0x44, 1));
    expect(pixels.getUint8(offset + 3), 255);
  });

