    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
    );
    await tester.pumpAndSettle();
    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var redCommentPixels = 0;
    for (var y = 1; y <= 7; y += 1) {
      for (var x = 66; x <= 72; x += 1) {
        final offset = (y * image!.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 180 && green < 90 && blue < 80) {
          redCommentPixels += 1;
        }
      }
    }
    expect(redCommentPixels, greaterThan(8));

    var dropdownMarkerPixels = 0;
    for (var y = 7; y <= 14; y += 1) {
      for (var x = 134; x <= 142; x += 1) {
        final offset = (y * image!.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if ((red - 95).abs() < 20 &&
            (green - 99).abs() < 20 &&
            (blue - 104).abs() < 20) {
          dropdownMarkerPixels += 1;
        }
      }
    }
    expect(dropdownMarkerPixels, greaterThan(6));

    var checkboxPixels = 0;
    for (var y = 4; y <= 15; y += 1) {
      for (var x = 148; x <= 158; x += 1) {
        final offset = (y * image!.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red < 80 && green < 80 && blue < 80) {
          checkboxPixels += 1;
        }
      }
    }
    expect(checkboxPixels, greaterThan(8));

    var checkboxLabelPixels = 0;
    for (var y = 3; y <= 18; y += 1) {
      for (var x = 162; x <= 202; x += 1) {
        final offset = (y * image!.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (blue > 150 && red < 90 && green < 120) {
          checkboxLabelPixels += 1;
        }
      }
    }
    expect(checkboxLabelPixels, greaterThan(4));
  });

