  test('raw shape line overlay parses endpoint aliases', () {
    final sheet = FortuneSheet(
      id: 's1',
      name: 'Sheet1',
      extraFields: const {
        'shapes': {
          'line1': {
            'type': 'line',
            'startx': 90,
            'starty': 50,
            'endx': 20,
            'endy': 10,
            'strokecolor': '#112233',
            'linewidth': '3',
            'zindex': '7',
          },
          'line2': {
            'type': 'line',
            'startX': 4,
            'startY': 4,
            'endX': 4,
            'endY': 4,
          },
        },
      },
    );

    final overlay = fortuneRawShapeOverlays(sheet).single;
    expect(overlay.kind, 'line');
    expect(overlay.rect, const Rect.fromLTWH(20, 10, 70, 40));
    expect(
      fortuneRawShapeOverlayScreenRect(
        overlay,
        const FortuneSettings(),
        const Offset(6, 8),
        2,
      ),
      const Rect.fromLTWH(80, 32, 140, 80),
    );
    expect(
      fortuneRawShapeOverlayScreenRect(
        overlay,
        const FortuneSettings(),
        Offset.zero,
        0,
      ),
      const Rect.fromLTWH(66, 30, 70, 40),
    );
    expect(overlay.lineStart, const Offset(70, 40));
    expect(overlay.lineEnd, Offset.zero);
    expect(overlay.strokeColor, const Color(0xff112233));
    expect(overlay.strokeWidth, 3);
    expect(overlay.zIndex, 7);
  });

