  testWidgets('raw chart tooltip hover respects show delay', (tester) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          extraFields: const {
            'chart': [
              {
                'id': 'hoverDelayChart',
                'left': 20,
                'top': 20,
                'width': 160,
                'height': 110,
                'option': {
                  'tooltip': {'show': true, 'showDelay': 120},
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 420,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final settings = workbook.settings;
    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final hoverPoint =
        topLeft +
        Offset(
          settings.rowHeaderWidth + 20 + 80,
          settings.toolbarHeight +
              settings.formulaBarHeight +
              settings.columnHeaderHeight +
              20 +
