    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          zoomRatio: 2,
          extraFields: const {
            'chart': [
              {
                'id': 'zoomClickChart',
                'left': 120,
                'top': 40,
                'width': 80,
                'height': 60,
                'option': {
                  'tooltip': {'show': true, 'triggerOn': 'click'},
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2, 5],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 620,
          height: 420,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final settings = workbook.settings;
    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    Offset chartPoint({required bool scaled}) {
      final zoomRatio = scaled ? workbook.activeSheet.zoomRatio : 1.0;
      return topLeft +
          Offset(
            settings.rowHeaderWidth + (120 + 40) * zoomRatio,
            settings.toolbarHeight +
                settings.formulaBarHeight +
                settings.columnHeaderHeight +
                (40 + 30) * zoomRatio,
          );
    }

    await tester.tapAt(chartPoint(scaled: false));
    await tester.pump();

    expect(painter().rawChartClickPosition, isNull);

    await tester.tapAt(chartPoint(scaled: true));
    await tester.pump();

    expect(painter().rawChartClickPosition, isNotNull);
    expect(painter().rawChartClickOverlayKey, 'chart:0');
  });

