    expect(series.endLabelShadowOffsetX, -6);
    expect(series.endLabelTextShadowBlur, isNull);
    expect(series.endLabelTextShadowOffsetY, -8);
    expect(series.itemShadowBlur, isNull);
    expect(series.itemShadowOffsetX, -10);
    expect(series.labelLineShadowBlur, isNull);
    expect(series.labelLineShadowOffsetY, -18);
    expect(series.pointLabelShadowBlurs.first, isNull);
    expect(series.pointLabelShadowOffsetXs.first, -12);
    expect(series.pointLabelTextShadowBlurs.first, isNull);
    expect(series.pointLabelTextShadowOffsetYs.first, -14);
