    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var shiftedCyanPixels = 0;
    var defaultCenterCyanPixels = 0;
    for (var y = 10; y < math.min(image!.height, 110); y += 1) {
      for (var x = 20; x < math.min(image.width, 140); x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final isCyan = green > 180 && blue > 180 && red < 100;
        if (!isCyan) {
          continue;
        }
        if (x >= 100 && y >= 68) {
          shiftedCyanPixels += 1;
        }
        if (x < 86 && y < 68) {
          defaultCenterCyanPixels += 1;
        }
      }
    }
    expect(shiftedCyanPixels, greaterThan(0));
    expect(shiftedCyanPixels, greaterThan(defaultCenterCyanPixels));
  });

