      final image = painter().screenshotImage;
      expect(image, isNotNull);
      final pixels = await tester.runAsync(
        () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);

      var magentaPixels = 0;
      var cyanPixels = 0;
      var magentaLeft = image!.width;
      var magentaRight = 0;
      var magentaTop = image.height;
      var magentaBottom = 0;
      var cyanXSum = 0;
      var cyanYSum = 0;
      for (var y = 0; y < math.min(image.height, 140); y += 1) {
        for (var x = 0; x < math.min(image.width, 180); x += 1) {
          final offset = (y * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 100) {
            magentaPixels += 1;
            magentaLeft = math.min(magentaLeft, x);
            magentaRight = math.max(magentaRight, x);
            magentaTop = math.min(magentaTop, y);
            magentaBottom = math.max(magentaBottom, y);
          }
          if (green > 180 && blue > 180 && red < 100) {
            cyanPixels += 1;
            cyanXSum += x;
            cyanYSum += y;
          }
        }
      }
      expect(magentaPixels, greaterThan(3000));
      expect(cyanPixels, greaterThan(20));
      expect(magentaRight - magentaLeft, greaterThan(110));
      expect(magentaBottom - magentaTop, greaterThan(40));
      expect(
        cyanXSum / cyanPixels,
        greaterThan((magentaLeft + magentaRight) / 2),
      );
      expect(
        cyanYSum / cyanPixels,
        greaterThan((magentaTop + magentaBottom) / 2),
      );
    },
  );

