    var defaultFarMagentaPixels = 0;
    for (var y = 0; y < math.min(image!.height, 118); y += 1) {
      for (var x = 20; x < math.min(image.width, 335); x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final isMagenta = red > 180 && blue > 180 && green < 100;
        if (!isMagenta) {
          continue;
        }
        if (x >= 126 && x < 160) {
          extendedMagentaPixels += 1;
        }
        if (x >= 310 && x < 335) {
          defaultFarMagentaPixels += 1;
        }
      }
    }
    expect(extendedMagentaPixels, greaterThan(20));
    expect(defaultFarMagentaPixels, lessThan(5));
  });

