    var magentaShadowPixels = 0;
    var blackLinePixels = 0;
    for (var y = 0; y < math.min(image!.height, 125); y += 1) {
      for (var x = 70; x < math.min(image.width, 170); x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaShadowPixels += 1;
        }
        if (red < 60 && green < 60 && blue < 60) {
          blackLinePixels += 1;
        }
      }
    }
    expect(magentaShadowPixels, greaterThan(20));
    expect(blackLinePixels, greaterThan(10));
  });

