    Future<int> captureCornerBorderPixels(double? radius) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            selectionSave: const [
              {
                'row': [0, 4],
