                'row_focus': 0,
                'column_focus': 0,
              },
            ],
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 10,
                  'width': 170,
                  'height': 100,
                  'option': {
                    'legend': {
                      'data': ['Actual', 'Plan'],
                      'textStyle': {
                        'color': '#ff00ff',
