                        'fontStyle': ?fontStyle,
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                        'lineStyle': {'color': '#00ff00'},
                      },
                      {
                        'type': 'bar',
                        'data': [2, 3, 4, 1],
                        'itemStyle': {'color': '#00ffff'},
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );

      final overlay = fortuneRawShapeOverlays(workbook.activeSheet).single;
      if (fontStyle == null) {
        expect(overlay.chartLegendTextFontStyle, isNull);
      } else {
        expect(overlay.chartLegendTextFontStyle, FontStyle.italic);
      }

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
      );
      await tester.pumpAndSettle();
      await tester.runAsync(() async {
        await Future<void>.delayed(const Duration(milliseconds: 100));
      });
      await tester.pump();
      for (var attempt = 0; attempt < 20; attempt += 1) {
        if (painter().screenshotImage != null) {
          break;
        }
        await tester.pump(const Duration(milliseconds: 50));
      }

      final image = painter().screenshotImage;
      expect(image, isNotNull);
      final pixels = await tester.runAsync(
        () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);
      return (pixels: pixels!, width: image!.width, height: image.height);
    }

    final normal = await captureLegendPixels(null);
    final italic = await captureLegendPixels('italic');

    var changedMagentaPixels = 0;
    for (var y = 62; y < math.min(normal.height, 98); y += 1) {
      for (var x = 38; x < math.min(normal.width, 180); x += 1) {
        final offset = (y * normal.width + x) * 4;
        final normalRed = normal.pixels.getUint8(offset);
        final normalGreen = normal.pixels.getUint8(offset + 1);
        final normalBlue = normal.pixels.getUint8(offset + 2);
        final italicRed = italic.pixels.getUint8(offset);
        final italicGreen = italic.pixels.getUint8(offset + 1);
        final italicBlue = italic.pixels.getUint8(offset + 2);
        final hasMagenta =
            (normalRed > 180 && normalBlue > 180 && normalGreen < 150) ||
            (italicRed > 180 && italicBlue > 180 && italicGreen < 150);
        final changed =
            (normalRed - italicRed).abs() +
            (normalGreen - italicGreen).abs() +
            (normalBlue - italicBlue).abs();
        if (hasMagenta && changed > 80) {
          changedMagentaPixels += 1;
        }
      }
    }
    expect(changedMagentaPixels, greaterThan(20));
  });

