    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var minX = image!.width;
    var minY = image.height;
    var maxX = -1;
    var maxY = -1;
    var greenPixels = 0;
    for (var y = 48; y < math.min(image.height, 88); y += 1) {
      for (var x = 24; x < math.min(image.width, 70); x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (green > 180 && red < 80 && blue < 80) {
          greenPixels += 1;
          minX = math.min(minX, x);
          minY = math.min(minY, y);
          maxX = math.max(maxX, x);
          maxY = math.max(maxY, y);
        }
      }
    }
    expect(greenPixels, greaterThan(120));
    expect(maxX - minX, greaterThan(20));
    expect(maxY - minY, greaterThan(10));

    var cornerPixels = 0;
    for (var y = minY; y <= minY + 2; y += 1) {
      for (var x = minX; x <= minX + 2; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (green > 180 && red < 80 && blue < 80) {
          cornerPixels += 1;
        }
      }
    }
    expect(cornerPixels, lessThan(3));
  });

