  testWidgets('toolbar screenshot preserves raw chart split area intervals', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    FortuneWorkbook workbookFor({required bool interval}) {
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            selectionSave: const [
              {
                'row': [0, 6],
                'column': [0, 4],
                'row_focus': 0,
                'column_focus': 0,
              },
            ],
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 10,
                  'width': 150,
                  'height': 130,
                  'option': {
                    'xAxis': {
                      'splitArea': {
                        'show': true,
                        if (interval) 'interval': 1,
                        'areaStyle': {
                          'color': ['#ff00ff', '#ff00ff'],
                        },
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
                {
                  'id': 'chart2',
                  'left': 200,
                  'top': 10,
                  'width': 150,
                  'height': 130,
                  'option': {
                    'yAxis': {
                      'splitArea': {
                        'show': true,
                        if (interval) 'interval': 1,
                        'areaStyle': {
                          'color': ['#00ffff', '#00ffff'],
                        },
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<(int, int)> captureBandPixels(FortuneWorkbook workbook) async {
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
      );
      await tester.pumpAndSettle();
      await tester.runAsync(() async {
        await Future<void>.delayed(const Duration(milliseconds: 100));
      });
      await tester.pump();
      for (var attempt = 0; attempt < 20; attempt += 1) {
        if (painter().screenshotImage != null) {
          break;
        }
        await tester.pump(const Duration(milliseconds: 50));
      }

      final image = painter().screenshotImage;
      expect(image, isNotNull);
      final pixels = await tester.runAsync(
        () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);

      var magentaBandPixels = 0;
      var cyanBandPixels = 0;
      for (var y = 0; y < image!.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = (y * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 120) {
            magentaBandPixels += 1;
          }
          if (green > 180 && blue > 180 && red < 120) {
            cyanBandPixels += 1;
          }
        }
      }
      return (magentaBandPixels, cyanBandPixels);
    }

    final intervalWorkbook = workbookFor(interval: true);
    final overlays = fortuneRawShapeOverlays(intervalWorkbook.activeSheet);
    expect(overlays.first.chartVerticalSplitAreaInterval, 1);
    expect(overlays.last.chartHorizontalSplitAreaInterval, 1);

    final (allMagentaPixels, allCyanPixels) = await captureBandPixels(
      workbookFor(interval: false),
    );
    final (intervalMagentaPixels, intervalCyanPixels) = await captureBandPixels(
      intervalWorkbook,
    );

    expect(allMagentaPixels, greaterThan(1000));
    expect(allCyanPixels, greaterThan(1000));
    expect(intervalMagentaPixels, lessThan(allMagentaPixels * 0.7));
    expect(intervalCyanPixels, lessThan(allCyanPixels * 0.7));
    expect(intervalMagentaPixels, greaterThan(500));
    expect(intervalCyanPixels, greaterThan(500));
  });

