    expect(overlay.chartYAxisPointerHandleShadowBlur, 4);
    expect(overlay.chartXAxisPointerHandleShadowOffsetX, 4);
    expect(overlay.chartYAxisPointerHandleShadowOffsetX, 5);
    expect(overlay.chartXAxisPointerHandleShadowOffsetY, 5);
    expect(overlay.chartYAxisPointerHandleShadowOffsetY, 6);
    expect(overlay.chartXAxisPointerHandleMargin, 8);
    expect(overlay.chartYAxisPointerHandleMargin, 9);
    expect(overlay.chartXAxisPointerHandleThrottle, 40);
    expect(overlay.chartYAxisPointerHandleThrottle, 60);
    expect(overlay.chartXAxisPointerColor, const Color(0xffff00ff));
    expect(overlay.chartYAxisPointerColor, const Color(0xff00ffff));
    expect(overlay.chartXAxisPointerWidth, 5);
    expect(overlay.chartYAxisPointerWidth, 4);
    expect(overlay.chartXAxisPointerType, 'dashed');
    expect(overlay.chartYAxisPointerType, 'dotted');
    expect(overlay.chartXAxisPointerDashOffset, 6);
    expect(overlay.chartYAxisPointerDashOffset, 7);
    expect(overlay.chartXAxisPointerCap, 'round');
    expect(overlay.chartYAxisPointerCap, 'square');
    expect(overlay.chartXAxisPointerShadowColor, const Color(0xff00ff00));
    expect(overlay.chartYAxisPointerShadowColor, const Color(0xffff8800));
    expect(overlay.chartXAxisPointerShadowBlur, 0);
    expect(overlay.chartYAxisPointerShadowBlur, 0);
    expect(overlay.chartXAxisPointerShadowOffsetX, 7);
    expect(overlay.chartYAxisPointerShadowOffsetX, 8);
    expect(overlay.chartXAxisPointerShadowOffsetY, 8);
    expect(overlay.chartYAxisPointerShadowOffsetY, 7);

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
    );
    await tester.pumpAndSettle();
    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var magentaPointerPixels = 0;
    var cyanPointerPixels = 0;
    var greenShadowPixels = 0;
    var orangeShadowPixels = 0;
    for (var y = 0; y < image!.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 180 && blue > 180 && green < 100) {
          magentaPointerPixels += 1;
        }
        if (green > 180 && blue > 180 && red < 100) {
          cyanPointerPixels += 1;
        }
        if (green > 170 && red < 120 && blue < 120) {
          greenShadowPixels += 1;
        }
        if (red > 170 && green > 90 && green < 180 && blue < 120) {
          orangeShadowPixels += 1;
        }
      }
    }
    expect(magentaPointerPixels, greaterThan(120));
    expect(cyanPointerPixels, greaterThan(120));
    expect(greenShadowPixels, greaterThan(60));
    expect(orangeShadowPixels, greaterThan(60));
  });

