  test('raw chart graphic metadata parses nested elements', () {
    final sheet = FortuneSheet(
      id: 's1',
      name: 'Sheet1',
      extraFields: const {
        'chart': [
          {
            'id': 'chart1',
            'left': 20,
            'top': 10,
            'width': 150,
            'height': 110,
            'option': {
              'graphic': {
                'elements': [
                  {
                    'id': 'watermark-group',
                    'type': 'group',
                    'left': 'center',
                    'top': 12,
                    'rotation': '0.25',
                    'scale': [1.2, 0.8],
                    'scaleX': '1.4',
                    'scaleY': 0.6,
                    'origin': ['50%', '50%'],
                    'bounding': 'raw',
                    'z': '20',
                    'z2': 3,
                    'zlevel': '2',
                    'silent': 1,
                    'children': [
                      {
                        'id': 'watermark-text',
                        'name': 'Watermark',
                        'type': 'text',
                        'x': '10',
                        'y': 15,
                        'position': [10, 15],
                        'style': {'text': 'Draft', 'fill': '#cccccc'},
                        'textContent': {
                          'type': 'text',
                          'style': {'text': 'Inner'},
                        },
                        'textConfig': {'position': 'inside'},
                      },
                    ],
                  },
                  {
                    'id': 'badge-rect',
                    'type': 'rect',
                    'right': 8,
                    'bottom': '10%',
                    'width': '24',
                    'height': 12,
                    'invisible': 0,
                    'ignore': 'false',
                    'draggable': 'true',
                    'cursor': 'move',
                    'clipPath': {
                      'type': 'rect',
                      'shape': {'width': 12, 'height': 10},
                    },
                    'shape': {'r': 4},
                    'style': {'fill': '#00ffff'},
                    'elements': [
                      {'id': 'badge-child', 'type': 'circle'},
                    ],
                  },
                ],
              },
              'series': [
                {
                  'type': 'line',
                  'data': [1, 4, 2, 5],
                },
              ],
            },
          },
        ],
      },
    );

    final graphics = fortuneRawShapeOverlays(sheet).single.chartGraphics;
    expect(graphics, hasLength(2));

    final group = graphics[0];
    expect(group.id, 'watermark-group');
    expect(group.type, 'group');
    expect(group.left, 'center');
    expect(group.top, 12);
    expect(group.rotation, 0.25);
    expect(group.scale, [1.2, 0.8]);
    expect(group.scaleX, 1.4);
    expect(group.scaleY, 0.6);
    expect(group.origin, ['50%', '50%']);
    expect(group.bounding, 'raw');
    expect(group.z, 20);
    expect(group.z2, 3);
    expect(group.zLevel, 2);
    expect(group.silent, isTrue);
    expect(group.children, hasLength(1));

    final text = group.children.single;
    expect(text.id, 'watermark-text');
    expect(text.name, 'Watermark');
    expect(text.type, 'text');
    expect(text.x, 10);
    expect(text.y, 15);
    expect(text.position, [10, 15]);
    expect(text.style, {'text': 'Draft', 'fill': '#cccccc'});
    expect(text.textContent, {
      'type': 'text',
      'style': {'text': 'Inner'},
    });
    expect(text.textConfig, {'position': 'inside'});

    final badge = graphics[1];
    expect(badge.id, 'badge-rect');
    expect(badge.type, 'rect');
    expect(badge.right, 8);
    expect(badge.bottom, '10%');
    expect(badge.width, 24);
    expect(badge.height, 12);
    expect(badge.invisible, isFalse);
    expect(badge.ignore, isFalse);
    expect(badge.draggable, isTrue);
    expect(badge.cursor, 'move');
    expect(badge.clipPath?.type, 'rect');
    expect(badge.clipPath?.shape, {'width': 12, 'height': 10});
    expect(badge.shape, {'r': 4});
    expect(badge.style, {'fill': '#00ffff'});
    expect(badge.children.single.id, 'badge-child');
    expect(badge.children.single.type, 'circle');
  });

  testWidgets('toolbar screenshot preserves raw chart cross axis pointer', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          selectionSave: const [
            {
              'row': [0, 5],
              'column': [0, 3],
              'row_focus': 0,
              'column_focus': 0,
            },
          ],
          extraFields: const {
            'chart': [
              {
                'id': 'chart1',
                'left': 20,
                'top': 10,
                'width': 150,
                'height': 110,
                'option': {
                  'tooltip': {
                    'axisPointer': {
                      'type': 'cross',
                      'crossStyle': {'color': '#ff8800', 'width': 4},
                    },
                  },
                  'xAxis': {
                    'data': ['A', 'B', 'C'],
                    'axisLabel': {'show': false},
                  },
                  'yAxis': {
                    'axisLabel': {'show': false},
                  },
                  'series': [
                    {
                      'type': 'line',
                      'data': [1, 4, 2],
                    },
                  ],
                },
              },
            ],
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 600,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
    );
    await tester.pumpAndSettle();
    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var orangePointerPixels = 0;
    for (var y = 0; y < image!.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 180 && green > 90 && green < 170 && blue < 80) {
          orangePointerPixels += 1;
        }
      }
    }
    expect(orangePointerPixels, greaterThan(120));
  });

