    expect(pixels, isNotNull);

    var yellowPointerPixels = 0;
    var yellowMinY = image!.height.toDouble();
    var yellowMaxY = 0.0;
    for (var y = 0; y < image.height; y += 1) {
      for (var x = 0; x < image.width; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if (red > 180 && green > 180 && blue < 80) {
          yellowPointerPixels += 1;
          yellowMinY = math.min(yellowMinY, y.toDouble());
          yellowMaxY = math.max(yellowMaxY, y.toDouble());
        }
      }
    }
    expect(yellowPointerPixels, greaterThan(50));
    expect(yellowMaxY - yellowMinY, lessThan(12));
  });

