          yAxisTick['alignWithLabel'] = alignWithLabel;
        }
        return FortuneWorkbook(
          sheets: [
            FortuneSheet(
              id: 's1',
              name: 'Sheet1',
              selectionSave: const [
                {
                  'row': [0, 5],
                  'column': [0, 3],
