                        },
                      ],
                    },
                  },
                ],
              },
            ),
          ],
        );
      }

      Future<({Rect magenta, Rect cyan})> captureTickBounds(
        FortuneWorkbook workbook,
      ) async {
        await tester.pumpWidget(
          Directionality(
            textDirection: TextDirection.ltr,
            child: SizedBox(
              width: 1688,
              height: 600,
              child: FortuneSheetCanvas(workbook: workbook),
            ),
          ),
        );

        FortuneSheetPainter painter() {
          return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter;
        }

        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.tapAt(
          topLeft +
              toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
        );
        await tester.pumpAndSettle();
        await tester.runAsync(() async {
          await Future<void>.delayed(const Duration(milliseconds: 100));
        });
        await tester.pump();
        for (var attempt = 0; attempt < 20; attempt += 1) {
          if (painter().screenshotImage != null) {
            break;
          }
          await tester.pump(const Duration(milliseconds: 50));
        }

        final image = painter().screenshotImage;
        expect(image, isNotNull);
        final pixels = await tester.runAsync(
          () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
        );
        expect(pixels, isNotNull);

        var magentaLeft = image!.width.toDouble();
        var magentaTop = image.height.toDouble();
        var magentaRight = 0.0;
        var magentaBottom = 0.0;
        var cyanLeft = image.width.toDouble();
        var cyanTop = image.height.toDouble();
        var cyanRight = 0.0;
        var cyanBottom = 0.0;
        var magentaPixels = 0;
        var cyanPixels = 0;
        for (var y = 0; y < image.height; y += 1) {
          for (var x = 0; x < image.width; x += 1) {
            final offset = (y * image.width + x) * 4;
            final red = pixels!.getUint8(offset);
            final green = pixels.getUint8(offset + 1);
            final blue = pixels.getUint8(offset + 2);
            if (red > 180 && blue > 180 && green < 100) {
              magentaPixels += 1;
              magentaLeft = math.min(magentaLeft, x.toDouble());
              magentaTop = math.min(magentaTop, y.toDouble());
              magentaRight = math.max(magentaRight, x.toDouble());
              magentaBottom = math.max(magentaBottom, y.toDouble());
            }
            if (green > 180 && blue > 180 && red < 100) {
              cyanPixels += 1;
              cyanLeft = math.min(cyanLeft, x.toDouble());
              cyanTop = math.min(cyanTop, y.toDouble());
              cyanRight = math.max(cyanRight, x.toDouble());
              cyanBottom = math.max(cyanBottom, y.toDouble());
            }
          }
        }
        expect(magentaPixels, greaterThan(90));
        expect(cyanPixels, greaterThan(70));
        return (
          magenta: Rect.fromLTRB(
            magentaLeft,
            magentaTop,
            magentaRight,
            magentaBottom,
          ),
          cyan: Rect.fromLTRB(cyanLeft, cyanTop, cyanRight, cyanBottom),
        );
      }

      final alignedWorkbook = workbookFor(alignWithLabel: 1);
      final overlay = fortuneRawShapeOverlays(
        alignedWorkbook.activeSheet,
      ).single;
      expect(overlay.chartXAxisTickAlignWithLabel, isTrue);
      expect(overlay.chartYAxisTickAlignWithLabel, isTrue);

      final baseBounds = await captureTickBounds(workbookFor());
      final alignedBounds = await captureTickBounds(alignedWorkbook);

      expect(
        alignedBounds.magenta.left,
        greaterThan(baseBounds.magenta.left + 8),
      );
      expect(
        alignedBounds.magenta.right,
        lessThan(baseBounds.magenta.right - 8),
      );
      expect(alignedBounds.cyan.top, greaterThan(baseBounds.cyan.top + 6));
      expect(alignedBounds.cyan.bottom, lessThan(baseBounds.cyan.bottom - 6));
    },
  );

