    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var magentaPixels = 0;
    var cyanPixels = 0;
    var maxMagentaColumnRuns = 0;
    var maxCyanRowRuns = 0;
    for (var x = 0; x < image!.width; x += 1) {
      var columnRuns = 0;
      var inMagentaRun = false;
      for (var y = 0; y < image.height; y += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final isMagenta = red > 180 && blue > 180 && green < 100;
        if (isMagenta) {
          magentaPixels += 1;
          if (!inMagentaRun) {
            columnRuns += 1;
          }
        }
        inMagentaRun = isMagenta;
      }
      maxMagentaColumnRuns = math.max(maxMagentaColumnRuns, columnRuns);
    }
    for (var y = 0; y < image.height; y += 1) {
      var rowRuns = 0;
      var inCyanRun = false;
      for (var x = 0; x < image.width; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final isCyan = green > 180 && blue > 180 && red < 100;
        if (isCyan) {
          cyanPixels += 1;
          if (!inCyanRun) {
            rowRuns += 1;
          }
        }
        inCyanRun = isCyan;
      }
      maxCyanRowRuns = math.max(maxCyanRowRuns, rowRuns);
    }
    expect(magentaPixels, greaterThan(80));
    expect(cyanPixels, greaterThan(40));
    expect(maxMagentaColumnRuns, greaterThan(1));
    expect(maxCyanRowRuns, greaterThan(1));
  });

