  testWidgets('toolbar screenshot preserves raw chart axis inverse direction', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    FortuneWorkbook workbookFor({Object? xInverse, Object? yInverse}) {
      final xAxis = <String, Object?>{
        'data': ['A', 'B'],
      };
      final yAxis = <String, Object?>{'min': 0, 'max': 5};
      if (xInverse != null) {
        xAxis['inverse'] = xInverse;
      }
      if (yInverse != null) {
        yAxis['inverse'] = yInverse;
      }
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            selectionSave: const [
              {
                'row': [0, 6],
                'column': [0, 4],
                'row_focus': 0,
                'column_focus': 0,
              },
            ],
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 10,
                  'width': 170,
                  'height': 125,
                  'option': {
                    'xAxis': xAxis,
                    'yAxis': yAxis,
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 5],
                        'lineStyle': {'color': '#ff00ff'},
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<({double covariance, int pixels})> captureSeriesRegions(
      FortuneWorkbook workbook,
    ) async {
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
      );
      await tester.pumpAndSettle();
      await tester.runAsync(() async {
        await Future<void>.delayed(const Duration(milliseconds: 100));
      });
      await tester.pump();
      for (var attempt = 0; attempt < 20; attempt += 1) {
        if (painter().screenshotImage != null) {
          break;
        }
        await tester.pump(const Duration(milliseconds: 50));
      }

      final image = painter().screenshotImage;
      expect(image, isNotNull);
      final pixels = await tester.runAsync(
        () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);

      var seriesPixels = 0;
      var sumX = 0.0;
      var sumY = 0.0;
      final points = <Offset>[];
      for (var y = 0; y < image!.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = (y * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 120) {
            seriesPixels += 1;
            sumX += x;
            sumY += y;
            points.add(Offset(x.toDouble(), y.toDouble()));
          }
        }
      }
      expect(seriesPixels, greaterThan(20));
      final meanX = sumX / seriesPixels;
      final meanY = sumY / seriesPixels;
      final covariance = points.fold<double>(0, (total, point) {
        return total + (point.dx - meanX) * (point.dy - meanY);
      });
      return (covariance: covariance, pixels: seriesPixels);
    }

    final xInverseWorkbook = workbookFor(xInverse: 1);
    final yInverseWorkbook = workbookFor(yInverse: 1);
    final xOverlay = fortuneRawShapeOverlays(
      xInverseWorkbook.activeSheet,
    ).single;
    final yOverlay = fortuneRawShapeOverlays(
      yInverseWorkbook.activeSheet,
    ).single;
    expect(xOverlay.chartXAxisInverse, isTrue);
    expect(xOverlay.chartYAxisInverse, isFalse);
    expect(yOverlay.chartXAxisInverse, isFalse);
    expect(yOverlay.chartYAxisInverse, isTrue);

    final normal = await captureSeriesRegions(workbookFor());
    final xReversed = await captureSeriesRegions(xInverseWorkbook);
    final yReversed = await captureSeriesRegions(yInverseWorkbook);

    expect(normal.covariance, lessThan(-100));
    expect(xReversed.covariance, greaterThan(100));
    expect(yReversed.covariance, greaterThan(100));
  });

