                        'lineStyle': {'color': '#ff00ff'},
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<
      ({
        double magentaMinX,
        double magentaMaxX,
        double cyanMinY,
        double cyanMaxY,
      })
    >
    captureRegions(FortuneWorkbook workbook) async {
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
      );
      await tester.pumpAndSettle();
      await tester.runAsync(() async {
        await Future<void>.delayed(const Duration(milliseconds: 100));
      });
      await tester.pump();
      for (var attempt = 0; attempt < 20; attempt += 1) {
        if (painter().screenshotImage != null) {
          break;
        }
        await tester.pump(const Duration(milliseconds: 50));
      }

      final image = painter().screenshotImage;
      expect(image, isNotNull);
      final pixels = await tester.runAsync(
        () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);

      var magentaMinX = image!.width.toDouble();
      var magentaMaxX = 0.0;
      var cyanMinY = image.height.toDouble();
      var cyanMaxY = 0.0;
      var magentaPixels = 0;
      var cyanPixels = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = (y * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          if (red > 180 && blue > 180 && green < 120) {
            magentaPixels += 1;
            magentaMinX = math.min(magentaMinX, x.toDouble());
            magentaMaxX = math.max(magentaMaxX, x.toDouble());
          }
          if (green > 180 && blue > 180 && red < 120) {
            cyanPixels += 1;
            cyanMinY = math.min(cyanMinY, y.toDouble());
            cyanMaxY = math.max(cyanMaxY, y.toDouble());
          }
        }
      }
      expect(magentaPixels, greaterThan(20));
      expect(cyanPixels, greaterThan(200));
      return (
        magentaMinX: magentaMinX,
        magentaMaxX: magentaMaxX,
        cyanMinY: cyanMinY,
        cyanMaxY: cyanMaxY,
      );
    }

    final gapWorkbook = workbookFor(boundaryGap: 1);
    final overlay = fortuneRawShapeOverlays(gapWorkbook.activeSheet).single;
    expect(overlay.chartXAxisBoundaryGap, isTrue);
    expect(overlay.chartYAxisBoundaryGap, isTrue);

    final noGap = await captureRegions(workbookFor());
    final withGap = await captureRegions(gapWorkbook);

    expect(withGap.magentaMinX, greaterThan(noGap.magentaMinX + 12));
    expect(withGap.magentaMaxX, lessThan(noGap.magentaMaxX - 12));
    expect(withGap.cyanMinY, greaterThan(noGap.cyanMinY + 8));
    expect(withGap.cyanMaxY, lessThan(noGap.cyanMaxY - 8));
  });

