      Future<({int left, int right, int top, int bottom})> captureDistribution(
        FortuneWorkbook workbook,
        bool Function(int red, int green, int blue) background,
      ) async {
        await tester.pumpWidget(
          Directionality(
            textDirection: TextDirection.ltr,
            child: SizedBox(
              width: 1688,
              height: 600,
              child: FortuneSheetCanvas(workbook: workbook),
            ),
          ),
        );

        FortuneSheetPainter painter() {
          return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter;
        }

        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.tapAt(
          topLeft +
              toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
        );
        await tester.pumpAndSettle();
        await tester.runAsync(() async {
          await Future<void>.delayed(const Duration(milliseconds: 100));
        });
        await tester.pump();
        for (var attempt = 0; attempt < 20; attempt += 1) {
          if (painter().screenshotImage != null) {
            break;
          }
          await tester.pump(const Duration(milliseconds: 50));
        }

        final image = painter().screenshotImage;
        expect(image, isNotNull);
        final pixels = await tester.runAsync(
          () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
        );
        expect(pixels, isNotNull);

        var minX = image!.width;
        var maxX = -1;
        var minY = image.height;
        var maxY = -1;
        for (var y = 0; y < image.height; y += 1) {
          for (var x = 0; x < image.width; x += 1) {
            final offset = (y * image.width + x) * 4;
            final red = pixels!.getUint8(offset);
            final green = pixels.getUint8(offset + 1);
            final blue = pixels.getUint8(offset + 2);
            if (background(red, green, blue)) {
              minX = math.min(minX, x);
              maxX = math.max(maxX, x);
              minY = math.min(minY, y);
              maxY = math.max(maxY, y);
            }
          }
        }
        expect(maxX, greaterThanOrEqualTo(minX));
        expect(maxY, greaterThanOrEqualTo(minY));

        final centerX = (minX + maxX) / 2;
        final centerY = (minY + maxY) / 2;
        var left = 0;
        var right = 0;
        var top = 0;
        var bottom = 0;
        for (var y = minY; y <= maxY; y += 1) {
          for (var x = minX; x <= maxX; x += 1) {
            final offset = (y * image.width + x) * 4;
            final red = pixels!.getUint8(offset);
            final green = pixels.getUint8(offset + 1);
            final blue = pixels.getUint8(offset + 2);
            if (red < 90 && green < 90 && blue < 90) {
              if (x < centerX) {
                left += 1;
              } else {
                right += 1;
              }
              if (y < centerY) {
                top += 1;
              } else {
                bottom += 1;
              }
            }
          }
        }
        return (left: left, right: right, top: top, bottom: bottom);
      }

      final alignedWorkbook = workbookFor(
        align: 'right',
        verticalAlign: 'bottom',
      );
      final overlay = fortuneRawShapeOverlays(
        alignedWorkbook.activeSheet,
      ).single;
      expect(overlay.chartXAxisLabelAlign, 'right');
      expect(overlay.chartYAxisLabelAlign, 'right');
      expect(overlay.chartXAxisLabelVerticalAlign, 'bottom');
      expect(overlay.chartYAxisLabelVerticalAlign, 'bottom');

      final defaultMagenta = await captureDistribution(
        workbookFor(),
        (red, green, blue) => red > 180 && blue > 180 && green < 120,
      );
      final alignedMagenta = await captureDistribution(
        alignedWorkbook,
        (red, green, blue) => red > 180 && blue > 180 && green < 120,
      );
      expect(defaultMagenta.left, greaterThan(defaultMagenta.right));
      expect(defaultMagenta.top, greaterThan(defaultMagenta.bottom));
      expect(alignedMagenta.right, greaterThan(alignedMagenta.left));
      expect(alignedMagenta.bottom, greaterThan(alignedMagenta.top));
    },
  );

