          for (var x = 0; x < image.width; x += 1) {
            final offset = (y * image.width + x) * 4;
            final red = pixels!.getUint8(offset);
            final green = pixels.getUint8(offset + 1);
            final blue = pixels.getUint8(offset + 2);
            if (red > 180 && blue > 180 && green < 120) {
              magenta += 1;
            }
            if (green > 180 && blue > 180 && red < 120) {
              cyan += 1;
            }
          }
        }
        return (magenta: magenta, cyan: cyan);
      }

      final truncateWorkbook = workbookFor(truncate: true);
      final overlay = fortuneRawShapeOverlays(
        truncateWorkbook.activeSheet,
      ).single;
      expect(overlay.chartXAxisLabelOverflow, 'truncate');
      expect(overlay.chartYAxisLabelOverflow, 'truncate');
      expect(overlay.chartXAxisLabelEllipsis, '..');
      expect(overlay.chartYAxisLabelEllipsis, '..');

      final defaultCounts = await captureCounts(workbookFor());
      final truncateCounts = await captureCounts(truncateWorkbook);

      expect(truncateCounts.magenta, lessThan(defaultCounts.magenta - 20));
      expect(truncateCounts.cyan, lessThan(defaultCounts.cyan - 20));
    },
  );

  testWidgets('toolbar screenshot preserves raw chart axis label margins', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    FortuneWorkbook workbookFor(double margin) {
      return FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            selectionSave: const [
              {
                'row': [0, 6],
                'column': [0, 4],
                'row_focus': 0,
                'column_focus': 0,
              },
            ],
            extraFields: {
              'chart': [
                {
                  'id': 'chart1',
                  'left': 20,
                  'top': 10,
                  'width': 160,
                  'height': 110,
                  'option': {
                    'xAxis': {
                      'data': ['Start', 'End'],
                      'axisLine': {
                        'lineStyle': {'color': '#00ff00'},
                      },
                      'axisLabel': {
                        'color': '#ff00ff',
                        'fontSize': 12,
                        'margin': margin,
                      },
                    },
                    'yAxis': {
                      'data': ['High', 'Low'],
                      'axisLine': {
                        'lineStyle': {'color': '#00ff00'},
                      },
                      'axisLabel': {
                        'color': '#00ffff',
                        'fontSize': 12,
                        'margin': margin,
                      },
                    },
                    'series': [
                      {
                        'type': 'line',
                        'data': [1, 4, 2, 5],
                      },
                    ],
                  },
                },
              ],
            },
          ),
        ],
      );
    }

    Future<({int minX, int minY, int maxY, int pixels})> captureBounds({
      required double margin,
      required String color,
    }) async {
      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 600,
            child: FortuneSheetCanvas(workbook: workbookFor(margin)),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
      );
      await tester.pumpAndSettle();
      await tester.runAsync(() async {
        await Future<void>.delayed(const Duration(milliseconds: 100));
      });
      await tester.pump();
      for (var attempt = 0; attempt < 20; attempt += 1) {
        if (painter().screenshotImage != null) {
          break;
        }
        await tester.pump(const Duration(milliseconds: 50));
      }

      final image = painter().screenshotImage;
      expect(image, isNotNull);
      final pixels = await tester.runAsync(
        () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);

      var minX = image!.width;
      var minY = image.height;
      var maxY = -1;
      var count = 0;
      for (var y = 0; y < image.height; y += 1) {
        for (var x = 0; x < image.width; x += 1) {
          final offset = (y * image.width + x) * 4;
          final red = pixels!.getUint8(offset);
          final green = pixels.getUint8(offset + 1);
          final blue = pixels.getUint8(offset + 2);
          final matches = switch (color) {
            'magenta' => red > 180 && blue > 180 && green < 100,
            'cyan' => green > 180 && blue > 180 && red < 100,
            'green' => green > 180 && red < 100 && blue < 100,
            _ => false,
          };
          if (matches) {
            count += 1;
            minX = math.min(minX, x);
            minY = math.min(minY, y);
            maxY = math.max(maxY, y);
          }
        }
      }
      return (minX: minX, minY: minY, maxY: maxY, pixels: count);
    }

    final smallMagenta = await captureBounds(margin: 3, color: 'magenta');
    final largeMagenta = await captureBounds(margin: 18, color: 'magenta');
    final smallCyan = await captureBounds(margin: 3, color: 'cyan');
    final largeCyan = await captureBounds(margin: 18, color: 'cyan');
    final smallGreen = await captureBounds(margin: 3, color: 'green');
    final largeGreen = await captureBounds(margin: 18, color: 'green');

    expect(largeMagenta.pixels, greaterThan(40));
    expect(largeCyan.pixels, greaterThan(40));
    expect(
      largeMagenta.minY - largeGreen.maxY,
      greaterThan(smallMagenta.minY - smallGreen.maxY),
    );
    expect(largeCyan.minX, lessThan(smallCyan.minX));
  });

