    for (var y = 4; y < math.min(image.height - 4, 52); y += 1) {
      for (var x = 124; x < math.min(image.width - 4, 236); x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        if ((red - 189).abs() < 24 &&
            (green - 193).abs() < 24 &&
            (blue - 198).abs() < 24) {
          bulletRangePixels += 1;
        } else if (red < 40 && green > 100 && blue > 180) {
          bulletAchievedPixels += 1;
        } else if (red > 180 && green < 90 && blue < 90) {
          bulletTargetPixels += 1;
        }
      }
    }

    expect(boxOutlinePixels, greaterThan(10));
    expect(boxMedianPixels, greaterThan(5));
    expect(bulletRangePixels, greaterThan(20));
    expect(bulletAchievedPixels, greaterThan(10));
    expect(bulletTargetPixels, greaterThan(5));
  });

