                'data': [2, 1, 1],
              },
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 600,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemCenter(fortuneToolbarScreenshotCommand, width: 1688),
    );
    await tester.pumpAndSettle();
    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().screenshotImage != null) {
        break;
      }
      await tester.pump(const Duration(milliseconds: 50));
    }

    final image = painter().screenshotImage;
    expect(image, isNotNull);
    final pixels = await tester.runAsync(
      () => image!.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    var lineAliasPixels = 0;
    var barPositivePixels = 0;
    var barNegativePixels = 0;
    var stackColumnYellowPixels = 0;
    var stackColumnGreenPixels = 0;
    var stackBarYellowPixels = 0;
    var stackBarGreenPixels = 0;
    for (var y = 4; y < math.min(image!.height - 4, 52); y += 1) {
      for (var x = 4; x < math.min(image.width - 4, 380); x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final isBlue = red < 40 && green > 100 && blue > 180;
        final isRed = red > 180 && green < 90 && blue < 90;
        final isYellow = red > 220 && green > 140 && blue < 40;
        final isGreen = red < 80 && green > 130 && blue < 120;
        if (x < 92 && isBlue) {
          lineAliasPixels += 1;
        } else if (x >= 100 && x < 188 && isBlue) {
          barPositivePixels += 1;
        } else if (x >= 100 && x < 188 && isRed) {
          barNegativePixels += 1;
        } else if (x >= 196 && x < 284 && isYellow) {
          stackColumnYellowPixels += 1;
        } else if (x >= 196 && x < 284 && isGreen) {
          stackColumnGreenPixels += 1;
        } else if (x >= 292 && x < 380 && isYellow) {
          stackBarYellowPixels += 1;
        } else if (x >= 292 && x < 380 && isGreen) {
          stackBarGreenPixels += 1;
        }
      }
    }

    expect(lineAliasPixels, greaterThan(15));
    expect(barPositivePixels, greaterThan(20));
    expect(barNegativePixels, greaterThan(10));
    expect(stackColumnYellowPixels, greaterThan(20));
    expect(stackColumnGreenPixels, greaterThan(20));
    expect(stackBarYellowPixels, greaterThan(20));
    expect(stackBarGreenPixels, greaterThan(20));
  });

