          )
          .focusNode
          .hasFocus,
      isTrue,
    );

    final focusChanges = <String>[];
    void recordFocusChange() {
      final label = FocusManager.instance.primaryFocus?.debugLabel;
      if (label != null) {
        focusChanges.add(label);
      }
