      tester.getSize(find.byType(FortuneSheetCanvas)),
      hasResults: false,
    );
    await tester.tapAt(topLeft + fortuneSearchInputRect(dialogRect).center);
    await tester.pump();

    expect(focusChanges, isNot(contains('FortuneSheetCanvas')));
    expect(
      tester
          .widget<EditableText>(
            find.byKey(const ValueKey('fortune-search-input')),
          )
          .focusNode
          .hasFocus,
      isTrue,
    );
  });

