          width: 1688,
          height: 600,
          child: FortuneSheetCanvas(
            workbook: workbook,
            locale: const FortuneSheetLocale(
              searchInputTip: 'Need search text',
              noReplaceTip: 'Nothing to replace',
              replaceSuccessTip: 'Replaced \${xlength}',
            ),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));

    Future<void> openReplaceDialog() async {
      await tester.tapAt(
        topLeft + toolbarItemCenter(fortuneToolbarSearchCommand, width: 1688),
      );
      await tester.pump();
      final dialogRect = fortuneSearchDialogRect(
        tester.getSize(find.byType(FortuneSheetCanvas)),
        hasResults: false,
      );
      await tester.tapAt(
        topLeft + fortuneSearchReplaceTabRect(dialogRect).center,
      );
      await tester.pump();
    }

    Future<void> tapReplaceAll() async {
      final dialogRect = fortuneSearchDialogRect(
        tester.getSize(find.byType(FortuneSheetCanvas)),
        hasResults: false,
      );
      await tester.tapAt(
        topLeft +
            fortuneSearchButtonRect(
              dialogRect,
              'replaceAll',
              replace: true,
            ).center,
      );
      await tester.pump();
    }

    await openReplaceDialog();
    await tapReplaceAll();

    expect(painter().locationMessageDialogText, 'Need search text');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    await openReplaceDialog();
    await tester.enterText(
      find.byKey(const ValueKey('fortune-search-input')),
      'missing',
    );
    await tester.enterText(
      find.byKey(const ValueKey('fortune-replace-input')),
      'pear',
    );
    await tester.pump();
    await tapReplaceAll();

    expect(painter().locationMessageDialogText, 'Nothing to replace');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    await openReplaceDialog();
    await tester.enterText(
      find.byKey(const ValueKey('fortune-search-input')),
      'apple',
    );
    await tester.enterText(
      find.byKey(const ValueKey('fortune-replace-input')),
      'pear',
    );
    await tester.pump();
    await tapReplaceAll();

    expect(painter().locationMessageDialogText, 'Replaced 1');
    expect(
      painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]?.value,
      'pear',
    );
  });

