  testWidgets('inactive loaded images hide border and can be activated', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(900, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final repaintKey = GlobalKey();
    const loadedImageSrc =
        'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=';
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          images: [
            FortuneImage(
              id: 'img1',
              src: loadedImageSrc,
              left: 20,
              top: 20,
              width: 40,
              height: 30,
            ),
            FortuneImage(
              id: 'img2',
              src: loadedImageSrc,
              left: 80,
              top: 20,
              width: 40,
              height: 30,
            ),
          ],
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 900,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    await tester.runAsync(() async {
      await Future<void>.delayed(const Duration(milliseconds: 100));
    });
    await tester.pump();
    for (var attempt = 0; attempt < 20; attempt += 1) {
      if (painter().decodedImages.containsKey(loadedImageSrc)) {
        break;
      }
      await tester.runAsync(() async {
        await Future<void>.delayed(const Duration(milliseconds: 50));
      });
      await tester.pump(const Duration(milliseconds: 50));
    }
    expect(painter().decodedImages, contains(loadedImageSrc));

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final imageLeft = workbook.settings.rowHeaderWidth + 20;
    final imageTop =
        workbook.settings.toolbarHeight +
        workbook.settings.formulaBarHeight +
        workbook.settings.columnHeaderHeight +
        20;
    final borderOffset =
        (imageTop.round() * image.width + (imageLeft + 20).round()) * 4;
    expect(pixels!.getUint8(borderOffset), isNot(0x5f));
    expect(pixels.getUint8(borderOffset + 1), isNot(0x63));
    expect(pixels.getUint8(borderOffset + 2), isNot(0x68));

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + Offset(imageLeft + 20, imageTop + 15));
    await tester.pump();

    expect(painter().activeImageId, 'img1');
  });

