  testWidgets('active image selection does not render control buttons', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(900, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final repaintKey = GlobalKey();
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          images: const [
            FortuneImage(
              id: 'img1',
              src: '',
              left: 20,
              top: 50,
              width: 80,
              height: 50,
            ),
          ],
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 900,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final imageLeft = workbook.settings.rowHeaderWidth + 20;
    final imageTop =
        workbook.settings.toolbarHeight +
        workbook.settings.formulaBarHeight +
        workbook.settings.columnHeaderHeight +
        50;
    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + Offset(imageLeft + 40, imageTop + 25));
    await tester.pump();

    expect(painter().activeImageId, 'img1');

    final boundary =
        repaintKey.currentContext!.findRenderObject()! as RenderRepaintBoundary;
    final image = await boundary.toImage(pixelRatio: 1);
    final pixels = await tester.runAsync(
      () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
    );
    expect(pixels, isNotNull);

    final controlTop = imageTop - 34;
    var controlGrayPixels = 0;
    for (var y = controlTop.round(); y < controlTop + 28; y += 1) {
      for (var x = imageLeft.round(); x < imageLeft + 80; x += 1) {
        final offset = (y * image.width + x) * 4;
        final red = pixels!.getUint8(offset);
        final green = pixels.getUint8(offset + 1);
        final blue = pixels.getUint8(offset + 2);
        final maxChannel = math.max(red, math.max(green, blue));
        final minChannel = math.min(red, math.min(green, blue));
        if (maxChannel >= 70 &&
            maxChannel <= 170 &&
            maxChannel - minChannel <= 24) {
          controlGrayPixels += 1;
        }
      }
    }
    expect(controlGrayPixels, lessThan(10));
  });

