  testWidgets(
    'toolbar quick formula fills grid totals for upstream functions',
    (tester) async {
      tester.view.physicalSize = const Size(1688, 600);
      tester.view.devicePixelRatio = 1;
      addTearDown(() {
        tester.view.resetPhysicalSize();
        tester.view.resetDevicePixelRatio();
      });

      final cases = <String, (String, List<String>)>{
        fortuneToolbarFormulaSumCommand: ('SUM', ['70', '80', '60', '90']),
        fortuneToolbarFormulaMinCommand: ('MIN', ['30', '30', '30', '40']),
        fortuneToolbarFormulaMaxCommand: ('MAX', ['40', '50', '30', '50']),
        fortuneToolbarFormulaAverageCommand: (
          'AVERAGE',
          ['35', '40', '30', '45'],
        ),
        fortuneToolbarFormulaCountCommand: ('COUNT', ['2', '2', '2', '2']),
      };

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      for (final entry in cases.entries) {
        final controller = FortuneSheetController();
        final workbook = FortuneWorkbook(
          sheets: [
            FortuneSheet(
              id: 's1',
              name: 'Sheet1',
              cells: {
                const FortuneCellCoord(0, 0): const FortuneCell(value: '30'),
                const FortuneCellCoord(0, 1): const FortuneCell(value: '40'),
                const FortuneCellCoord(1, 0): const FortuneCell(value: '30'),
                const FortuneCellCoord(1, 1): const FortuneCell(value: '50'),
              },
            ),
          ],
        );

        await tester.pumpWidget(
          Directionality(
            textDirection: TextDirection.ltr,
            child: SizedBox(
              width: 1688,
              height: 360,
              child: FortuneSheetCanvas(
                workbook: workbook,
                controller: controller,
              ),
            ),
          ),
        );

        controller.setSelection(const [
          FortuneRange(
            rowStart: 0,
            rowEnd: 1,
            columnStart: 0,
            columnEnd: 1,
            rowFocus: 0,
            columnFocus: 0,
          ),
        ]);
        await tester.pump();

        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.tapAt(
          topLeft +
              toolbarItemArrowCenter(
                fortuneToolbarQuickFormulaPopupKey,
                width: 1688,
              ),
        );
        await tester.pump();

        final popupLeft = toolbarPopupLeftForKey(
          fortuneToolbarQuickFormulaPopupKey,
          width: 1688,
        );
        await tester.tapAt(
          topLeft +
              toolbarPopupItemCenterForKey(
                popupLeft: popupLeft,
                toolbarKey: fortuneToolbarQuickFormulaPopupKey,
                itemIndex: fortuneToolbarFormulaCommands.indexOf(entry.key),
              ),
        );
        await tester.pump();

        final functionName = entry.value.$1;
        final expectedValues = entry.value.$2;
        final sheet = painter().workbook.activeSheet;
        expect(
          sheet.cells[const FortuneCellCoord(0, 2)]?.formula,
          '=$functionName(A1:B1)',
        );
        expect(
          sheet.cells[const FortuneCellCoord(0, 2)]?.renderedText,
          expectedValues[0],
        );
        expect(
          sheet.cells[const FortuneCellCoord(1, 2)]?.formula,
          '=$functionName(A2:B2)',
        );
        expect(
          sheet.cells[const FortuneCellCoord(1, 2)]?.renderedText,
          expectedValues[1],
        );
        expect(
          sheet.cells[const FortuneCellCoord(2, 0)]?.formula,
          '=$functionName(A1:A2)',
        );
        expect(
          sheet.cells[const FortuneCellCoord(2, 0)]?.renderedText,
          expectedValues[2],
        );
        expect(
          sheet.cells[const FortuneCellCoord(2, 1)]?.formula,
          '=$functionName(B1:B2)',
        );
        expect(
          sheet.cells[const FortuneCellCoord(2, 1)]?.renderedText,
          expectedValues[3],
        );

        await tester.pumpWidget(const SizedBox.shrink());
      }
    },
  );

