        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1688,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> chooseQuickFormula(String command) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft +
            toolbarItemArrowCenter(
              fortuneToolbarQuickFormulaPopupKey,
              width: 1688,
            ),
      );
      await tester.pump();

      final popupLeft = toolbarPopupLeftForKey(
        fortuneToolbarQuickFormulaPopupKey,
        width: 1688,
      );
      await tester.tapAt(
        topLeft +
            toolbarPopupItemCenter(
              popupLeft: popupLeft,
              itemIndex: fortuneToolbarFormulaCommands.indexOf(command),
            ),
      );
      await tester.pump();
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.dragFrom(topLeft + const Offset(83, 100), const Offset(0, 20));
    await tester.pump();
    await chooseQuickFormula(fortuneToolbarFormulaSumCommand);

    expect(
      painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(2, 0)]
          ?.formula,
      '=SUM(A1:A2)',
    );

    await tester.dragFrom(
      topLeft + const Offset(156, 120),
      const Offset(73, 0),
    );
    await tester.pump();
    await chooseQuickFormula(fortuneToolbarFormulaSumCommand);

    var sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(1, 1)]?.value, 'label');
    expect(sheet.cells[const FortuneCellCoord(1, 1)]?.formula, isNull);
    expect(sheet.cells[const FortuneCellCoord(2, 0)]?.formula, '=SUM(A1:A2)');
    expect(sheet.cells[const FortuneCellCoord(1, 3)]?.formula, '=SUM(B2:C2)');
    expect(sheet.cells[const FortuneCellCoord(1, 3)]?.renderedText, '30');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    sheet = painter().workbook.activeSheet;
