              {
                'type': 'default',
                'cellrange': [
                  {
                    'row': [0, 0],
                    'column': [0, 0],
                  },
                ],
                'conditionName': 'greaterThan',
                'conditionValue': ['1'],
                'format': [
                  {'textColor': '#9c0006'},
                  {'cellColor': '#ffc7ce'},
                ],
              },
            ],
          },
        ],
      });

