      await tester.tapAt(
        topLeft + toolbarCenter(fortuneToolbarConditionFormatPopupKey),
      );
      await tester.pump();

      expect(painter().toolbarPopupKey, fortuneToolbarConditionFormatPopupKey);
      expect(
        fortuneToolbarPopupItems[fortuneToolbarConditionFormatPopupKey],
        fortuneConditionFormatTopLevelItems,
      );

      final popupLeft = toolbarPopupLeftForKey(
        fortuneToolbarConditionFormatPopupKey,
        width: conditionFormatToolbarTestWidth,
      );
      await tester.tapAt(
        topLeft +
            conditionFormatTopLevelArrowTarget(
              popupLeft: popupLeft,
              topLevelIndex: fortuneConditionFormatDeleteTopLevelIndex,
            ),
      );
      await tester.pump();

