        painter().conditionFormatSubmenuKey,
        fortuneConditionFormatDeleteSubmenuKey,
      );
      expect(painter().workbook.activeSheet.conditionFormats, isNotEmpty);

      await tester.tapAt(
        topLeft +
            conditionFormatSubmenuItemCenter(
              popupLeft: popupLeft,
              topLevelIndex: fortuneConditionFormatDeleteTopLevelIndex,
              itemIndex: 0,
            ),
      );
