      var sheet = painter().workbook.activeSheet;
      var json = FortuneSheetCodec.sheetToJson(sheet);
      expect(sheet.conditionFormats, isEmpty);
      expect(json['luckysheet_conditionformat_save'], isEmpty);
      expect(painter().toolbarPopupKey, isNull);

      await tester.tapAt(
        topLeft + toolbarCenter(fortuneToolbarConditionFormatPopupKey),
      );
      await tester.pump();
      await tapConditionFormatSubmenuItem(
        tester,
        topLeft: topLeft,
        popupLeft: popupLeft,
        submenuKey: fortuneConditionFormatDeleteSubmenuKey,
