      expect(json['luckysheet_conditionformat_save'], isEmpty);

      await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
      await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
      await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
      await tester.pump();

      sheet = painter().workbook.activeSheet;
      json = FortuneSheetCodec.sheetToJson(sheet);
      final restoredRules = json['luckysheet_conditionformat_save']! as List;
      final restoredRule = restoredRules.single as Map;
      expect(sheet.conditionFormats, isNotEmpty);
      expect(restoredRule['conditionName'], 'greaterThan');
      expect(restoredRule['conditionValue'], ['1']);
    },
  );

