  testWidgets(
    'toolbar alignment wrap and rotation popups update cell metadata',
    (tester) async {
      tester.view.physicalSize = const Size(1200, 600);
      tester.view.devicePixelRatio = 1;
      addTearDown(() {
        tester.view.resetPhysicalSize();
        tester.view.resetDevicePixelRatio();
      });

      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Sheet1',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(
                value: 'formatted',
              ),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1200,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      Future<void> chooseToolbarPopupItem(
        String toolbarKey,
        String item,
      ) async {
        final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
        await tester.tapAt(topLeft + toolbarItemArrowCenter(toolbarKey));
        await tester.pump();

        expect(painter().toolbarPopupKey, toolbarKey);

        final options = fortuneToolbarPopupItems[toolbarKey]!;
        final index = options.indexOf(item);
        expect(index, greaterThanOrEqualTo(0));
        final popupLeft = toolbarPopupLeftForKey(toolbarKey);
        await tester.tapAt(
          topLeft +
              toolbarPopupItemCenterForKey(
                popupLeft: popupLeft,
                toolbarKey: toolbarKey,
                itemIndex: index,
              ),
        );
        await tester.pump();
      }

      await chooseToolbarPopupItem(
        fortuneToolbarHorizontalAlignPopupKey,
        fortuneToolbarAlignRightCommand,
      );
      await chooseToolbarPopupItem(
        fortuneToolbarVerticalAlignPopupKey,
        fortuneToolbarVerticalAlignBottomCommand,
      );
      await chooseToolbarPopupItem(
        fortuneToolbarTextWrapPopupKey,
        fortuneToolbarWrapOverflowCommand,
      );
      var cell =
          painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
      expect(cell.textWrap, '1');

      await chooseToolbarPopupItem(
        fortuneToolbarTextWrapPopupKey,
        fortuneToolbarWrapClipCommand,
      );
      cell =
          painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
      expect(cell.textWrap, '0');

      await chooseToolbarPopupItem(
        fortuneToolbarTextWrapPopupKey,
        fortuneToolbarWrapWrapCommand,
      );
      await chooseToolbarPopupItem(
        fortuneToolbarTextRotationPopupKey,
        fortuneToolbarRotateVerticalCommand,
      );

      cell =
          painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]!;
      expect(cell.horizontalAlign, '2');
      expect(cell.verticalAlign, '2');
      expect(cell.textWrap, '2');
      expect(cell.textRotationMode, '3');
      expect(painter().toolbarPopupKey, isNull);
    },
  );

