      'Tahoma',
      'Verdana',
      'Aptos',
      'Bahnschrift',
      'Calibri',
      'Cambria',
      'Candara',
      'Cascadia Code',
      'Comic Sans MS',
      'Consolas',
      'Constantia',
      'Corbel',
      'Courier New',
      'Franklin Gothic',
      'Georgia',
      'Impact',
      'Lucida Console',
      'Microsoft Sans Serif',
      'Nirmala Text',
      'Palatino Linotype',
      'Segoe UI',
      'Trebuchet MS',
      'Yu Gothic',
    ];
    final workbook = FortuneWorkbook(
      settings: FortuneSettings(
        fontFamilies: fontFamilies,
        fontProvider: () async => fontFamilies,
      ),
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'fonted',
              fontFamily: 'Yu Gothic',
              fontSize: 72,
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1200,
          height: 160,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );
    await tester.pump();

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(
      topLeft + toolbarItemArrowCenter(fortuneToolbarFontPopupKey),
    );
    await tester.pump();

    expect(painter().toolbarPopupKey, fortuneToolbarFontPopupKey);
    final fontOptions = [
      for (final family in painter().workbook.settings.fontFamilies)
        fortuneToolbarFontFamilyCommand(family),
    ];
    final fontSelectedIndex = fontOptions.indexOf(
      fortuneToolbarFontFamilyCommand('Yu Gothic'),
    );
    expect(fontSelectedIndex, greaterThanOrEqualTo(0));
    expect(painter().toolbarPopupSelectedIndex, fontSelectedIndex);
    expect(painter().toolbarPopupHoveredIndex, isNull);
    expect(painter().toolbarPopupScrollOffset, greaterThan(0));

    final fontNaturalHeight = fortuneToolbarPopupHeightFor(
      fortuneToolbarFontPopupKey,
      fontOptions,
    );
    final fontVisibleHeight = fortuneToolbarPopupVisibleHeightFor(
      viewportHeight: 160,
      naturalHeight: fontNaturalHeight,
    );
    final fontSelectedCenterY =
        fortuneToolbarPopupTop +
        fortuneToolbarPopupContentTopPaddingFor(fortuneToolbarFontPopupKey) +
        fortuneToolbarPopupRowHeightFor(fortuneToolbarFontPopupKey) *
            fontSelectedIndex +
        fortuneToolbarPopupRowHeightFor(fortuneToolbarFontPopupKey) / 2 -
        painter().toolbarPopupScrollOffset;
    expect(fontSelectedCenterY, greaterThan(fortuneToolbarPopupTop));
    expect(
      fontSelectedCenterY,
      lessThan(fortuneToolbarPopupTop + fontVisibleHeight),
    );

    final mouse = await tester.createGesture(kind: PointerDeviceKind.mouse);
    await mouse.addPointer(location: topLeft + const Offset(1, 1));
    await mouse.moveTo(
      topLeft +
          Offset(
            toolbarPopupLeftForKey(fortuneToolbarFontPopupKey) + 20,
            fortuneToolbarPopupTop + 28,
          ),
    );
    await tester.pump();

    expect(painter().toolbarPopupHoveredIndex, isNotNull);
    expect(painter().toolbarPopupHoveredIndex, isNot(fontSelectedIndex));
    await mouse.removePointer();

    await tester.tapAt(
      topLeft + toolbarItemArrowCenter(fortuneToolbarFontSizePopupKey),
    );
    await tester.pump();

    expect(painter().toolbarPopupKey, fortuneToolbarFontSizePopupKey);
    expect(
      painter().toolbarPopupSelectedIndex,
      fortuneToolbarFontSizeCommands.indexOf(fortuneToolbarFontSize72Command),
    );
    expect(painter().toolbarPopupHoveredIndex, isNull);
    expect(painter().toolbarPopupScrollOffset, greaterThan(0));
  });

