    tester,
  ) async {
    tester.view.physicalSize = const Size(1200, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          authority: {'sheet': 1},
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'protected'),
            const FortuneCellCoord(0, 1): const FortuneCell(
              value: 'undo',
              locked: false,
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1200,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(156, 100));
    await tester.pump();
    await tester.tapAt(topLeft + toolbarItemCenter(fortuneToolbarBoldCommand));
    await tester.pump();

    var sheet = painter().workbook.activeSheet;
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.bold, isTrue);

    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.tapAt(
      topLeft + toolbarItemArrowCenter(fortuneToolbarFontPopupKey),
    );
    await tester.pump();

    final options = [
      for (final family in painter().workbook.settings.fontFamilies)
        fortuneToolbarFontFamilyCommand(family),
    ];
    final index = options.indexOf(fortuneToolbarFontFamilyCommand('Arial'));
    expect(index, greaterThanOrEqualTo(0));
    final popupLeft = toolbarPopupLeftForKey(fortuneToolbarFontPopupKey);
    await tester.tapAt(
      topLeft +
          toolbarPopupItemCenterForKey(
            popupLeft: popupLeft,
            toolbarKey: fortuneToolbarFontPopupKey,
            itemIndex: index,
          ),
    );
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(painter().toolbarPopupKey, isNull);
    expect(
      sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText,
      'protected',
    );
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.fontFamily, isNull);
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.bold, isTrue);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    sheet = painter().workbook.activeSheet;
    expect(
      sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText,
      'protected',
    );
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.fontFamily, isNull);
    expect(sheet.cells[const FortuneCellCoord(0, 1)]?.bold, isNot(isTrue));
  });

  testWidgets('toolbar font popups export canonical font metadata', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1200, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneSheetCodec.workbookFromJson({
      'data': [
        {
          'id': 's1',
          'name': 'Sheet1',
          'celldata': [
            {
              'r': 0,
              'c': 0,
              'v': {'v': 'fonted', 'ff': 'Arial', 'fs': 10, 'rawOnly': true},
            },
          ],
        },
      ],
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1200,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> chooseToolbarPopupItem(String toolbarKey, String item) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(topLeft + toolbarItemArrowCenter(toolbarKey));
      await tester.pump();

      expect(painter().toolbarPopupKey, toolbarKey);

      final options = toolbarKey == fortuneToolbarFontPopupKey
          ? [
              for (final family in painter().workbook.settings.fontFamilies)
                fortuneToolbarFontFamilyCommand(family),
            ]
          : fortuneToolbarPopupItems[toolbarKey]!;
      final index = options.indexOf(item);
      expect(index, greaterThanOrEqualTo(0));
      final popupLeft = toolbarPopupLeftForKey(toolbarKey);
      await tester.tapAt(
        topLeft +
            toolbarPopupItemCenterForKey(
              popupLeft: popupLeft,
              toolbarKey: toolbarKey,
              itemIndex: index,
            ),
      );
      await tester.pump();
    }

    await chooseToolbarPopupItem(
      fortuneToolbarFontPopupKey,
      fortuneToolbarFontFamilyCommand('Tahoma'),
    );
    await chooseToolbarPopupItem(
      fortuneToolbarFontSizePopupKey,
      fortuneToolbarFontSize18Command,
    );

    final sheet = painter().workbook.activeSheet;
    final json = FortuneSheetCodec.sheetToJson(sheet);
    final celldata = json['celldata']! as List;
    final cellJson = (celldata.single as Map)['v']! as Map;

    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.fontFamily, 'Tahoma');
    expect(sheet.cells[const FortuneCellCoord(0, 0)]?.fontSize, 18);
    expect(cellJson['ff'], 'Tahoma');
    expect(cellJson['fs'], 18);
    expect(cellJson['rawOnly'], isTrue);
    expect(painter().toolbarPopupKey, isNull);
  });

  testWidgets('toolbar border popup updates selected cell border metadata', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1200, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'bordered'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 1200,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    Future<void> chooseBorderItem(String item) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      await tester.tapAt(
        topLeft + toolbarItemArrowCenter(fortuneToolbarBorderPopupKey),
      );
      await tester.pump();

      expect(painter().toolbarPopupKey, fortuneToolbarBorderPopupKey);

      final options = fortuneToolbarPopupItems[fortuneToolbarBorderPopupKey]!;
      final index = options.indexOf(item);
      expect(index, greaterThanOrEqualTo(0));
      final popupLeft = toolbarPopupLeftForKey(fortuneToolbarBorderPopupKey);
      await tester.tapAt(
        topLeft +
            toolbarPopupItemCenterForKey(
              popupLeft: popupLeft,
              toolbarKey: fortuneToolbarBorderPopupKey,
              itemIndex: index,
            ),
      );
      await tester.pump();
    }

    await chooseBorderItem(fortuneToolbarBorderAllCommand);

    var sheet = painter().workbook.activeSheet;
    expect(sheet.borderInfo.last.borderType, 'border-all');
    expect(sheet.borderInfo.last.ranges.single.rowStart, 0);
    expect(sheet.borderInfo.last.ranges.single.columnStart, 0);

    var borders = FortuneBorderCompute.compute(sheet);
    final cellBorders = borders[const FortuneCellCoord(0, 0)]!;
    expect(cellBorders.top, isNotNull);
    expect(cellBorders.right, isNotNull);
    expect(cellBorders.bottom, isNotNull);
    expect(cellBorders.left, isNotNull);

    await chooseBorderItem(fortuneToolbarBorderAllCommand);

    sheet = painter().workbook.activeSheet;
    expect(sheet.borderInfo, hasLength(1));

    await chooseBorderItem(fortuneToolbarBorderNoneCommand);

    sheet = painter().workbook.activeSheet;
    expect(sheet.borderInfo.last.borderType, 'border-none');
    borders = FortuneBorderCompute.compute(sheet);
    expect(borders[const FortuneCellCoord(0, 0)], isNull);
    expect(painter().toolbarPopupKey, isNull);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    borders = FortuneBorderCompute.compute(painter().workbook.activeSheet);
    expect(borders[const FortuneCellCoord(0, 0)]?.top, isNotNull);
  });

