  testWidgets('sheet tab scroll buttons move the visible tab strip', (
    tester,
  ) async {
    final repaintKey = GlobalKey();
    final workbook = FortuneWorkbook(
      sheets: [
        for (var i = 1; i <= 8; i += 1)
          FortuneSheet(id: 's$i', name: 'LongSheet$i'),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: RepaintBoundary(
          key: repaintKey,
          child: SizedBox(
            width: 240,
            height: 320,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    expect(painter().sheetTabScrollOffset, 0);

    Future<Color> canvasPixelAt(Offset local) async {
      final boundary =
          repaintKey.currentContext!.findRenderObject()!
              as RenderRepaintBoundary;
      final image = await boundary.toImage(pixelRatio: 1);
      final pixels = await tester.runAsync(
        () => image.toByteData(format: ui.ImageByteFormat.rawRgba),
      );
      expect(pixels, isNotNull);
      final x = local.dx.round().clamp(0, image.width - 1);
      final y = local.dy.round().clamp(0, image.height - 1);
      final offset = (y * image.width + x) * 4;
      return Color.fromARGB(
        pixels!.getUint8(offset + 3),
        pixels.getUint8(offset),
        pixels.getUint8(offset + 1),
        pixels.getUint8(offset + 2),
      );
    }

    int colorChannel(double value) => (value * 255).round().clamp(0, 255);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    final localTabY = tabY - topLeft.dy;
    final initialRightBoundary = await canvasPixelAt(Offset(236, localTabY));
    expect(colorChannel(initialRightBoundary.r), lessThan(230));
    expect(colorChannel(initialRightBoundary.g), lessThan(230));
    expect(colorChannel(initialRightBoundary.b), lessThan(230));

    await tester.tapAt(Offset(topLeft.dx + 51, tabY));
    await tester.pump();

    expect(painter().sheetTabScrollOffset, 96);
    final scrolledLeftBoundary = await canvasPixelAt(Offset(59, localTabY));
    expect(colorChannel(scrolledLeftBoundary.r), lessThan(230));
    expect(colorChannel(scrolledLeftBoundary.g), lessThan(230));
    expect(colorChannel(scrolledLeftBoundary.b), lessThan(230));

    await tester.tapAt(Offset(topLeft.dx + 37, tabY));
    await tester.pump();

    expect(painter().sheetTabScrollOffset, 0);
    final restoredRightBoundary = await canvasPixelAt(Offset(236, localTabY));
    expect(colorChannel(restoredRightBoundary.r), lessThan(230));
    expect(colorChannel(restoredRightBoundary.g), lessThan(230));
    expect(colorChannel(restoredRightBoundary.b), lessThan(230));
  });

