  testWidgets('sheet list popups expose upstream focusable row semantics', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1'),
        FortuneSheet(id: 'hidden', name: 'Hidden', hide: 1),
        FortuneSheet(id: 's2', name: 'Sheet2'),
      ],
    );
    final painter = FortuneSheetPainter(
      workbook: workbook,
      selection: const FortuneSelection(row: 0, column: 0),
      scrollOffset: Offset.zero,
      sheetTabScrollOffset: 0,
      textDirection: TextDirection.ltr,
      sheetListAt: const Offset(20, 120),
      hiddenSheetListAt: const Offset(220, 120),
    );
    final semantics = painter.semanticsBuilder(const Size(420, 320));

    CustomPainterSemantics node(String label) {
      return semantics.singleWhere((entry) => entry.properties.label == label);
    }

    expect(node('Sheet1').properties.button, isTrue);
    expect(node('Sheet1').properties.selected, isTrue);
    final hiddenNodes = semantics
        .where((entry) => entry.properties.label == 'Hidden')
        .toList();
    expect(hiddenNodes, hasLength(2));
    final visibleListHiddenNode = hiddenNodes.singleWhere(
      (entry) =>
          entry.rect == fortuneSheetListTextRect(const Offset(20, 120), 1, 3),
    );
    expect(visibleListHiddenNode.properties.button, isTrue);
    expect(visibleListHiddenNode.properties.selected, isFalse);
    final hiddenListNode = hiddenNodes.singleWhere(
      (entry) =>
          entry.rect ==
          fortuneHiddenSheetTextRect(const Offset(220, 120), 0, 1),
    );
    expect(hiddenListNode.properties.button, isTrue);
  });

  testWidgets('sheet tab add export writes canonical workbook data', (
    tester,
  ) async {
    final workbook = FortuneSheetCodec.workbookFromJson({
      'workbookExtra': true,
      'data': [
        {'id': 's1', 'name': 'Sheet1', 'firstExtra': true},
        'legacy-gap',
        {'id': 's2', 'name': 'Sheet2', 'secondExtra': true},
      ],
    });

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    await tester.tapAt(Offset(topLeft.dx + 15, tabY));
    await tester.pump();

    var json = FortuneSheetCodec.workbookToJson(painter().workbook);
    var data = json['data']! as List;
    var sheetEntries = data.whereType<Map>().toList();
    final addedSheetId = painter().workbook.activeSheet.id;

    expect(addedSheetId, matches(fortuneUuidV4Pattern));
    expect(addedSheetId, isNot('sheet_03'));

    expect(painter().workbook.sheets.map((sheet) => sheet.id), [
      's1',
      's2',
      addedSheetId,
    ]);
    expect(painter().workbook.activeSheet.id, addedSheetId);
    expect(json['workbookExtra'], isTrue);
    expect(data, hasLength(3));
    expect(
      [for (final item in sheetEntries) item['id']],
      ['s1', 's2', addedSheetId],
    );
    expect(sheetEntries.first['firstExtra'], isTrue);
    expect(sheetEntries.elementAt(1)['secondExtra'], isTrue);
    expect(sheetEntries.last['name'], 'Sheet3');
    expect(sheetEntries.last['status'], 1);
    expect(sheetEntries.take(2).map((item) => item['status']), [0, 0]);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    json = FortuneSheetCodec.workbookToJson(painter().workbook);
    data = json['data']! as List;
    sheetEntries = data.whereType<Map>().toList();

    expect(painter().workbook.sheets.map((sheet) => sheet.id), ['s1', 's2']);
    expect(painter().workbook.activeSheet.id, 's1');
    expect(json['workbookExtra'], isTrue);
    expect(data, hasLength(3));
    expect(data[1], 'legacy-gap');
    expect([for (final item in sheetEntries) item['id']], ['s1', 's2']);
    expect(sheetEntries.first['firstExtra'], isTrue);
    expect(sheetEntries.last['secondExtra'], isTrue);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.sheets.map((sheet) => sheet.id), [
      's1',
      's2',
      addedSheetId,
    ]);
    expect(painter().workbook.activeSheet.id, addedSheetId);
  });

