  testWidgets('canvas onChange emits workbook snapshots', (tester) async {
    final workbook = FortuneSheetCodec.workbookFromJson({
      'data': [
        {'id': 's1', 'name': 'Sheet1'},
        {'id': 's2', 'name': 'Sheet2'},
      ],
    });
    final changes = <FortuneWorkbook>[];

    var nextGeneratedId = 0;
    final settings = FortuneSettings(
      row: 12,
      column: 8,
      showToolbar: false,
      generateSheetId: () => 'generated_${nextGeneratedId++}',
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(
            workbook: workbook,
            settings: settings,
            onChange: changes.add,
          ),
        ),
      ),
    );
    await tester.pump();

    expect(changes, isNotEmpty);
    expect(changes.last.activeSheet.id, 's1');
    expect(changes.last.settings.row, 12);
    expect(changes.last.settings.column, 8);
    expect(changes.last.settings.showToolbar, isFalse);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    await tester.tapAt(Offset(topLeft.dx + 15, tabY));
    await tester.pump();

    expect(changes.last.activeSheet.id, 'generated_0');
    expect(changes.last.sheets.map((sheet) => sheet.id), [
      's1',
      's2',
      'generated_0',
    ]);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
