  testWidgets('external workbook prop update clears undo history', (
    tester,
  ) async {
    final controller = FortuneSheetController();
    final firstWorkbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 'a',
          name: 'A',
          cells: {const FortuneCellCoord(0, 0): FortuneCell(value: 'A')},
        ),
      ],
    );
    final secondWorkbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 'b',
          name: 'B',
          cells: {const FortuneCellCoord(0, 0): FortuneCell(value: 'B')},
        ).setSelection(const [
          FortuneRange(rowStart: 1, rowEnd: 2, columnStart: 1, columnEnd: 2),
        ]),
      ],
    );
    final changes = <FortuneWorkbook>[];
    var nextGeneratedId = 0;
    final settings = FortuneSettings(
      generateSheetId: () => 'generated_${nextGeneratedId++}',
    );

    Widget build(FortuneWorkbook workbook) {
      return Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(
            workbook: workbook,
            controller: controller,
            settings: settings,
            onChange: changes.add,
          ),
        ),
      );
    }

    await tester.pumpWidget(build(firstWorkbook));
    await tester.pump();

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    await tester.tapAt(Offset(topLeft.dx + 15, tabY));
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 'generated_0');
    expect(painter().workbook.sheets.map((sheet) => sheet.id), [
      'a',
      'generated_0',
    ]);

    expect(controller.scroll(scrollLeft: 40, scrollTop: 80), {
      'scrollLeft': 40,
      'scrollTop': 80,
    });
    controller.setSelection(const [
      FortuneRange(rowStart: 2, rowEnd: 2, columnStart: 2, columnEnd: 2),
    ]);
    await tester.pump();

    expect(painter().scrollOffset, const Offset(40, 80));
    expect(controller.getSelection()!.single.rowStart, 2);

    await tester.pumpWidget(build(secondWorkbook));
    await tester.pump();
    await tester.pump();
    changes.clear();

    expect(painter().workbook.activeSheet.id, 'b');
    expect(
      painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]?.value,
      'B',
    );
    expect(painter().scrollOffset, Offset.zero);
    expect(controller.getSelection()!.single.rowStart, 1);
    expect(controller.getSelection()!.single.rowEnd, 2);
    expect(controller.getSelection()!.single.columnStart, 1);
    expect(controller.getSelection()!.single.columnEnd, 2);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 'b');
    expect(
      painter().workbook.activeSheet.cells[const FortuneCellCoord(0, 0)]?.value,
      'B',
    );
  });

