  testWidgets('canvas onOp emits sheet add and delete ops', (tester) async {
    final workbook = FortuneSheetCodec.workbookFromJson({
      'data': [
        {'id': 's1', 'name': 'Sheet1'},
        {'id': 's2', 'name': 'Sheet2'},
      ],
    });
    final ops = <List<FortuneOp>>[];

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook, onOp: ops.add),
        ),
      ),
    );
    await tester.pump();

    FortuneWorkbook paintedWorkbook() {
      return (tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter)
          .workbook;
    }

    expect(ops, isEmpty);
    final previousActiveSheetId = paintedWorkbook().activeSheet.id;
    expect(paintedWorkbook().sheets.map((sheet) => sheet.id), ['s1', 's2']);

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    await tester.tapAt(Offset(topLeft.dx + 15, tabY));
    await tester.pump();

    final addedSheetId = paintedWorkbook().activeSheet.id;
    expect(addedSheetId, matches(fortuneUuidV4Pattern));
    expect(addedSheetId, isNot('sheet_03'));

    expect(ops, hasLength(1));
    expect(ops.last.single['op'], 'addSheet');
    expect(ops.last.single['id'], addedSheetId);
    expect(ops.last.single['path'], isEmpty);
    expect((ops.last.single['value']! as Map)['name'], 'Sheet3');
    expect(paintedWorkbook().sheets.map((sheet) => sheet.id), [
      's1',
      's2',
      addedSheetId,
    ]);
    expect(paintedWorkbook().activeSheet.id, addedSheetId);

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(ops, hasLength(2));
    expect(ops.last.single['op'], 'deleteSheet');
    expect(ops.last.single['id'], addedSheetId);
    expect(ops.last.single['path'], isEmpty);
    expect((ops.last.single['value']! as Map)['name'], 'Sheet3');
    expect(paintedWorkbook().sheets.map((sheet) => sheet.id), ['s1', 's2']);
    expect(paintedWorkbook().activeSheet.id, previousActiveSheetId);
  });

