  testWidgets('canvas onOp emits row column structural ops', (tester) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          rowCount: 4,
          columnCount: 4,
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
            const FortuneCellCoord(1, 1): const FortuneCell(value: 'B2'),
          },
        ),
      ],
    );
    final ops = <List<FortuneOp>>[];

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook, onOp: ops.add),
        ),
      ),
    );
    await tester.pump();

    Future<void> openContextMenuAt(Offset local) async {
      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final gesture = await tester.startGesture(
        topLeft + local,
        kind: PointerDeviceKind.mouse,
        buttons: kSecondaryMouseButton,
      );
      await gesture.up();
      await tester.pump();
    }

    Future<void> tapContextCommand(String command) async {
      const rowHeight = 28.0;
      const dividerHeight = 9.0;
      var y = 6.0;
      final currentPainter =
          tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter;
      for (final item in currentPainter.contextMenuItems) {
        if (item == '|') {
          y += dividerHeight;
          continue;
        }
        if (item == command) {
          final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
          await tester.tapAt(
            topLeft +
                currentPainter.contextMenuAt! +
                Offset(40, y + rowHeight / 2),
          );
          await tester.pump();
          return;
        }
        y += rowHeight;
      }
      fail('context command not found: $command');
    }

    await openContextMenuAt(const Offset(20, 120));
    ops.clear();
    await tapContextCommand(fortuneContextInsertRowCommand);

    var emittedOps = ops.expand((batch) => batch).toList();
    expect(
      emittedOps,
      contains(
        allOf(
          containsPair('op', 'insertRowCol'),
          containsPair('id', 's1'),
          containsPair('path', isEmpty),
          containsPair('value', {
            'type': 'row',
            'index': 1,
            'count': 1,
            'direction': 'lefttop',
            'id': 's1',
          }),
        ),
      ),
    );

    ops.clear();
    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    emittedOps = ops.expand((batch) => batch).toList();
    expect(
      emittedOps,
      contains(
        allOf(
          containsPair('op', 'deleteRowCol'),
          containsPair('id', 's1'),
          containsPair('path', isEmpty),
          containsPair('value', {
            'type': 'row',
            'id': 's1',
            'start': 1,
            'end': 1,
          }),
        ),
      ),
    );

    ops.clear();
    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    emittedOps = ops.expand((batch) => batch).toList();
    expect(
      emittedOps,
      contains(
        allOf(
          containsPair('op', 'insertRowCol'),
          containsPair('id', 's1'),
          containsPair('path', isEmpty),
          containsPair('value', {
            'type': 'row',
            'index': 1,
            'count': 1,
            'direction': 'lefttop',
            'id': 's1',
          }),
        ),
      ),
    );

    ops.clear();
    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    emittedOps = ops.expand((batch) => batch).toList();
    expect(
      emittedOps,
      contains(
        allOf(
          containsPair('op', 'deleteRowCol'),
          containsPair('id', 's1'),
          containsPair('path', isEmpty),
          containsPair('value', {
            'type': 'row',
            'id': 's1',
            'start': 1,
            'end': 1,
          }),
        ),
      ),
    );

