    await tester.pump();

    expect(calls, [
      {
        'hook': 'before',
        'value': 'B1',
        'row': 0,
        'column': 1,
        'startRow': 0,
        'startColumn': 74,
        'endRow': 20,
        'endColumn': 148,
      },
      {
        'hook': 'after',
        'value': 'B1',
        'row': 0,
        'column': 1,
        'startRow': 0,
        'startColumn': 74,
        'endRow': 20,
        'endColumn': 148,
      },
    ]);
  });

