  testWidgets('canvas cell update hooks wrap edit commits', (tester) async {
    final calls = <Map<String, Object?>>[];
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'old'),
          },
        ),
      ],
      settings: FortuneSettings(
        beforeUpdateCell: (row, column, value) {
          calls.add({
            'hook': 'before',
            'row': row,
            'column': column,
            'value': value,
          });
          return true;
        },
        afterUpdateCell: (row, column, oldValue, newValue) {
          calls.add({
            'hook': 'after',
            'row': row,
            'column': column,
            'old': oldValue?.renderedText,
            'next': newValue?.renderedText,
          });
        },
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(83, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();
    await tester.enterText(find.byType(EditableText), 'edited');
    await tester.tapAt(topLeft + const Offset(130, 100));
    await tester.pump();

    expect(calls, [
      {'hook': 'before', 'row': 0, 'column': 0, 'value': 'edited'},
      {'hook': 'after', 'row': 0, 'column': 0, 'old': 'old', 'next': 'edited'},
    ]);
    expect(
      painter()
          .workbook
          .activeSheet
          .cells[const FortuneCellCoord(0, 0)]
          ?.renderedText,
      'edited',
    );
  });

