  testWidgets('sheet tab custom focus command preserves saved selection', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1'),
        FortuneSheet(
          id: 's2',
          name: 'Sheet2',
          selectionSave: const [
            {
              'row': [3, 4],
              'column': [2, 5],
              'row_focus': 3,
              'column_focus': 2,
            },
          ],
        ),
      ],
      settings: const FortuneSettings(
        sheetTabContextMenu: [fortuneSheetTabFocusCommand],
      ),
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    final firstTabWidth = math.max(72.0, 'Sheet1'.length * 8 + 32.0);
    final secondTabWidth = math.max(72.0, 'Sheet2'.length * 8 + 32.0);
    final secondTabMenuX = 58 + firstTabWidth - 1 + secondTabWidth - 11;

    await tester.tapAt(Offset(topLeft.dx + secondTabMenuX, tabY));
    await tester.pump();

    expect(painter().workbook.activeSheet.id, 's2');
    expect(painter().selection.row, 3);
    expect(painter().selection.column, 2);
    final menuAt = painter().sheetTabMenuAt!;
    await tester.tapAt(
      topLeft +
          fortuneSheetTabMenuItemTextRect(menuAt, 0, [
            fortuneSheetTabFocusCommand,
          ]).center,
    );
    await tester.pump();

    expect(painter().sheetTabMenuAt, isNull);
    expect(painter().workbook.activeSheet.id, 's2');
    expect(painter().selection.row, 3);
    expect(painter().selection.column, 2);
    expect(painter().selection.rowEnd, 4);
    expect(painter().selection.columnEnd, 5);
  });

