  testWidgets('sheet tab structural actions respect allowEdit false', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      settings: const FortuneSettings(allowEdit: false),
      sheets: [
        FortuneSheet(id: 's1', name: 'Sheet1'),
        FortuneSheet(id: 's2', name: 'Sheet2'),
        FortuneSheet(id: 'hidden', name: 'Hidden', hide: 1),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 420,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    List<Object?> sheetSnapshot() => [
      painter().workbook.activeSheet.id,
      for (final sheet in painter().workbook.sheets)
        [sheet.id, sheet.name, sheet.hide],
    ];

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    final before = sheetSnapshot();

    await tester.tapAt(Offset(topLeft.dx + 15, tabY));
    await tester.pump();
    expect(sheetSnapshot(), before);
    expect(painter().sheetListAt, isNull);

    await tester.tapAt(Offset(topLeft.dx + 37, tabY));
    await tester.pump();
    expect(sheetSnapshot(), before);
    expect(painter().sheetListAt, isNull);

    Future<void> openFirstTabMenu() async {
      final firstTabWidth = math.max(72.0, 'Sheet1'.length * 8 + 32.0);
      await tester.tapAt(Offset(topLeft.dx + 58 + firstTabWidth - 11, tabY));
      await tester.pump();
      expect(painter().sheetTabMenuAt, isNotNull);
    }

    Future<void> tapSheetTabCommand(String command) async {
      await openFirstTabMenu();
      final menuAt = painter().sheetTabMenuAt!;
      await tester.tapAt(
        topLeft +
            fortuneSheetTabMenuItemTextRect(
              menuAt,
              painter().workbook.settings.sheetTabContextMenu.indexOf(command),
              painter().workbook.settings.sheetTabContextMenu,
            ).center,
      );
      await tester.pump();
      expect(sheetSnapshot(), before);
    }

    await tapSheetTabCommand(fortuneSheetTabCopyCommand);
    await tapSheetTabCommand(fortuneSheetTabMoveCommand);
    await tapSheetTabCommand(fortuneSheetTabDeleteCommand);
    await tapSheetTabCommand(fortuneSheetTabHideCommand);

    final gesture = await tester.startGesture(
      Offset(topLeft.dx + 70, tabY),
      kind: PointerDeviceKind.mouse,
    );
    await gesture.moveTo(Offset(topLeft.dx + 190, tabY));
    await tester.pump();
    await gesture.up();
    await tester.pump();
    expect(sheetSnapshot(), before);

    await tapSheetTabCommand(fortuneSheetTabRenameCommand);
    expect(find.byType(EditableText), findsNothing);
  });

