  testWidgets('sheet tab rename rejects upstream invalid names', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [FortuneSheet(id: 's1', name: 'Sheet1')],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 360,
          height: 320,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;

    Future<void> renameFirstSheet(String name) async {
      final tabWidth = math.max(
        72.0,
        painter().workbook.sheets.first.name.length * 8 + 32.0,
      );
      await tester.tapAt(Offset(topLeft.dx + 58 + tabWidth - 11, tabY));
      await tester.pump();
      final menuAt = painter().sheetTabMenuAt!;
      await tester.tapAt(
        Offset(topLeft.dx + menuAt.dx + 18, topLeft.dy + menuAt.dy + 76),
      );
      await tester.pump();
      await tester.enterText(find.byType(EditableText), name);
      await tester.sendKeyEvent(LogicalKeyboardKey.enter);
      await tester.pump();
    }

    await renameFirstSheet('1234567890123456789012345678901');
    expect(
      painter().workbook.sheets.first.name,
      '1234567890123456789012345678901',
    );

    for (final invalidName in [
      '12345678901234567890123456789012',
      "'Leading",
      "Trailing'",
      'Bad:Name',
      r'Bad\Name',
      'Bad/Name',
      'Bad?Name',
      'Bad*Name',
      'Bad[Name',
      'Bad]Name',
      'Bad：Name',
      'Bad？Name',
    ]) {
      await renameFirstSheet(invalidName);
      expect(
        painter().workbook.sheets.first.name,
        '1234567890123456789012345678901',
        reason: invalidName,
      );
    }
  });

