  testWidgets('sheet tab single visible delete hide keeps undo stack', (
    tester,
  ) async {
    tester.view.physicalSize = const Size(1688, 600);
    tester.view.devicePixelRatio = 1;
    addTearDown(() {
      tester.view.resetPhysicalSize();
      tester.view.resetDevicePixelRatio();
    });

    Future<void> verifySingleVisibleNoOp(double commandY) async {
      final workbook = FortuneWorkbook(
        sheets: [
          FortuneSheet(
            id: 's1',
            name: 'Only Sheet',
            cells: {
              const FortuneCellCoord(0, 0): const FortuneCell(value: 'A1'),
              const FortuneCellCoord(0, 2): const FortuneCell(value: 'Undo'),
            },
          ),
        ],
      );

      await tester.pumpWidget(
        Directionality(
          textDirection: TextDirection.ltr,
          child: SizedBox(
            width: 1688,
            height: 360,
            child: FortuneSheetCanvas(workbook: workbook),
          ),
        ),
      );

      FortuneSheetPainter painter() {
        return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
            as FortuneSheetPainter;
      }

      final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
      final size = tester.getSize(find.byType(FortuneSheetCanvas));
      final tabY = topLeft.dy + size.height - 23 - 31 + 20;
      final tabWidth = math.max(72.0, 'Only Sheet'.length * 8 + 32.0);

      await tester.tapAt(topLeft + const Offset(229, 100));
      await tester.pump();
      await tester.tapAt(
        topLeft + toolbarItemCenter(fortuneToolbarBoldCommand, width: 1688),
      );
      await tester.pump();

      expect(
        painter()
            .workbook
            .activeSheet
            .cells[const FortuneCellCoord(0, 2)]
            ?.bold,
        isTrue,
      );

      await tester.tapAt(Offset(topLeft.dx + 58 + tabWidth - 11, tabY));
      await tester.pump();

      expect(painter().sheetTabMenuAt, isNotNull);
      final menuAt = painter().sheetTabMenuAt!;
      await tester.tapAt(
        Offset(topLeft.dx + menuAt.dx + 18, topLeft.dy + menuAt.dy + commandY),
      );
      await tester.pump();

      var sheet = painter().workbook.activeSheet;
      expect(painter().sheetTabMenuAt, isNull);
      expect(painter().workbook.sheets, hasLength(1));
      expect(sheet.id, 's1');
      expect(sheet.hide, isNull);
      expect(sheet.cells[const FortuneCellCoord(0, 0)]?.renderedText, 'A1');
      expect(sheet.cells[const FortuneCellCoord(0, 2)]?.bold, isTrue);

