  testWidgets('cell editor commit participates in workbook undo and redo', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(value: 'before'),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneCell? activeCell() {
      final painter =
          tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
              as FortuneSheetPainter;
      return painter.workbook.activeSheet.cells[const FortuneCellCoord(0, 0)];
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.tapAt(topLeft + const Offset(58, 100));
    await tester.pump();
    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();

    await tester.enterText(find.byType(EditableText), 'after');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    expect(activeCell()?.value, 'after');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(activeCell()?.value, 'before');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyY);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(activeCell()?.value, 'after');

    await tester.sendKeyEvent(LogicalKeyboardKey.f2);
    await tester.pump();
    await tester.enterText(find.byType(EditableText), 'after');
    await tester.sendKeyEvent(LogicalKeyboardKey.enter);
    await tester.pump();

    expect(activeCell()?.value, 'after');

    await tester.sendKeyDownEvent(LogicalKeyboardKey.controlLeft);
    await tester.sendKeyEvent(LogicalKeyboardKey.keyZ);
    await tester.sendKeyUpEvent(LogicalKeyboardKey.controlLeft);
    await tester.pump();

    expect(activeCell()?.value, 'before');
  });

  testWidgets('hovering commented cell shows comment overlay state', (
    tester,
  ) async {
    final workbook = FortuneWorkbook(
      sheets: [
        FortuneSheet(
          id: 's1',
          name: 'Sheet1',
          cells: {
            const FortuneCellCoord(0, 0): const FortuneCell(
              value: 'commented',
              comment: FortuneCellComment(value: 'note'),
            ),
          },
        ),
      ],
    );

    await tester.pumpWidget(
      Directionality(
        textDirection: TextDirection.ltr,
        child: SizedBox(
          width: 640,
          height: 360,
          child: FortuneSheetCanvas(workbook: workbook),
        ),
      ),
    );

    FortuneSheetPainter painter() {
      return tester.widget<CustomPaint>(find.byType(CustomPaint)).painter!
          as FortuneSheetPainter;
    }

    final topLeft = tester.getTopLeft(find.byType(FortuneSheetCanvas));
    await tester.sendEventToBinding(
      PointerHoverEvent(
        position: topLeft + const Offset(82, 100),
        kind: PointerDeviceKind.mouse,
      ),
    );
    await tester.pump();

    expect(painter().hoveredCommentCoord, const FortuneCellCoord(0, 0));

    await tester.sendEventToBinding(
      PointerHoverEvent(
        position: topLeft + const Offset(10, 10),
        kind: PointerDeviceKind.mouse,
      ),
    );
    await tester.pump();

    expect(painter().hoveredCommentCoord, isNull);
    final size = tester.getSize(find.byType(FortuneSheetCanvas));
    final tabY = topLeft.dy + size.height - 23 - 31 + 20;
    await tester.tapAt(Offset(topLeft.dx + 37, tabY));
    await tester.pump();

    expect(painter().sheetListAt, isNotNull);

    await tester.sendEventToBinding(
      PointerHoverEvent(
        position: topLeft + const Offset(82, 100),
        kind: PointerDeviceKind.mouse,
      ),
    );
    await tester.pump();

    expect(painter().hoveredCommentCoord, isNull);
  });
